-- Poems batch 82
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('59ed6f37-a7a7-45bd-a0fc-34a98bb2e317','和董令升喜雨用前韵','王之道','宋','宋诗','song-poetry','','[]','夜聽簷聲翻急雨，想見膏潤均率土。',128,'全唐诗/poet.song.104000.json','["夜聽簷聲翻急雨，想見膏潤均率土。", "先生休戚共斯民，憂在惔焚非憚暑。", "人情類被饑所移，我爾相忘自甘苦。", "寧從禱旱身暴日，肯對驅蝗歌侑俎。", "用心何獨追老杜，大庇寒儒歡廣宇。", "要令匹夫被惠澤，上致吾君堯舜數。", "嗟予糞朽伏邱壑，尺短寸長無足取。", "洊蒙珠玉過稱揚，丈夫殆以氣相許。"]'),
('26341e48-4435-4a78-bd74-049c2decd330','次韵畢少董游西湖','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖春晚未全熱，湖上山光互明滅。',128,'全唐诗/poet.song.104000.json','["西湖春晚未全熱，湖上山光互明滅。", "往來冠盖競駢闐，斷續笙簫共伊咽。", "我憐湖山山見憐，波間湧出佳人鈿。", "太真一去不復返，圓荷萬點臙脂錢。", "船頭美眄珠的皪，不必洞房深處覔。", "忽然相值更相呼，嫩藍衫子山争碧。", "腸斷騷人一軸詩，細看煙柳想腰肢。", "明年我亦西湖去，遲日光風二月時。"]'),
('6d13f08a-75a2-4970-95af-bfec84895b2c','西湖遊次韵趙見燭','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山鎮在越澤在吳，東南形勢憑江湖。',160,'全唐诗/poet.song.104000.json','["山鎮在越澤在吳，東南形勢憑江湖。", "不知弱水竟何處，恍若員嶠連方壺。", "海門潮至飛雪湧，天竺雨過遥青紆。", "十年不見看愈好，正復妙筆那能圖。", "蒼松揺風翠盖偃，芳草藉地柔茵鋪。", "僧舍朝遊恣登覽，酒樓夕醉争歌呼。", "朅來俛仰春又曉，對花無語空長吁。", "作詩既非拙者事，强欲寫書編澤蒲。", "偉哉得志佐明主，進退百辟稱鴻儒。", "應憐伺候奔走輩，終日趦趄仍囁嚅。"]'),
('62115d75-3847-4b93-807d-c98f17ad45ac','天寶歌和魏定公文次韵','王之道','宋','宋诗','song-poetry','','[]','連昌宫中馬爲樂，一時舞馬黄金絡。',160,'全唐诗/poet.song.104000.json','["連昌宫中馬爲樂，一時舞馬黄金絡。", "君王養欲臣養文，忠鯁漫多寧救藥。", "嗷嗷萬國風中船，檣傾柂壞夫何言。", "潼闗莫拒范陽賊，傷哉天廐空連錢。", "翠華西去遥指蜀，應念霓裳舊家曲。", "六軍敢怒誰敢呵，馬足空污太真肉。", "始皇布漆徒堅城，元海斬木徒輕兵。", "驅魚驅雀强鸇獺，乃使後世蒙佳聲。", "亂離每憶昇平日，忽對新詩重嗟泣。", "望仙花草自春秋，怊悵六龍歸未得。"]'),
('4674eadf-7779-4528-b233-a1b8eb1baf92','和江和仲司理喜雨','王之道','宋','宋诗','song-poetry','','[]','天憐轍鮒噓殘濕，震奮雷霆起幽蟄。',96,'全唐诗/poet.song.104000.json','["天憐轍鮒噓殘濕，震奮雷霆起幽蟄。", "清風入夜送雨來，大慰焦枯望霓急。", "新詩如雨雨未休，相對自可忘爲憂。", "東皋秋稔想多秫，預期劇飲無論籌。", "老蟾宿畢君知否，欲煩更問東家丘。", "我今已具西歸舟，會見扶桑升赤虬。"]'),
('f50e4830-c5fa-4ffb-b4c0-69404cd3d84a','鹿泉居士王覺民頗有杜子美不徹之惱和東坡憶梅韵箴其膏肓','王之道','宋','宋诗','song-poetry','','[]','鹿泉居士身若槁，不慣看花夢顛倒。',128,'全唐诗/poet.song.104000.json','["鹿泉居士身若槁，不慣看花夢顛倒。", "桐廬有客燕新昬，妄託嬌癡重伊惱。", "凍雲垂地雪欲落，斷雁呌群天尚早。", "一枝何處寄春來，便覺寒窗自華好。", "瓊瑶萬里眼界淨，咫尺前村莫輕掃。", "留將青女伴孤芳，長向茅齋照衰老。", "先生才思老不進，寤寐池塘見春草。", "對花酌酒祝東君，煩把窮通問蒼昊。"]'),
('ed156827-82e7-4188-8ed3-fbf02b60c20c','次韵胡德輝松軒時乞兵戍淮','王之道','宋','宋诗','song-poetry','','[]','伐蛟生得鬚髯蒼，隠然爲屋分三梁。',140,'全唐诗/poet.song.104000.json','["伐蛟生得鬚髯蒼，隠然爲屋分三梁。", "廣寒恍若東西廂，清風入座衣披猖。", "蕭蕭終日聲奏篁，一洗鄭衞無伊涼。", "嗟予頑鈍鐵石腸，時危命蹇甘皇皇。", "江城正苦夏烈日，淮甸已懼秋飛霜。", "綠尊翠杓且徑醉，喜與夫子參翺翔。", "平生邱壑老增劇，夢想朝露珠璣香。", "何時元戎北渡森旗章，料敵制勝一一盡所長，鷄群野鶴看昂昂。"]'),
('f7fa3631-f0bf-4b55-b139-53f2710a987e','大柿行','王之道','宋','宋诗','song-poetry','','[]','君不見鄭虔學書晚彌篤，歲收柿葉貯三屋。',262,'全唐诗/poet.song.104000.json','["君不見鄭虔學書晚彌篤，歲收柿葉貯三屋。", "興來寢食兩俱忘，但覺毛公老而秃。", "又不見梓人造車度群木，木中無火柿所獨。", "舊言盖軫象乾坤，須信斡旋歸一軸。", "美哉此果有常德，結實何曾問荒熟。", "霜餘萬顆綴寒林，下視黄柑類奴僕。", "牛心取象庶彷彿，熨斗得名何凂瀆。", "火乾既許暖闗膈，冰冷當知解煩燠。", "今年夏秋足時雨，盡道和氣鍾百穀。", "西成僅得十之五，亦見陰陽有盈縮。", "就中朱實繁且大，照野煌煌駭人目。", "較之常歲遠不侔，正似斗勝難趁斛。", "國家運厄困强敵，一紀於兹事弓韣。", "空庭喋血在今年，我已不疑何更卜。", "禾和鞋諧古云讖，大柿之祥天下福。", "請賡繼伐獻吾君，王者功成四方服。"]'),
('75eabff0-b64c-471d-9a23-78be902750f1','秋日苦雨和子厚弟韵','王之道','宋','宋诗','song-poetry','','[]','烟鬰濕薪費挑撥，可堪餘瀝濺如潑。',64,'全唐诗/poet.song.104000.json','["烟鬰濕薪費挑撥，可堪餘瀝濺如潑。", "吹霞弄日語縱工，正恐詩人類迂闊。", "屋角蕭蕭霜葉鳴，夜静亂我糟床聲。", "詩成欲寫輒復已，鄰雞犯早催天明。"]'),
('e88c0cb4-ff1c-42a4-a0d8-877d97ac2ba7','贈曾桑中彈琴','王之道','宋','宋诗','song-poetry','','[]','春寒沍連冬，春雪深數尺。',292,'全唐诗/poet.song.104000.json','["春寒沍連冬，春雪深數尺。", "千門擁瓊瑰，跬步燕越隔。", "朝來有情意，淡日透雲隙。", "殷勤貴公子，訪我跨龍脊。", "登堂笑不休，爲言督詩責。", "君嘗許我詩，俛仰歲三易。", "至今猶未償，無乃言遂食。", "我老苦健志，百不記六七。", "公子誠有意，何吝話疇昔。", "昔也君過我，我方事琴歷。", "嘗爲陽春弄，次第長短側。", "君乎鍾子期，此舉不輕擲。", "聞之思茫然，彷彿見擘趯。", "我有朱絲絃，塵埃久侵蝕。", "試煩一再鼓，助我毛頴力。", "公子不我拒，抱琴枕雙膝。", "須臾扣商絃，當春變秋律。", "凉風着草木，離離盡成實。", "我貧人不知，陋巷家四壁。", "何幸空乏中，登此黍與稷。", "但恐時令乖，瘡痍至生疾。", "公子其反是，叩角夾鍾激。", "不然總四絃，命宫以調適。", "坐令景風與慶雲，爲福爲祥遍方國。"]'),
('ce31cd93-e041-4683-84cb-f7d7bb4f734d','送趙仲達','王之道','宋','宋诗','song-poetry','','[]','人生邂逅非偶耳，一面豈容輕愠喜。',224,'全唐诗/poet.song.104000.json','["人生邂逅非偶耳，一面豈容輕愠喜。", "白首如新傾盖歡，誰解乘閒究斯理。", "君家江南我江北，南北相望殆千里。", "惠寵顧我端有由，衰滯不應能致此。", "爲言前歲在金沙，幽討窮探徧山水。", "論文獲與阿逢游，賸馥殘膏丐猶子。", "是行來赴徐卿召，昨日扁舟方戾止。", "阿逢聞是公僧彌，予乃阿逢門下士。", "知公閒放今杜門，所舍與公殊密邇。", "何妨旦夕侍杖屨，執經仍與諸郎齒。", "過從彈指見周星，入室芝蘭被蕸薳。", "須知四海皆兄弟，高義似君誰可比。", "徐卿報政趣歸朝，畫鷁高檣艤江涘。", "明朝車騎遂東還，有便時時遺雙鯉。"]'),
('4792834c-0e99-47d4-8211-201b19b3d250','贈李廷吉知縣','王之道','宋','宋诗','song-poetry','','[]','李侯入境憐焦枯，指麾屏翳如家奴。',160,'全唐诗/poet.song.104000.json','["李侯入境憐焦枯，指麾屏翳如家奴。", "坐令大旱變霖雨，一時凋瘵歌巖夫。", "我思東坡不可見，夜諷新詩還撚鬚。", "慶源老人骨已朽，愛民似子當今無。", "稻田上下水聲接，農家凖擬相攜壺。", "南鄰敗屋欹欲倒，君來往往人争扶。", "流離復合燕相賀，向人競欲嘲解襦。", "吏民莫恠吾面瘠，耄倪艱食方饑癯。", "政聲不必家置喙，自然和氣成歡呼。", "何當相聚飲一斗，高吟大笑臨卭壚。"]'),
('e3a7dc2c-6b1c-401b-8a1e-5bb284bcb55b','次韵秦壽之雷江阻風','王之道','宋','宋诗','song-poetry','','[]','君之是行亦不惡，到處名山得佳作。',192,'全唐诗/poet.song.104000.json','["君之是行亦不惡，到處名山得佳作。", "江神好事欲援例，横起狂風捲帆脚。", "要求詩句須少駐，故戲舟師令暫泊。", "雷江正在淮南岸，萬頃黄蘆映青廓。", "不知眼界闊多少，但見炊煙耿墟落。", "歸心浩浩孰撩動，歸夢忡忡予忖度。", "怒濤底事强留滯，清夜無眠屢驚愕。", "遡游初冀日千里，今比驅車反成錯。", "人生離合自有數，誰謂江神能見謔。", "新詩入筆走驊騮，奔逸絕塵那可卻。", "何妨有酒發妙思，坐對陶泓自斟酌。", "韵嚴語險屬和難，顧我才慳子非虐。"]'),
('f049c25d-5bee-4665-ae65-9c75c82808dc','曉解糝潭追和張文潜白沙阻風','王之道','宋','宋诗','song-poetry','','[]','江上驚風夜穿屋，扁舟正艤沙頭宿。',96,'全唐诗/poet.song.104000.json','["江上驚風夜穿屋，扁舟正艤沙頭宿。", "燈寒屢剔短檠青，酒暖孤斟老盆綠。", "更闌艇子催人起，泥汊而今趁朝市。", "披衣踉蹡出馬門，凌波逐浪來江豚。", "鳴櫓嘔啞濺飛雨，静聽依稀似人語。", "月城百里指顧中，只好張帆使風去。"]'),
('613cf8c1-a85e-4963-9c8e-ee83304ae3c5','和李似矩馬圖歌次韵','王之道','宋','宋诗','song-poetry','','[]','畫工妙處稱毛羽，我欲論功第先兔。',176,'全唐诗/poet.song.104000.json','["畫工妙處稱毛羽，我欲論功第先兔。", "不知心手會天機，象管紛紛誰比數。", "寥寥千載一曹霸，墨妙于今傳二馬。", "龔生重馬輕尺璧，蔑視韓韋復何者。", "爾來一顧遇孫陽，奔走侯門日無暇。", "一匹騰驤一匹嘶，先生愛駿非愛奇。", "有如霓裳第三疊，按圖知拍逢王維。", "新詩邁絕今老杜，作經未必多馬蹄。", "先生馳騁金馬裏，口角雌黄即公是。", "欲知早晚定登庸，步武風雲起平地。", "偉哉驊騮世英物，一日早行三萬里。"]'),
('4b3d2dfe-1a9d-49ac-a64c-ebaa7162ed67','應資深康樂園四詠  其一','王之道','宋','宋诗','song-poetry','','[]','溪頭柳色春無際，溪水浮天一張紙。',64,'全唐诗/poet.song.104000.json','["溪頭柳色春無際，溪水浮天一張紙。", "東君戲草康樂園，旋入夭桃與繁李。", "亂花無數不知名，往往倚檻窺前楹。", "有時酒惡吐欲死，先生來約花間行。"]'),
('295e77f7-331c-42df-a19a-68415e010781','應資深康樂園四詠  其二','王之道','宋','宋诗','song-poetry','','[]','露梢戞戞敲鳴玉，雲葉差差傳新綠。',64,'全唐诗/poet.song.104000.json','["露梢戞戞敲鳴玉，雲葉差差傳新綠。", "亭前十頃碧琉璃，過雨荷花浄如浴。", "客來不迎君莫嗔，我有清風如故人。", "先生午醉睡正熟，長須倒盡床頭春。"]'),
('324ec5a6-e109-4324-b5d6-ca88a39b51e3','應資深康樂園四詠  其三','王之道','宋','宋诗','song-poetry','','[]','不知眼界幾多闊，隠隠青山在天末。',64,'全唐诗/poet.song.104000.json','["不知眼界幾多闊，隠隠青山在天末。", "湖光釀就琥珀濃，應助先生恣澆潑。", "西風揺落黄花秋，江城有蟹供拍浮。", "人如淵明亦不惡，肯使臨賦成悠悠。"]'),
('4c889e02-e107-4a67-b2da-ae11d9d1f2fd','應資深康樂園四詠  其四','王之道','宋','宋诗','song-poetry','','[]','誰人獨釣江南雪，雪滿江南鳥飛絕。',64,'全唐诗/poet.song.104000.json','["誰人獨釣江南雪，雪滿江南鳥飛絕。", "先生對雪望江南，嗅認梅花忍寒折。", "癡雲捲盡清月流，小舟横卧南池頭。", "子猷乘興欲何往，歸歟莫爲伊人留。"]'),
('23b299fe-5086-413b-80b2-0842953cf5e9','華亭風月堂避暑','王之道','宋','宋诗','song-poetry','','[]','大哉天休何穹窿，惟王配天居域中。',320,'全唐诗/poet.song.104000.json','["大哉天休何穹窿，惟王配天居域中。", "東西南北乃四裔，盛德可使車書同。", "吾皇中興繼商武，小雅不復歌車攻。", "年來幽障滅烽燧，梯航萬里來夷戎。", "華亭瀕海古巖邑，商民填委百貨通。", "雕題交趾在何許，但見巨艦浮蒼龍。", "國家懷遠固有道，緩征薄稅垂無窮。", "名官市舶司置長，往往所任多名公。", "洪侯才望在人右，暫此出使良忡忡。", "使臺雄勝壓湖水，飛橋百尺如垂虹。", "作堂枕水傍風月，想見浩氣盤高空。", "我來五月過淫雨，炎雲烈日方爞爞。", "登臨不獨眼界豁，一洗煩暑清心胸。", "偕行相遇二三子，吳趙與我并王鍾。", "高談亹亹到莫逆，圍碁把酒還從容。", "輕風拂拂動襟袖，明月炯炯窺簾櫳。", "湖光十頃碧上下，身世怳在玻瓈宫。", "何人倚檻正横笛，數聲裂石開雲峰。", "忽然琵琶又繼作，罄此百榼誰能供。", "夜闌歸去不成寢，卧聽湖外鳴豐隆。"]'),
('bbf1b66d-43fa-4c49-9995-b20292f75994','次韵因老胡避遊','王之道','宋','宋诗','song-poetry','','[]','新詩滚滚江流東，一瀉萬里誰能窮。',128,'全唐诗/poet.song.104000.json','["新詩滚滚江流東，一瀉萬里誰能窮。", "平生清峭不近俗，雪山突兀江頭峰。", "相逢一笑莫相避，自古高人苦難致。", "涪翁骨冷喚不醒，且向新詩求筆勢。", "君於涪翁真後身，有同次律前身僧。", "語言直下見理窟，何須辛苦從張凴。", "對君令我思秋菊，三月褒山如一宿。", "君看玉局感秋吟，嘆息流光豈予獨。"]'),
('087f4146-e879-4a0b-867f-ec8991649d30','送管養正長歌','王之道','宋','宋诗','song-poetry','','[]','餞别宜有酒，我無一杯潄君口。',384,'全唐诗/poet.song.104000.json','["餞别宜有酒，我無一杯潄君口。", "送行當以贐，我無一物藉我手。", "與君意氣真相知，君嘗謂予可言詩。", "獨有詩句堪送别，欲賦復止空嗟咨。", "送君胡爲三歎息，文酒從今失三益。", "干戈日尋雅道衰，吾徒一别真可惜。", "問君四海無家歸，飄然此去將何之。", "答云南陽善城守，屢以孤壘攘重圍。", "我今欲往誠有以，主帥好賢同邑里。", "輜車儻許載病翁，長策猶能靖多壘。", "騏驥君看伏櫪姿，髪雖種種心不衰。", "胸中之奇老未吐，忍死山谷甘寒饑。", "君不見元龍豪氣真磊落，卧見許生自旁若。", "時危康濟乃丈夫，問舍求田匪餘樂。", "又不見越石夜半聞雞鳴，披衣起舞賀友生。", "風塵澒洞四海亂，英雄攘臂收功名。", "古人相期盖如此，豈效世間兒女子。", "出門惘惘色可憐，君亦爲之殊可鄙。", "壯君此語膽忽張，群憂散盡增激昂。", "西風獵獵天落霜，千山凋林松檜蒼。", "寒菊始花黄且香，高空無雲老鵰翔。", "登山臨水秋興長，行人欲行送者傷。", "我獨不復傷，知君壯志殊未央。", "爲君援筆寫長句，一洗古今離别腸。"]'),
('ac72d7c9-a057-4caf-a981-7b94701e0c80','冬不雪春苦雨外臺爲民心惻檄郡請禱於法輪應感尊者悉獲靈貺曾不終日教授有詩以發揚盛美郡人相山居士聞而悦之勉次其韵','王之道','宋','宋诗','song-poetry','','[]','誰令一日如三秋，仁人方念淮南州。',256,'全唐诗/poet.song.104000.json','["誰令一日如三秋，仁人方念淮南州。", "斯民忍饑望麰麥，積雨又有傷殘憂。", "冬温土燥生春瘴，半夜風聲來枕上。", "曉看飛雪欲堆簷，白馬參差攅玉嶂。", "年饑高下藝麥多，暴如山阜汸如河。", "那知雪欲苦淫潦，兩岐半吐翻隨波。", "欣聞萬事一言了，使者勤民坐待曉。", "指麾郡將率官僚，出郭共迎羅漢禱。", "由來天意每因人，況自至誠宜感神。", "明朝披霧走烏轡，晴光杲杲清無塵。", "回頭菽粟賤如水，醉飽田間摩腹觜。", "周行四海不齎糧，可但攜壺餉鄰里。", "出遊遂繼文昌謠，追鋒行赴公車招。", "快將劉晏幹排手，衮衣入相禆唐堯。", "廣文才氣邁燕許，分教芹宫從少駐。", "政德穏步玉筍班，好尾輶軒上天去。"]'),
('c77946dd-d8af-4696-9f4c-7111bce88079','次韵孫興宗秋懷','王之道','宋','宋诗','song-poetry','','[]','秋山赫赫明丹楓，秋天隠隠分玄鴻。',384,'全唐诗/poet.song.104000.json','["秋山赫赫明丹楓，秋天隠隠分玄鴻。", "不知眼界闊多少，九華突兀撐晴空。", "嗟予老病百事懶，誰能强勉追兒童。", "讀書既苦齒多豁，屬文益覺心如蓬。", "年來衰甚更齟齬，乘舟賣麵皆遭風。", "茫茫有類墮雲海，躊躇四顧迷西東。", "感君賦秋肯寄我，開緘反覆歌三終。", "如痿忽起盲忽視，角力未易分雌雄。", "寒郷冰雪正凝沍，暖回愛日何烘烘。", "驚濤巨浸浩無際，安流利涉輸艨艟。", "蓽門圭竇僅容膝，規模敢擬阿房宫。", "生平未慣新斧鑿，斲削便許從共工。", "偉哉歐梅兩黄鵠，逃名詩酒俱稱翁。", "余生顧後八十載，賢愚雖異襟期同。", "知君尚友取前哲，言之聊復輸丹衷。", "何爲規規事騷雅，乃欲索我章句中。", "舂容大軸爛錦繡，令人一睹情融融。", "清新嫵麗似鮑謝，豈徒奥學稱淹通。", "人能平地覆一簣，不輟會致邱山崇。", "披雲俛仰三百日，相逢底事常怱怱。", "去年江上識君處，鑿冰初見陽冲冲。", "分攜不覺秋又晚，向來旱氣方藴隆。", "君如鎮西我淝水，我往無事還何功。", "而君被檄試多士，考覈曲盡權衡公。"]'),
('ed106440-0e72-489b-a201-c663664ba5ec','上元後漕幕同僚二十八人會飲於西湖登千佛閣運幹趙漁樵希聖以坡詩七言絕句分韵得陌字','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','福星臺畔依紅客，厭踏紅塵穿紫陌。',96,'全唐诗/poet.song.104000.json','["福星臺畔依紅客，厭踏紅塵穿紫陌。", "湧金門外泛蘭舟，兩岸融融春水拍。", "隔浦笙歌寄幽思，向陽花柳饒春色。", "六橋突兀披丹青，千佛森羅眩金碧。", "登臨肯作懷古愁，志在雲臺書竹帛。", "須臾飲散晚風號，卻掃陰霾生桂魄。"]'),
('4931c25c-743b-4f41-a583-77793172723b','含山令尹章邦基即其所居剜山得石嵌空乃作堂於其上而目之曰玉璧窟求詩諸公予不識邦基而與其侄無爲簿濟之游濟之索詩故爲賦之','王之道','宋','宋诗','song-poetry','','[]','我聞美玉地所秘，出爲世用自有時。',192,'全唐诗/poet.song.104000.json','["我聞美玉地所秘，出爲世用自有時。", "譬猶景星與慶雲，千載往往一見之。", "君家玉璧豈無說，鑿山得石夸瑰奇。", "豈惟蒼翠實相似，温潤清越璠璵姿。", "細看高廣類墻壁，以璧名之故其宜。", "剜劖不已石無盡，此窟未易窺藩籬。", "作堂正在佳絕處，下視海岳如城池。", "錢塘雪浪湧澎湃，天竺煙岫紛參差。", "君于其間日成趣，長篇短句揮蛟螭。", "乃知地靈不愛寶，要令景物求新詩。", "顧我與君無半面，牽帥阿咸難固辭。", "沽哉沽哉吾與玉，它年相見期相知。"]'),
('6f8d917c-c2aa-4a8a-90be-eaa0d7a9b788','送神童胡元弼元英從其父胡庭俊歸秋浦','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖清麗春雨餘，子今欲去其焉如。',160,'全唐诗/poet.song.104000.json','["西湖清麗春雨餘，子今欲去其焉如。", "九華插天遠在望，三月不見愁容舒。", "二兒奔逸汗血駒，輩視長離與鵷雛。", "去年冒雪來其俱，一鳴上國驚群儒。", "書不負人人負書，公卿豈應終犁鋤。", "惠然過我騎甚都，蕭蕭晚吹飄襟裾。", "借問能留旬月無，吾亦理棹其歸夫。", "爲言與君不同塗，藹峰松竹鳴笙竽。", "奇童小友良不誣，異哉老蚌生雙珠。", "君之是行亦榮歟，三胡盛事喧州閭。"]'),
('52a3d4d7-3dc0-49a4-bf7d-d97aace929ca','和王覺民松軒詩','王之道','宋','宋诗','song-poetry','','[]','蒼髯綠髪三四椽，茅齋高下輕且軒。',64,'全唐诗/poet.song.104000.json','["蒼髯綠髪三四椽，茅齋高下輕且軒。", "清風入夜可人意，來與夫子調朱絃。", "連日秋陰蕩殘暑，抖擻煩襟欲輕舉。", "簡編燈火置勿論，且快蛟龍得雲雨。"]'),
('565e2b8e-6693-478b-9a8a-cf0806daf2a2','追和東坡郭熈秋山示王覺民','王之道','宋','宋诗','song-poetry','','[]','平生最愛烟水閒，不知歲月磨江山。',128,'全唐诗/poet.song.104000.json','["平生最愛烟水閒，不知歲月磨江山。", "干戈七載厭奔走，清霜夜入飛蓬間。", "我家山水擅平遠，未向郭熙見秋晚。", "驚鴻斷處抹微雲，野水盡頭横翠巘。", "林塘綠浄明拒霜，似與楓葉驕秋陽。", "東坡山谷妙言語，珠玉倍增山水光。", "亂離記得承平日，政出多門事如髪。", "傷心北猗歸何時，園苑荒涼萬年石。"]'),
('160f2347-230e-4dba-9197-2b490a284098','次韵袁望回見贈兼簡楊德潤','王之道','宋','宋诗','song-poetry','','[]','長堤十里荷花雨，隠約塵頭南去路。',160,'全唐诗/poet.song.104000.json','["長堤十里荷花雨，隠約塵頭南去路。", "故人戀戀不能忘，又遣長須寄新語。", "錦嚢玉軸纒朱絲，開緘怳覺雲烟飛。", "青山未許松柏老，綠野會致牛羊肥。", "嗟予衰滯煩訾相，十年相對江湖上。", "苦吟猛省爆鴨脚，劇論旋驚爛熊掌。", "分攜令我重回首，日月漂流易成久。", "因風頻寄數行書，毋蹈從前作詩痩。", "比鄰先生倦不出，德齒俱尊時第一。", "何妨杖屨日過逢，白酒黄鷄醉秋色。"]'),
('7b234c78-5525-4173-8bf6-cbf260607b3d','按麥行和魏定父韵','王之道','宋','宋诗','song-poetry','','[]','號啼莫怪妻兒疏，麥秋恰了償官租。',80,'全唐诗/poet.song.104000.json','["號啼莫怪妻兒疏，麥秋恰了償官租。", "噓嚅濕沫魚在陸，傷時令我思唐虞。", "平生學易有何說，大要豐財貴知節。", "相扶相吊來流亡，問言豆葉何時黄。", "遠哉天道所不曉，人比前年孰多少。"]'),
('bb5863f7-dd64-4d0a-aac2-f33cfe07197e','清江引用蘇養直韵示王覺民','王之道','宋','宋诗','song-poetry','','[]','荷葉亭亭綠滿塘，秋炎深得盖鴛鴦。',64,'全唐诗/poet.song.104000.json','["荷葉亭亭綠滿塘，秋炎深得盖鴛鴦。", "晚來江上西風急，收拾蓮紅付拒霜。", "萬山揺落見森樾，翠影蕭蕭冷梳髪。", "請君無作宋玉悲，來賦江樓望明月。"]'),
('cf0dd83e-42ec-49be-90f5-829b141b45a7','清江曲追和魯直韵','王之道','宋','宋诗','song-poetry','','[]','鬢邊殘雪幾春秋，自說生來不解憂。',64,'全唐诗/poet.song.104000.json','["鬢邊殘雪幾春秋，自說生來不解憂。", "晚食得魚吹荻火，秋盤尋筍艤松舟。", "布裙斗酒不須惡，明月清風且相樂。", "紫宸朝去醉眠時，初日寒林正揺落。"]'),
('bc86e4b3-6fba-42e0-941c-d87175595589','追和蘇養直飯牛歌','王之道','宋','宋诗','song-poetry','','[]','時來富貴非所憂，公卿何必皆黑頭。',64,'全唐诗/poet.song.104000.json','["時來富貴非所憂，公卿何必皆黑頭。", "力田孰若逢有秋，異哉甯戚親飯牛。", "商歌未絕驚齊侯，遂從仲父盟葵丘。", "勲業無聞死不休，磻溪有叟垂直鈎。"]'),
('4b7d5ae6-939a-4cd7-9f6b-dd2f787a45b1','次韵陶監丞茂安見贈','王之道','宋','宋诗','song-poetry','','[]','三年重見須川湄，捨舟東去何驅馳。',192,'全唐诗/poet.song.104000.json','["三年重見須川湄，捨舟東去何驅馳。", "王事靡盬莫遑息，人生所貴心相知。", "經從往返兩過我，一言意厚何多爲。", "向來江夏傾盖日，翕然譽望推麟儀。", "才猷伏火丹九轉，用之功效堪扶衰。", "重陽初過雨新霽，乾坤六合方平夷。", "邊城殘寇何足滅，廟堂勝算那容窺。", "相逢問我出世法，嗟我茅塞同荒陂。", "因君扣擊發深省，沉迷可笑群昏隨。", "我聞摩詰老居士，後身樓至今王維。", "忽然惠顧有緣契，怳若宿霧青天披。", "願君爲我取妙善，此界示現無邊慈。"]'),
('91b6f86b-e8e6-4f68-af44-640fa18406cd','和成都張通叔韵簡范偉明','王之道','宋','宋诗','song-poetry','','[]','高樓半天夸奕奕，一室蕭然再經昔。',96,'全唐诗/poet.song.104000.json','["高樓半天夸奕奕，一室蕭然再經昔。", "君今盤礴知幾時，邂逅相逢俱是客。", "襟懷磊落我輩人，傾盖便覺情相親。", "欲知富貴未乾沒，岷山錦水鍾精神。", "范侯國學同舍友，聞與吾人最親厚。", "别來不寄一行書，有便何妨爲予取。"]'),
('66be5fff-a1d5-442d-8e9d-127aa0b0bef1','贈蓑衣道人','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','七年兩見西湖濵，似向賤貧求貴人。',64,'全唐诗/poet.song.104000.json','["七年兩見西湖濵，似向賤貧求貴人。", "安民扶世在豪傑，貴人何必皆巖莘。", "嗟予坎壈今老矣，餬口相煎未能已。", "願君莫作貴人看，歲晚庶幾長不死。"]'),
('ffae6767-9b8d-4a80-836f-4c5f461d8899','寄白香巖縣丞','王之道','宋','宋诗','song-poetry','','[]','香山譽望不可攀，香山之後傳香巖。',64,'全唐诗/poet.song.104000.json','["香山譽望不可攀，香山之後傳香巖。", "香巖硉矹聳人目，香巖秀氣超塵凡。", "香巖之風清可掬，終日哦松適幽獨。", "媿我無能老杜門，何時一笑披青雲。"]'),
('5ef46222-9957-4eb2-8240-2e6252fb4268','題魏吉老若水軒','王之道','宋','宋诗','song-poetry','','[]','世情孔甘似醇酒，沾沾未必應心口。',64,'全唐诗/poet.song.104000.json','["世情孔甘似醇酒，沾沾未必應心口。", "覆手爲雨翻手雲，餘耳安能保長久。", "魏侯風味真可人，汪汪萬頃江湖春。", "相從丱歲今白髪，坐對小軒聊欠伸。"]'),
('065f2029-73cc-4134-b9c6-4f2d9639ec49','和沈次韓王覺民韵','王之道','宋','宋诗','song-poetry','','[]','二公才致同清壯，顧我無能但蘄向。',64,'全唐诗/poet.song.104000.json','["二公才致同清壯，顧我無能但蘄向。", "只今連璧復有誰，伯仲未可輕第行。", "小人老矣病且衰，目光近在牛背上。", "何當策蹇擬高談，歲晚寒雲連雪障。"]'),
('5553dd61-be23-4db5-ad11-a928beb29091','教授顔端行出示所和老杜曲江章因次韵  其一','王之道','宋','宋诗','song-poetry','','[]','浮雲捲盡秋天高，月光照水翻金濤。',40,'全唐诗/poet.song.104000.json','["浮雲捲盡秋天高，月光照水翻金濤。", "臨溪酌月羞溪毛。", "舉杯未飲欲誰酬，兹非沈謝須劉曹。"]'),
('e8a42add-592e-4a70-9d85-c1e7f6404c7d','教授顔端行出示所和老杜曲江章因次韵  其二','王之道','宋','宋诗','song-poetry','','[]','清夜無眠想千古，一字茫然墮沙莽。',40,'全唐诗/poet.song.104000.json','["清夜無眠想千古，一字茫然墮沙莽。", "賢否紛紛固難數。", "樓頭漏聲寂不聞，策策寒窗葉鳴雨。"]'),
('4d2ed115-f510-4960-bc14-4251f0c05706','教授顔端行出示所和老杜曲江章因次韵  其三','王之道','宋','宋诗','song-poetry','','[]','富貴從今信在天，君看黍稌多秋田。',40,'全唐诗/poet.song.104000.json','["富貴從今信在天，君看黍稌多秋田。", "金風玉宇秋無邊。", "白屋青雲朝暮耳，正如農父須逢年。"]'),
('b6ce3a75-c8bd-4b96-9aef-1ab95a4a5f70','定慧院海棠追和東坡呈虞季然陳德夫','王之道','宋','宋诗','song-poetry','','[]','春來何處無花木，偶向招提見君獨。',224,'全唐诗/poet.song.104000.json','["春來何處無花木，偶向招提見君獨。", "一枝着雨濕紅粧，便覺群芳自塵俗。", "嚶嚶幽鳥競遷喬，皎皎縶駒聊在谷。", "人生富貴會有日，莫以青雲輕白屋。", "固應遺策暫駐馬，況復過屠宜得肉。", "無心杜老吟不到，半醉楊妃睡難足。", "態濃意遠誰得似，空想當年麗人淑。", "嗟予坎壈世所鄙，正坐甲壬無背腹。", "少甘糠籺老葵藿，自笑清癯類霜竹。", "看花把酒發浩歎，反復新詩三過目。", "仇池老人已仙去，千載東坡與西蜀。", "思之展轉不可見，夜夢乘風跨黄鵠。", "朱唇翠袖妙今古，我欲宫商歌作曲。", "翻愁刻鵠難復工，唐突西施卻成觸。"]'),
('31ebf3a8-af43-4951-b77c-344c78d2de85','次韵寄荀晉仲簡陳夫子','王之道','宋','宋诗','song-poetry','','[]','二老亭亭雙屬玉，交映霜餘半溪綠。',192,'全唐诗/poet.song.104000.json','["二老亭亭雙屬玉，交映霜餘半溪綠。", "才高一世妙言語，落筆珠璣爛盈掬。", "時來釣叟爲三公，傅巖莘野誰雌雄。", "紛紛俗態任冷煖，風雲早晚騰蛟龍。", "中興復見宣和盛，須信人心協天命。", "真從僵仆正邦基，更向膏肓起民病。", "尺書寄我三長篇，管中窺豹非其全。", "墨渝紙敝未釋手，晴窗飛盡沉香煙。", "嗟予留滯濡須塢，夢寐斯文屬燕許。", "何當單騎造齋榻，遂使高軒出城府。", "春風回首歸萌芽，又促畦丁種早瓜。", "我心傾寫會有日，爲言已辦浮江槎。"]'),
('97cbe03d-4ed3-4c13-9c00-da89043dbcfd','再用奴字韵寄李廷吉','王之道','宋','宋诗','song-poetry','','[]','霜餘菊暗荷葉枯，千頭喜見君家奴。',160,'全唐诗/poet.song.104000.json','["霜餘菊暗荷葉枯，千頭喜見君家奴。", "離離丹實照綠葉，不減五松官大夫。", "邇來萬木凍欲死，東君信到梅花鬚。", "一枝亞竹斜照水，便覺清香無處無。", "李君江南我江北，正如員嶠鄰方壺。", "操修逈與世俗異，政事賴有神明扶。", "文書甚簡民甚喜，老吏往往寒無襦。", "項侯秀發西楚後，作詩語带山仙癯。", "願因徐辟見孟子，折簡未敢先招呼。", "異時鼎社遂酣暢，會使王衍悲黄壚。"]'),
('964ac720-0fba-4c23-a4f4-9450622a07ce','酬秦壽之見贈三首  其一','王之道','宋','宋诗','song-poetry','','[]','人言韓孟才相高，欲將詩骨追詩濤。',40,'全唐诗/poet.song.104000.json','["人言韓孟才相高，欲將詩骨追詩濤。", "可憐寒谷痩不毛。", "青蒿倚松亦浪語，遂令後世稱同曹。"]'),
('3d284974-771f-4ae6-b0ce-dbc6d88139ae','酬秦壽之見贈三首  其二','王之道','宋','宋诗','song-poetry','','[]','誰能胸次澆今古，老去蓬茅雜榛莽。',40,'全唐诗/poet.song.104000.json','["誰能胸次澆今古，老去蓬茅雜榛莽。", "樸遫已甘無足數。", "品題忽及乃君餘，頓覺焦枯得時雨。"]'),
('ddd4c826-3814-4c32-867c-3606f027c5f8','酬秦壽之見贈三首  其三','王之道','宋','宋诗','song-poetry','','[]','静中真樂全吾天，勿輕捨己芸人田。',40,'全唐诗/poet.song.104000.json','["静中真樂全吾天，勿輕捨己芸人田。", "甜均食蜜無中邊。", "濁醪麤飯自不惡，那能問命推行年。"]'),
('8b721b2c-284a-4e1e-8690-5fb5646f17f7','江天暮雪','王之道','宋','宋诗','song-poetry','','[]','凍雲垂地風栗冽，萬里江天暮飛雪。',64,'全唐诗/poet.song.104000.json','["凍雲垂地風栗冽，萬里江天暮飛雪。", "九華何處正嶙峋，瓊樹瑶林鬬明潔。", "扁舟突兀依寒蘆，朝來殘酒猶半壺。", "夜寒獨酌不成醉，卧聽宿雁鳴相呼。"]'),
('a5552edf-1dc0-4b7e-a663-bcf10f14566e','瀟湘夜雨','王之道','宋','宋诗','song-poetry','','[]','短篷暮艤湘江宿，坐見江豚起還伏。',64,'全唐诗/poet.song.104000.json','["短篷暮艤湘江宿，坐見江豚起還伏。", "忽然氣作浪山來，一夜雨聲如決瀆。", "淒淒寒氣欲相侵，燈火青熒更向深。", "床頭有酒且徑醉，免使萬慮縈吾心。"]'),
('b467057d-d660-4eba-8223-587ec9662362','洞庭秋月','王之道','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','扁舟夜泊蒹葭側，湖外雲間見明月。',64,'全唐诗/poet.song.104000.json','["扁舟夜泊蒹葭側，湖外雲間見明月。", "月光揺水掣金蛇，坐想騷人賦秋色。", "舉杯向天屬姮娥，君當照坐吾當歌。", "全勝送客九江上，荻花楓葉如渠何。"]'),
('a7890a58-8f73-46ed-bafc-484a077938a1','漁村落照','王之道','宋','宋诗','song-poetry','','[]','寒蘆萬頃迷西東，夕陽上下江天紅。',64,'全唐诗/poet.song.104000.json','["寒蘆萬頃迷西東，夕陽上下江天紅。", "炊烟幾處裊輕碧，知是漁家收釣筒。", "老翁長鬚更廣顙，路逢百錢掛藜杖。", "三杯酒罷月已高，短棹扁舟還獨往。"]'),
('d05c1847-8373-4ae8-aacf-c078b33d5853','平沙雁落','王之道','宋','宋诗','song-poetry','','[]','雨餘湖水吞遥空，前山宿霧開溟濛。',64,'全唐诗/poet.song.104000.json','["雨餘湖水吞遥空，前山宿霧開溟濛。", "坐看雁陣落沙觜，欲下復起摩蒼穹。", "寒蘆飛花秋色老，亂撲客衣紛不掃。", "肅肅驚風忽破行，卻似張芝作顛草。"]'),
('6f6e1370-6054-452c-8db2-7e2d3e34b645','和笑庵送麵','王之道','宋','宋诗','song-poetry','','[]','深堂傑閣松風鳴，黄梅已過雙溪晴。',64,'全唐诗/poet.song.104000.json','["深堂傑閣松風鳴，黄梅已過雙溪晴。", "不知城市乃有此，六月表裏冰壺清。", "我來蒙師炷香鼎，旋汲溪泉爲煎茗。", "明朝又送不托材，大慰枯腸怯龍餅。"]'),
('527a78d9-8f0b-4f99-890b-ab31c3dc02d7','贈堅上人','王之道','宋','宋诗','song-poetry','','[]','岷峩何處在目前，怳惚萬里惟心田。',128,'全唐诗/poet.song.104000.json','["岷峩何處在目前，怳惚萬里惟心田。", "道人遐想對縑素，毫端亹亹生雲烟。", "不煩捫參更歷井，坐見紫翠摩蒼天。", "崔嵬絕頂明積雪，崎嶇幽澗縈流泉。", "當時神禹導江處，隨山刋木知何年。", "竹齋言語妙天下，山情水思何緜緜。", "想當落筆快揮掃，精神如到岷峨巔。", "師誠乞詩我丐畫，不然無用徒相煎。"]'),
('940d63db-ce37-4a37-924a-ed5260501530','寄古上人若之用東坡徑山韵','王之道','宋','宋诗','song-poetry','','[]','寄語山中好看客，待與諸郎醉秋色。',96,'全唐诗/poet.song.104000.json','["寄語山中好看客，待與諸郎醉秋色。", "諸郎作詩學東坡，筆力駸駸清到骨。", "由來習氣相薫蒸，千古勾吳張季鷹。", "鱸魚斫鱠飲入夜，哦詩坐對風窗燈。", "好向少陵賡客至，樽酒盤飡正相似。", "請師淨掃壁上塵，凖擬臨時醉題字。"]'),
('24ab2e3f-970e-4a80-b58f-99e4494d44d6','送道覺遊天童山','王之道','宋','宋诗','song-poetry','','[]','小雨新晴接重九，獵獵西風振衰柳。',64,'全唐诗/poet.song.104000.json','["小雨新晴接重九，獵獵西風振衰柳。", "二禪過我欲東遊，爲說偕行得良友。", "天童老人笑垂手，應問師來欲何取。", "相逢莫作一日留，袖取鄞江過淮右。"]'),
('fd773e04-0c69-4875-99b0-12872cd7f683','四祖山','王之道','宋','宋诗','song-poetry','','[]','黄梅西去一舍許，奔走龍天瞻四祖。',192,'全唐诗/poet.song.104000.json','["黄梅西去一舍許，奔走龍天瞻四祖。", "師今何往昔何來，占斷金沙長作主。", "須知至道本不滅，豈獨高名固非取。", "偶傳衣鉢繼三世，遂配雲中詔千古。", "寺藏巖腹蟠地軸，塔據峰巔立天柱。", "稜層石棧斜甕玉，繚繞溪流緩縈組。", "月明飛瀑百虹掛，風撼長松萬蛟舞。", "路通澗谷横略彴，樹靄烟霞團縷數。", "清陰掃徑初入夏，蒼蘚封庭新過雨。", "留連歸客獲聨轡，邂逅主僧還接武。", "請觀異事花五葉，願結勝緣香一縷。", "何人爲作錦鷄夢，此意他年銘肺腑。"]'),
('dc4f1914-8fc7-4f19-9853-7d33459cdd6d','和荀晉仲題法隆韵','王之道','宋','宋诗','song-poetry','','[]','去來何所喜，一雨應澄清。',48,'全唐诗/poet.song.104000.json','["去來何所喜，一雨應澄清。", "憔悴有生理，嘆嗟成頌聲。", "酒壚從客醉，村畽問農耕。", "深得諏詢意，誰能繼此行。"]'),
('49eb7fd3-b426-4ac7-95d9-fe7c766616ff','和沈進可檢法秋夜飲客待月','王之道','宋','宋诗','song-poetry','','[]','欲雨雲容合，瀕江水氣浮。',48,'全唐诗/poet.song.104000.json','["欲雨雲容合，瀕江水氣浮。", "笑談初入夜，燈火適逢秋。", "巧借三豪便，還成一醉謀。", "投瓊酬木李，秪使老夫羞。"]'),
('4ff20750-c52f-4c1e-87a2-d9a20880c958','冬夜對月懷彦逢弟','王之道','宋','宋诗','song-poetry','','[]','荒庭寒有月，窮巷静無聲。',48,'全唐诗/poet.song.104000.json','["荒庭寒有月，窮巷静無聲。", "坐想積年别，遥同今夕明。", "蹉跎前進士，憔悴老書生。", "短棹歸來好，邉城久偃兵。"]'),
('64c4e436-2831-4bd2-ad1b-9623ccb9f0c5','和沈次韓歷陽歸來見寄','王之道','宋','宋诗','song-poetry','','[]','臘近梅争白，冬温柳漸黄。',48,'全唐诗/poet.song.104000.json','["臘近梅争白，冬温柳漸黄。", "强吟詩思澁，幽步野情長。", "别去嗟何闊，歸來肯遽忘。", "開緘得佳句，和氣溢寒鄊。"]'),
('be116b43-2f5e-4675-8823-5a8ebf64f5d1','和魏定父','王之道','宋','宋诗','song-poetry','','[]','十里南溪路，思君一望間。',48,'全唐诗/poet.song.104000.json','["十里南溪路，思君一望間。", "黄花秋色老，紅葉露痕殷。", "似說親朋集，遥知杖屨閒。", "徘徊松徑晚，踏破紫苔斑。"]'),
('922d11f6-5d64-4f64-956f-36134645b805','和子薳官牌夾口韵是日聞官軍破虔賊','王之道','宋','宋诗','song-poetry','','[]','滯留嗟是役，艱險笑吾生。',48,'全唐诗/poet.song.104000.json','["滯留嗟是役，艱險笑吾生。", "此去和風順，朝來虔賊平。", "湖山争喜氣，雁鶩送歡聲。", "千里前塘路，應知客念輕。"]'),
('b22e57db-dcdc-4efb-bfab-f13db2e438cb','和劉與可二首  其一','王之道','宋','宋诗','song-poetry','','[]','老來無柰懶，春至不勝情。',48,'全唐诗/poet.song.104000.json','["老來無柰懶，春至不勝情。", "萬石嗟遺迹，雙魚謝寄聲。", "壓花朝雨重，釃酒夜泉鳴。", "細把君詩讀，冰壺表裏清。"]'),
('f209b41d-77b9-42f1-9036-673bba1b3b66','和劉與可二首  其二','王之道','宋','宋诗','song-poetry','','[]','野塘春草遍，芳樹老藤纒。',48,'全唐诗/poet.song.104000.json','["野塘春草遍，芳樹老藤纒。", "遠信占黄耳，清游任白顛。", "山光晴抹黛，湖氣暖騰烟。", "我有邉韶癖，何妨晝日眠。"]'),
('fe37b882-6b72-4bfe-b739-4b3efb1f2d5f','和歷陽李簿見寄','王之道','宋','宋诗','song-poetry','','[]','短鬢紛垂白，衰顔悴带黄。',48,'全唐诗/poet.song.104000.json','["短鬢紛垂白，衰顔悴带黄。", "多寒冬更甚，少睡夜能長。", "舊學長荒廢，新知感愛忘。", "何時一樽酒，談詠带江鄉。"]'),
('8275e49f-95b2-497a-810f-808952af2235','和因格非見寄二首  其一','王之道','宋','宋诗','song-poetry','','[]','青山如我約，終日對柴門。',48,'全唐诗/poet.song.104000.json','["青山如我約，終日對柴門。", "學道未忘念，懷君空斷魂。", "時來當有用，事往置無論。", "反覆新詩讀，誰知老眼昏。"]'),
('58e099e1-2418-4231-a0f3-d2d891939937','和因格非見寄二首  其二','王之道','宋','宋诗','song-poetry','','[]','兀坐時看屋，閒居晝掩門。',48,'全唐诗/poet.song.104000.json','["兀坐時看屋，閒居晝掩門。", "吳吟聊遣興，楚些欲招魂。", "否泰宜周易，行藏付魯論。", "不須傷老大，眠食度朝昏。"]'),
('83ebb480-cd06-4e16-a1ce-7ed77f1d936d','和程德遠二首  其一','王之道','宋','宋诗','song-poetry','','[]','寓問發函舊，論交傾盖新。',48,'全唐诗/poet.song.104000.json','["寓問發函舊，論交傾盖新。", "幾年瞻翰墨，今日侍光塵。", "禦侮煩驍將，扶顛倚大臣。", "相逢更可恨，對酒漉陶巾。"]'),
('71a53ee9-1e1d-414d-bd07-616ebec8f141','和程德遠二首  其二','王之道','宋','宋诗','song-poetry','','[]','未盡通宵話，猶如一日秋。',48,'全唐诗/poet.song.104000.json','["未盡通宵話，猶如一日秋。", "壯懷天共遠，歸意雨同留。", "燈燼何明滅，蛩聲静應酬。", "十年爲客夢，應不負瀛洲。"]'),
('05db754f-7ee0-414c-b76c-3c826facef6c','追和老杜江上','王之道','宋','宋诗','song-poetry','','[]','獨坐日將夕，凄凄風雨秋。',48,'全唐诗/poet.song.104000.json','["獨坐日將夕，凄凄風雨秋。", "寒燈照孤屋，欹榻擁疏裘。", "身世槐安國，功名蜃化樓。", "歸歟老居士，蹤跡繼浮休。"]'),
('1f041c13-c0b7-4bb1-9a1e-b4e9206e2ed9','和彦時兄贈王廣濟','王之道','宋','宋诗','song-poetry','','[]','往矣古循吏，賢哉今長民。',48,'全唐诗/poet.song.104000.json','["往矣古循吏，賢哉今長民。", "牛羊歸落日，桑柘殿餘春。", "共學知名久，相逢見面新。", "瘡痍頼休養，猶喜見斯人。"]'),
('1c106c44-9b29-4f1e-8851-a7a3f9b5a71d','和王覺民簡褒山因上人棗嶺魏欣然二首  其一','王之道','宋','宋诗','song-poetry','','[]','七行才業在，寧久困無津。',48,'全唐诗/poet.song.104000.json','["七行才業在，寧久困無津。", "秋到搏風翼，春迴縱壑鱗。", "褒山方競秀，棗嶺益争新。", "珍重二三子，詩騷追古人。"]'),
('8daa3d78-6134-4b9a-993e-5df18e6ce892','和王覺民簡褒山因上人棗嶺魏欣然二首  其二','王之道','宋','宋诗','song-poetry','','[]','君來踰半月，未果一尊同。',48,'全唐诗/poet.song.104000.json','["君來踰半月，未果一尊同。", "湖水寒應碧，山梨雨自紅。", "何時過北牗，今日轉西風。", "相去無他地，孤城杖屨中。"]'),
('51da769d-7684-4cac-840b-888c5e8d12b3','酬陳勉仲勉仲寄示諸公所和黄字韵詩軸且責其歸重念匹夫懷璧之罪不敢靳因復和其韵反之','王之道','宋','宋诗','song-poetry','','[]','失梳蓬鬢結，欠洗垢衣黄。',48,'全唐诗/poet.song.104000.json','["失梳蓬鬢結，欠洗垢衣黄。", "我欲齊榮辱，誰能較短長。", "賤貧猶不去，富貴慎無忘。", "豈敢貪懷璧，春秋戒越鄉。"]'),
('2cb32dac-0842-4139-94f6-d88e9a1f1267','和秦壽之題蘄春驛浸月軒','王之道','宋','宋诗','song-poetry','','[]','千山初過雨，萬籟不鳴風。',48,'全唐诗/poet.song.104000.json','["千山初過雨，萬籟不鳴風。", "寶鑑沉寒水，冰輪上太空。", "竹梢低蘸碧，楓葉冷浮紅。", "終欲金沙去，經營一畆宫。"]'),
('06c77118-727d-4950-b0df-bc1db33888c1','吳興舟中有作','王之道','宋','宋诗','song-poetry','','[]','大澤知何處，扁舟快此行。',48,'全唐诗/poet.song.104000.json','["大澤知何處，扁舟快此行。", "綺羅紛勝賞，歌吹溢歡聲。", "茭葑春還合，波濤暮自平。", "臨風一披拂，誰識未歸情。"]'),
('3091675c-ffb0-48f3-b125-b398e8d79fdc','遣興','王之道','宋','宋诗','song-poetry','','[]','步屧隨兒輩，臨池得凭欄。',48,'全唐诗/poet.song.104000.json','["步屧隨兒輩，臨池得凭欄。", "久陰東虹斷，小滿北風寒。", "點水荷三疊，依墻竹數竿。", "乍晴何所喜，雲際遠山攅。"]'),
('3f66ff13-2aa3-4512-8364-ee5209671b4a','和龔聖任冬日即事','王之道','宋','宋诗','song-poetry','','[]','老怯繁霜勁，閒憐愛日温。',48,'全唐诗/poet.song.104000.json','["老怯繁霜勁，閒憐愛日温。", "禦寒朝强酒，防寇夜撐門。", "採薺籬根地，觀梅郭外春。", "餘生何所託，歸命大慈尊。"]'),
('085da647-7809-4a08-ac3b-bfecbd3df8b7','和秦壽之題黄州郡樓','王之道','宋','宋诗','song-poetry','','[]','西北張霞綺，東南漾月波。',48,'全唐诗/poet.song.104000.json','["西北張霞綺，東南漾月波。", "登臨笻作馬，吟詠筆翻河。", "思與蒼霞遠，情同白水多。", "新詩清且麗，標致壓陰何。"]'),
('07cf9be0-3c00-4cd7-8e7f-a5ed2a934f82','和子薳春江用老杜韵','王之道','宋','宋诗','song-poetry','','[]','欲去未成去，朔風鳴怒濤。',48,'全唐诗/poet.song.104000.json','["欲去未成去，朔風鳴怒濤。", "片帆洲外舉，列岫霧中高。", "竹屋雨沾被，紙窗寒透袍。", "遥應望歸艇，向夕走兒曹。"]'),
('de6f74cd-873d-441e-99ad-f12bd305259c','送彦逢弟赴西興鹽場','王之道','宋','宋诗','song-poetry','','[]','聞道西興去，全家共小舟。',48,'全唐诗/poet.song.104000.json','["聞道西興去，全家共小舟。", "别離江北岸，懷抱海東頭。", "閃閃風帆遠，滔滔雪浪浮。", "苕溪在何許，應爲故人留。"]'),
('153c8bea-90a7-4a18-ac61-e8fe582b35df','送安豐判官江叔夜用菊花韵','王之道','宋','宋诗','song-poetry','','[]','冬温行色好，江上菊花黄。',48,'全唐诗/poet.song.104000.json','["冬温行色好，江上菊花黄。", "鄊味蓴羮美，皇恩誥墨香。", "招延從北海，吟咏繼東陽。", "别後如相憶，時應問草堂。"]'),
('729c6ad6-570f-4fa1-9054-65ed4bc7f8bc','秋日喜雨題周材老壁','王之道','宋','宋诗','song-poetry','','[]','大旱彌千里，群心廹望霓。',48,'全唐诗/poet.song.104000.json','["大旱彌千里，群心廹望霓。", "簷聲聞夜溜，山氣見朝隮。", "處暑餘三日，高原滿一犂。", "我来何所喜，焦槁免無泥。"]'),
('54ac1fc3-02d5-4ffe-8f6f-e0696548938d','立春和孫子紹二首  其一','王之道','宋','宋诗','song-poetry','','[]','老窮推不去，湖海又逢春。',48,'全唐诗/poet.song.104000.json','["老窮推不去，湖海又逢春。", "懶復論三甲，空驚薦五辛。", "柳梢寒已動，萱草暖還新。", "我亦寰中物，因君試問津。"]'),
('2d41ce5c-65d9-4d29-adc6-7ca6eb069125','立春和孫子紹二首  其二','王之道','宋','宋诗','song-poetry','','[]','南浦初開凍，東郊未去寒。',48,'全唐诗/poet.song.104000.json','["南浦初開凍，東郊未去寒。", "芳華歸草木，生意入門闌。", "綠蟻供瑶甕，青絲送玉盤。", "新詩妙當世，賦答敢辭難。"]'),
('019f6d0f-70a9-4a56-adf4-537e4f49695a','題許公寨驛','王之道','宋','宋诗','song-poetry','','[]','畏景還迎日，追凉偶遡風。',48,'全唐诗/poet.song.104000.json','["畏景還迎日，追凉偶遡風。", "泉聲山上下，松影路西東。", "遠覽心猶壯，清吟語自工。", "雨多何所喜，郡國慶年豐。"]'),
('82d89b1d-6138-4312-8dc2-967c3132617f','和魯如晦春日過定遠山口','王之道','宋','宋诗','song-poetry','','[]','雨足塍塍水，春晴處處花。',48,'全唐诗/poet.song.104000.json','["雨足塍塍水，春晴處處花。", "畏塗雙隻堠，荒戍兩三家。", "心折朝鳴鹿，魂驚暮集鴉。", "想君行役苦，愁蹙不成嗟。"]'),
('c29c261c-0c85-468b-8421-c0a6411ab435','丹陽湖阻風二首  其一','王之道','宋','宋诗','song-poetry','','[]','水闊風還怒，舟輕浪更顛。',48,'全唐诗/poet.song.104000.json','["水闊風還怒，舟輕浪更顛。", "雲容初過雨，湖勢欲吞天。", "沙觜青楓外，魚罾白鳥邉。", "夕陽應到岸，沉醉酒家眠。"]'),
('623b56c3-ed4f-4aa6-a284-8ed83c4427d5','丹陽湖阻風二首  其二','王之道','宋','宋诗','song-poetry','','[]','老去心猶壮，詩成喜欲顛。',48,'全唐诗/poet.song.104000.json','["老去心猶壮，詩成喜欲顛。", "時危思報主，窮極待呼天。", "歸夢先湖外，離情到酒邉。", "晚來風更惡，舟卧不成眠。"]'),
('c46ec38e-3ba0-4468-b4c1-9a32f19ca892','和潘澤之沈元吉泛舟湖上','王之道','宋','宋诗','song-poetry','','[]','散騎真前輩，休文即當家。',48,'全唐诗/poet.song.104000.json','["散騎真前輩，休文即當家。", "泛舟成麗句，散綺見餘霞。", "驚去沙鷗没，招來酒斾斜。", "春歸何處覔，籬角見金沙。"]'),
('f57a8b88-7098-40b0-b0af-dcc4c27d570d','贈嚴彦醇','王之道','宋','宋诗','song-poetry','','[]','一别三年久，重來兩鬢蒼。',48,'全唐诗/poet.song.104000.json','["一别三年久，重來兩鬢蒼。", "瘦笻扶蹇步，新茗攪枯腸。", "得句情還適，逢人話頗長。", "湖山元不改，喪亂我心傷。"]'),
('5d2da2e8-0d4a-46ab-94bf-91fdc93a3464','中秋  其一','王之道','宋','宋诗','song-poetry','','[]','静院三更雨，樓臺一點風。',48,'全唐诗/poet.song.104000.json','["静院三更雨，樓臺一點風。", "新詩愁恨裏，故國夢魂中。", "節物它郷異，交情我輩同。", "眼前多怪事，咄咄强書空。"]'),
('2c28d7d7-7805-4ce0-83b5-435c595987f2','中秋  其二','王之道','宋','宋诗','song-poetry','','[]','出户喜折屐，江天來翠岑。',48,'全唐诗/poet.song.104000.json','["出户喜折屐，江天來翠岑。", "看雲忘久立，待月動微吟。", "闗塞重回首，簡編勞繫心。", "琴中有山水，應解遇知音。"]'),
('bf1c9f91-5a01-4035-9442-259c5c4a6510','題北莊用陳勉仲韵','王之道','宋','宋诗','song-poetry','','[]','幽亭臨水竹，云是使君莊。',48,'全唐诗/poet.song.104000.json','["幽亭臨水竹，云是使君莊。", "秋霽來觀稼，春融賦採桑。", "納凉供芡實，載酒摘蓮房。", "坐得牧民術，也應如牧羊。"]'),
('4f75c523-431d-4390-87d7-31bb366e758a','用陳阜卿勸農韵呈宣城太守  其一','王之道','宋','宋诗','song-poetry','','[]','何處催耕早，宣城刺史先。',48,'全唐诗/poet.song.104000.json','["何處催耕早，宣城刺史先。", "旗麾明曉市，耒耜徧晴川。", "道路歡聲接，樽罍麗景鮮。", "似聞携百榼，分餉及高年。"]'),
('eeba8920-9994-4144-aafa-dd6ac1ed995a','用陳阜卿勸農韵呈宣城太守  其二','王之道','宋','宋诗','song-poetry','','[]','欲知人意喜，萬户鬰爐煙。',48,'全唐诗/poet.song.104000.json','["欲知人意喜，萬户鬰爐煙。", "紗帽花垂額，金巵酒到蓮。", "歲豐端可卜，農勸競相傳。", "往矣南陽政，今追召父賢。"]'),
('36b2abb6-0ed9-47ed-b308-8dd537266bb0','燒火用陳西麓韵','王之道','宋','宋诗','song-poetry','','[]','燒火驅寒去，銜杯待暖回。',48,'全唐诗/poet.song.104000.json','["燒火驅寒去，銜杯待暖回。", "家書萬金值，懷抱一時開。", "臘雪猶棲樹，風光已着梅。", "相過隨處好，未怪損梅苔。"]'),
('27a6e200-4c1f-43ac-b91c-2d9ed2d8f156','題黄梅驛舍壁間','王之道','宋','宋诗','song-poetry','','[]','石潤占梅雨，山寒應麥秋。',48,'全唐诗/poet.song.104000.json','["石潤占梅雨，山寒應麥秋。", "清風鳴翠篠，疏雨濕紅榴。", "古驛苔封砌，荒城柳映樓。", "高吟一甌茗，聊爲故人留。"]'),
('2ff07c59-7e4a-40dd-a929-162a3dfb8383','太湖呈邵公晉沈元吉','王之道','宋','宋诗','song-poetry','','["\u592a\u6e56"]','半月江湖上，晚來方得風。',48,'全唐诗/poet.song.104000.json','["半月江湖上，晚來方得風。", "掛帆誰共快，到岸偶相逢。", "可是過從舊，都緣臭味同。", "長亭一樽茗，親厚意何窮。"]'),
('8e38c98e-c2e5-4ce1-9b84-76771dcb571a','秋夜對月','王之道','宋','宋诗','song-poetry','','[]','青廓經新雨，扶疏桂影秋。',48,'全唐诗/poet.song.104000.json','["青廓經新雨，扶疏桂影秋。", "夜凉山色静，風細水光浮。", "坐久因忘寐，詩成得散愁。", "願言乘此興，同賦庾公樓。"]'),
('8df0f126-068c-4226-b75f-9fd73a73bc27','春日無爲道中','王之道','宋','宋诗','song-poetry','','[]','旱甚山光暗，風顛日色微。',48,'全唐诗/poet.song.104000.json','["旱甚山光暗，風顛日色微。", "桑芽蝱翅小，荻筍彘肩肥。", "野寺看題壁，村壚問典衣。", "春容良不惡，楊柳正依依。"]'),
('a73f49ac-3f01-4f72-9d04-eab4f2fdc0e5','歸自合肥于四頂山絕湖呈孫仁叔抑之','王之道','宋','宋诗','song-poetry','','[]','達岸三時頃，瞻山四頂賖。',48,'全唐诗/poet.song.104000.json','["達岸三時頃，瞻山四頂賖。", "喬林知馬尾，亂石見麞牙。", "水脚浮青靛，湖脣滉白沙。", "漁人收輳網，歸去日西斜。"]'),
('ffee49f5-192e-49d8-a04d-15f1598b94e8','呈蔡元德二首  其一','王之道','宋','宋诗','song-poetry','','[]','别來閒計日，一日似三秋。',48,'全唐诗/poet.song.104000.json','["别來閒計日，一日似三秋。", "顧我無能老，逢君始欲愁。", "詩情今轉勝，交契久還稠。", "學問神龜似，當年繼踐猷。"]'),
('6eed0d8a-16cf-4e55-8bf3-af274c451da5','呈蔡元德二首  其二','王之道','宋','宋诗','song-poetry','','[]','一葉黄梅雨，潺潺過麥秋。',48,'全唐诗/poet.song.104000.json','["一葉黄梅雨，潺潺過麥秋。", "昏沉渾似醉，憔悴不禁愁。", "渠溢門庭淖，園荒草樹稠。", "乍晴酬絕唱，何幸對風猷。"]'),
('6e7d3ea6-833e-4783-84cf-7483b059fa79','蒙城早行','王之道','宋','宋诗','song-poetry','','[]','殘月千家閉，荒城萬竅號。',48,'全唐诗/poet.song.104000.json','["殘月千家閉，荒城萬竅號。", "舉頭華盖近，回睇啟明高。", "野逈霜迎面，風清冷透袍。", "十年河上路，從此步金鼇。"]'),
('7a6ac443-dbe3-4c22-9f5e-d0bdf6fe4585','固陵道中','王之道','宋','宋诗','song-poetry','','[]','道路榛菅合，装齎咫尺迷。',48,'全唐诗/poet.song.104000.json','["道路榛菅合，装齎咫尺迷。", "陟岡還見塔，下阪忽逢溪。", "逈野鳴朝麂，疏茨撼午鷄。", "固陵何處是，弛擔日應西。"]'),
('a31b72cc-2c55-49cc-8008-8301aeddd879','廣濟道中','王之道','宋','宋诗','song-poetry','','[]','曉日掛林麓，秋風入澗阿。',48,'全唐诗/poet.song.104000.json','["曉日掛林麓，秋風入澗阿。", "野禽飛自語，田父笑相過。", "村畽倉箱富，山蹊芋栗多。", "一鞭聊策蹇，馳上小羅坡。"]'),
('3d5b83ca-bf36-4da2-afb6-7e2087260ba9','沙窩道中','王之道','宋','宋诗','song-poetry','','[]','十里沙窩路，晴雲向暮開。',48,'全唐诗/poet.song.104000.json','["十里沙窩路，晴雲向暮開。", "褰裳九過水，駐馬一觀梅。", "歲晚松篁茂，山寒虎豹哀。", "不因王事迫，誰肯此間來。"]'),
('1cfccf68-f6aa-498b-b839-b04ec0972f97','舟過三丫河','王之道','宋','宋诗','song-poetry','','[]','揺落蒹葭浦，荒凉雁鶩村。',48,'全唐诗/poet.song.104000.json','["揺落蒹葭浦，荒凉雁鶩村。", "吳柑迎齒冷，魯酒著顔温。", "水澁風還逆，天寒日自暾。", "不堪歸思亂，鳥鵲閙黄昏。"]'),
('1d65d54a-aa7c-4953-b2e2-ca8349c2719f','過白羊市','王之道','宋','宋诗','song-poetry','','[]','小市環農畆，長橋接佛宫。',48,'全唐诗/poet.song.104000.json','["小市環農畆，長橋接佛宫。", "扁舟帆影日，幽鳥柳陰風。", "沙觜淺深水，樹梢紅白茸。", "乍聞秋糴賤，吾亦慶年豐。"]'),
('d5924324-7827-42df-b147-19d1a976219c','立春示兒二首  其一','王之道','宋','宋诗','song-poetry','','[]','雪盡適霑雨，臘窮初得春。',48,'全唐诗/poet.song.104000.json','["雪盡適霑雨，臘窮初得春。", "上冰魚意樂，出谷鳥聲新。", "便覺風光好，何憂活計貧。", "一樽聊共醉，疏率見吾真。"]'),
('7df63301-954d-450c-9b8f-86bda73b0cda','立春示兒二首  其二','王之道','宋','宋诗','song-poetry','','[]','朝來何所喜，人唱玉樓春。',48,'全唐诗/poet.song.104000.json','["朝來何所喜，人唱玉樓春。", "酒著心還壯，詩成思轉新。", "士衡寧久困，曲逆豈長貧。", "千載風雲會，欣逢聖主真。"]'),
('35660bc4-e85c-4440-aede-a5228c1b824c','追和李義山賦菊二首  其一','王之道','宋','宋诗','song-poetry','','[]','嫩萼猶封綠，繁英已醉黄。',48,'全唐诗/poet.song.104000.json','["嫩萼猶封綠，繁英已醉黄。", "雨餘三徑晚，秋到一枝香。", "滴滴盈朝露，暉暉映夕陽。", "何妨浮玉斚，共醉木蘭堂。"]'),
('8f735588-403d-4b1c-a9a6-95e23b229b3c','追和李義山賦菊二首  其二','王之道','宋','宋诗','song-poetry','','[]','團團青盖小，拂拂御袍黄。',48,'全唐诗/poet.song.104000.json','["團團青盖小，拂拂御袍黄。", "翠葉凌霜秀，繁英浥露香。", "浮觴追北牖，飲水記南陽。", "采采東籬下，行歌對草堂。"]'),
('39a3f3e1-8d66-40fd-8c2f-b53adc1c830f','和沈次韓秋日雨後督子厚報','王之道','宋','宋诗','song-poetry','','[]','江檻連朝雨，山齋昨夜凉。',48,'全唐诗/poet.song.104000.json','["江檻連朝雨，山齋昨夜凉。", "不知新稻熟，深怪晚炊香。", "得句君應喜，聞風我漫狂。", "繡溪行樂處，雲水幾千章。"]'),
('d295b78b-9636-48f6-aebd-6153b7b27c12','秋日即事三首  其一','王之道','宋','宋诗','song-poetry','','[]','晚來何所喜，急雨洗新秋。',48,'全唐诗/poet.song.104000.json','["晚來何所喜，急雨洗新秋。", "幸遂登高賦，應容遇勝留。", "藕花明遠近，鷗鳥任沉浮。", "不用揮紈扇，何妨醉玉舟。"]'),
('cd3cf526-0b33-4127-acd6-711f92b68b60','秋日即事三首  其二','王之道','宋','宋诗','song-poetry','','[]','今日知何日，西風正得秋。',48,'全唐诗/poet.song.104000.json','["今日知何日，西風正得秋。", "天心方祚漢，人物合師留。", "才略煩威敵，聲名頼鎮浮。", "不妨臨賦樂，汎汎有楊舟。"]'),
('ddcb9c0a-d09a-4312-87a6-862c41f19b7a','秋日即事三首  其三','王之道','宋','宋诗','song-poetry','','[]','俛仰黄花集，澄清九月秋。',48,'全唐诗/poet.song.104000.json','["俛仰黄花集，澄清九月秋。", "預愁新任迫，難爲故人留。", "風去山光合，江迴水氣浮。", "何當脱羈絆，同辦五湖舟。"]'),
('678e0aaf-9d67-4903-a15e-fd22ab19a992','雪晴三首  其一','王之道','宋','宋诗','song-poetry','','[]','雪壓千山浄，雲披萬里晴。',48,'全唐诗/poet.song.104000.json','["雪壓千山浄，雲披萬里晴。", "木冰争霽色，簷雨碎寒聲。", "静映吟窗冷，輕浮茗椀清。", "最宜今夜月，來借短檠明。"]'),
('566a3912-b370-42ad-b354-1b4a6479153e','雪晴三首  其二','王之道','宋','宋诗','song-poetry','','[]','湖山開宿靄，院落快新晴。',48,'全唐诗/poet.song.104000.json','["湖山開宿靄，院落快新晴。", "滉漾溶銀色，潺湲過雨聲。", "味增茶品勝，光奪月華清。", "放出東墻角，梅花數點明。"]'),
('f66c6d86-a59f-4843-8a87-cebd75cb5172','雪晴三首  其三','王之道','宋','宋诗','song-poetry','','[]','氣暾寒日曉，光照遠山晴。',48,'全唐诗/poet.song.104000.json','["氣暾寒日曉，光照遠山晴。", "鄒谷有春意，袁門聞履聲。", "映書何自苦，炙背不妨清。", "邂逅逢詩將，高吟眼倍明。"]'),
('fbc9a60a-fcd6-4068-aeea-35302890678b','和余時中元夕二首  其一','王之道','宋','宋诗','song-poetry','','[]','今夕知何夕，熈熈萬室春。',48,'全唐诗/poet.song.104000.json','["今夕知何夕，熈熈萬室春。", "歌樓醒醉客，燈市往來人。", "勸酒行杯促，聯詩得句新。", "銅壺休見廹，歡笑正相親。"]'),
('d429c4af-5650-4082-b64c-62407e48471b','和余時中元夕二首  其二','王之道','宋','宋诗','song-poetry','','[]','羅綺行歌夜，杯盤坐笑春。',48,'全唐诗/poet.song.104000.json','["羅綺行歌夜，杯盤坐笑春。", "舞衫催急管，步障擁佳人。", "燈火珠星粲，樓臺璧月新。", "傳柑良可樂，黼座玉音親。"]'),
('5613abfa-dbb4-4e93-b4c0-887f89f27def','次韵魯如晦七夕','王之道','宋','宋诗','song-poetry','','[]','今夕知何夕，相逢莫漫愁。',48,'全唐诗/poet.song.104000.json','["今夕知何夕，相逢莫漫愁。", "凉颸開北牖，新月挂西樓。", "重惜經年别，貪延數刻秋。", "明朝河漢隔，西向望牽牛。"]'),
('adf2c11e-ad4a-41af-95f9-9c9987fefea5','秋日郊行','王之道','宋','宋诗','song-poetry','','[]','斷橋臨野水，疏屋見人家。',48,'全唐诗/poet.song.104000.json','["斷橋臨野水，疏屋見人家。", "嫩綠幾畦菜，深黄三徑花。", "斷雲行自逐，征雁望還賖。", "好訪韓湘去，山林養白鴉。"]'),
('d9802764-8ae4-450e-9154-118e2ef62377','閒眠二首  其一','王之道','宋','宋诗','song-poetry','','[]','乍暖經行久，新凉出浴初。',48,'全唐诗/poet.song.104000.json','["乍暖經行久，新凉出浴初。", "酒酣春晝永，食飽午鐘餘。", "我懶喜聊復，君閒應樂胥。", "年來苦奔走，此味竟何如。"]'),
('bb39c6aa-93ab-42ea-85e7-3eb917b06ca0','閒眠二首  其二','王之道','宋','宋诗','song-poetry','','[]','秋懷一事無，暑盡晝凉初。',48,'全唐诗/poet.song.104000.json','["秋懷一事無，暑盡晝凉初。", "竹户静長閉，藜牀安有餘。", "逍遥化蝴蝶，容易入華胥。", "天上多官府，神仙恐不如。"]'),
('dd51b26b-e9f4-4395-8b41-78d895774a4d','閒居','王之道','宋','宋诗','song-poetry','','[]','五斗不爾競，一區聊自營。',48,'全唐诗/poet.song.104000.json','["五斗不爾競，一區聊自營。", "閒看探花信，静坐聽松聲。", "約客酒初熟，訪僧詩漫成。", "有時過閭里，往往競邀迎。"]'),
('c01ddf9c-68e5-4623-b175-035efd08e5ae','獨步','王之道','宋','宋诗','song-poetry','','[]','飽餘惟欲睡，散睡步東園。',48,'全唐诗/poet.song.104000.json','["飽餘惟欲睡，散睡步東園。", "雨足富蓮子，年豐多稻孫。", "崎嶇窮竹徑，詰曲遍花源。", "何必冠童輩，偕來笑語喧。"]'),
('5cb9e17a-062f-4ba5-a2fc-452f6b058976','逍遥堂二首  其一','王之道','宋','宋诗','song-poetry','','[]','獨坐虚堂寂，煙銷瓦博山。',48,'全唐诗/poet.song.104000.json','["獨坐虚堂寂，煙銷瓦博山。", "出游魚自樂，飛倦鳥知還。", "花氣清風遠，槐陰白晝閒。", "逍遥入詩思，落筆笑談間。"]'),
('36f6209c-a5ab-4c7b-a003-836a3dec1d8d','逍遥堂二首  其二','王之道','宋','宋诗','song-poetry','','[]','娜婀風前竹，空濛雨外山。',48,'全唐诗/poet.song.104000.json','["娜婀風前竹，空濛雨外山。", "孤雲心共遠，短艇興俱還。", "酒有雙蓮勝，詩無一字閒。", "因君成悵想，時到夢魂間。"]'),
('b4c8ab38-3a8c-44d5-acd5-edf4e91cf657','飽食','王之道','宋','宋诗','song-poetry','','[]','予亦屬厭耳，女寛何嘆三。',48,'全唐诗/poet.song.104000.json','["予亦屬厭耳，女寛何嘆三。", "一簞儻知足，八珍自忘貪。", "駝峰擅西北，瑶柱誇東南。", "但願無是餒，藜羮非我慚。"]'),
('b0bcd81e-f11b-41eb-b494-a6a50557f96f','放船和子薳韵','王之道','宋','宋诗','song-poetry','','[]','冬温寒日好，歲晚早梅開。',48,'全唐诗/poet.song.104000.json','["冬温寒日好，歲晚早梅開。", "帆脚隨風轉，江流與岸迴。", "坐憐青嶂遠，静見白鷗來。", "水驛三千里，斯游亦壯哉。"]'),
('6a2125ea-863d-4e67-a073-7fa3c7117e29','追和東坡倦夜一首','王之道','宋','宋诗','song-poetry','','[]','風閣開還閉，龕燈暗復明。',48,'全唐诗/poet.song.104000.json','["風閣開還閉，龕燈暗復明。", "竹間聽露滴，庭際看雲行。", "皎月千門静，微風一座清。", "只今廷諍者，誰復繼元成。"]'),
('90d4b05b-69c9-45db-81db-e41f7a050dd4','和子薳泛江送客用老杜韵','王之道','宋','宋诗','song-poetry','','[]','北風還入夜，波怒未能平。',48,'全唐诗/poet.song.104000.json','["北風還入夜，波怒未能平。", "江氣雲煙重，山光水墨輕。", "熒熒漁火亂，慘慘暮寒生。", "咫尺淮郷路，淹留繫此情。"]'),
('84ceb1a9-6713-4daa-ae21-864d22c456d0','久客和子薳用老杜韵','王之道','宋','宋诗','song-poetry','','[]','舟解風還順，江神亦世情。',48,'全唐诗/poet.song.104000.json','["舟解風還順，江神亦世情。", "滯留三月過，攀送一帆輕。", "行止闗吾道，窮通任此生。", "梅梢春已動，冰雪漫縱横。"]'),
('410498e4-76d5-40b1-a8c6-a83be049d6bb','歷陽倅蒙菴鄭公卒於位記歲在丁丑與僕有交承之契方來自鎮西而僕亦自安豐往邂逅於合肥驛中獲爲三日之款所談無非周易太玄老莊之書開警蒙昧多矣公平生學佛行一着端的不昧所謂毫髪無遺恨者僕老矣請從其後而爲浄土之游似不晚也作是詩以弔之  其一','王之道','宋','宋诗','song-poetry','','[]','我倅安豐日，君來自歷陽。',48,'全唐诗/poet.song.104000.json','["我倅安豐日，君來自歷陽。", "交承分彼此，邂逅及行藏。", "精義通玄易，微言妙老莊。", "刹那今十稔，歎仰未能忘。"]'),
('9c138416-f2fa-4bed-a28b-bc9a701777ab','歷陽倅蒙菴鄭公卒於位記歲在丁丑與僕有交承之契方來自鎮西而僕亦自安豐往邂逅於合肥驛中獲爲三日之款所談無非周易太玄老莊之書開警蒙昧多矣公平生學佛行一着端的不昧所謂毫髪無遺恨者僕老矣請從其後而爲浄土之游似不晚也作是詩以弔之  其二','王之道','宋','宋诗','song-poetry','','[]','東晉陶元亮，西京董仲舒。',48,'全唐诗/poet.song.104000.json','["東晉陶元亮，西京董仲舒。", "高風敦薄俗，妙論見遺書。", "水石傷新窆，松篁慘舊廬。", "楞伽今在否，此道發眀初。"]'),
('60f04633-3312-42f6-84b1-838a55e63f6c','哭韓積中二首  其一','王之道','宋','宋诗','song-poetry','','[]','命矣窮張籍，歸哉病長卿。',48,'全唐诗/poet.song.104000.json','["命矣窮張籍，歸哉病長卿。", "焦湖家自遠，畏日我同行。", "想像分攜處，依稀謦欬聲。", "仙踪向西路，回首淚縱横。"]'),
('cd33f9da-da5b-4049-ac1d-e8abf8a43e70','哭韓積中二首  其二','王之道','宋','宋诗','song-poetry','','[]','多能傾相府，高義著房州。',48,'全唐诗/poet.song.104000.json','["多能傾相府，高義著房州。", "脱略通侯貴，追隨逐客遊。", "敢論當世比，曾向古人求。", "怊悵今樓護，黄泉已再秋。"]'),
('e6b07845-5b5b-4dfe-b2e0-702c4d51ac5d','哀陳夫子  其一','王之道','宋','宋诗','song-poetry','','[]','不見陳夫子，依稀四載餘。',48,'全唐诗/poet.song.104000.json','["不見陳夫子，依稀四載餘。", "云亡前日信，報葬幾時書。", "玉軸千篇在，牙籖萬卷儲。", "九原應有恨，新第落成初。"]'),
('c56c9322-ec60-4f1b-95c0-829a30cef194','哀陳夫子  其二','王之道','宋','宋诗','song-poetry','','[]','去矣君何速，聞之我重悲。',48,'全唐诗/poet.song.104000.json','["去矣君何速，聞之我重悲。", "席塵埋古鼎，書蠧入新詩。", "鴻雁嗟安仰，枌揄痛莫追。", "木瓜慚未報，臨紙涕漣洏。"]'),
('a98f9764-ff99-4e7d-a3fc-87837206178d','哀湯與立父  其一','王之道','宋','宋诗','song-poetry','','[]','薄俗久不競，丘園多逸民。',48,'全唐诗/poet.song.104000.json','["薄俗久不競，丘園多逸民。", "聞君輕去世，令我重沾巾。", "一夢苕溪曉，千年石堵春。", "人情不能已，南望哭江濱。"]'),
('14bd3c7d-f429-40b2-86d5-c5348197f7d7','哀湯與立父  其二','王之道','宋','宋诗','song-poetry','','[]','一門今七世，誰復似君家。',48,'全唐诗/poet.song.104000.json','["一門今七世，誰復似君家。", "盛事追公藝，高風暎伯華。", "板輿方就養，玉樹遽興嗟。", "叔子今何在，魂應到馬牙。"]'),
('cee8db29-cbf1-4916-86f3-2e58c25f445d','哀湯與立父  其三','王之道','宋','宋诗','song-poetry','','[]','尚記宣和末，賢科擢阿戎。',48,'全唐诗/poet.song.104000.json','["尚記宣和末，賢科擢阿戎。", "義方傳輦下，士譽走江東。", "賀厦心雖切，披雲意自忡。", "思君想眉目，悲咽對西風。"]'),
('374668bd-113f-4c70-8023-8746b197d881','哀徐朝義恭人潘氏  其一','王之道','宋','宋诗','song-poetry','','[]','愛子心惟壹，宜家語不煩。',48,'全唐诗/poet.song.104000.json','["愛子心惟壹，宜家語不煩。", "雨添南澗藻，風偃北堂萱。", "鬰鬰今同穴，詵詵正滿門。", "善哉摩頂記，歸奉大慈尊。"]'),
('1236a2dc-abfa-4074-843b-ede3e434c5c0','哀徐朝義恭人潘氏  其二','王之道','宋','宋诗','song-poetry','','[]','城見三千歲，人終八十春。',48,'全唐诗/poet.song.104000.json','["城見三千歲，人終八十春。", "從夫安樂近，拜佛率陀新。", "婉孌書彤管，凄凉歎棘薪。", "中郎有賢子，遺澤擢平津。"]'),
('df3125b1-e92e-4811-9235-4ad92412a4d2','和秦壽之題靖安棲霞觀','王之道','宋','宋诗','song-poetry','','[]','飛觀臨無地，江天在目中。',48,'全唐诗/poet.song.104000.json','["飛觀臨無地，江天在目中。", "晚霞工射日，秋水欲浮空。", "蓼岸深迷綠，楓林遠映紅。", "歸歟還可喜，千里一帆風。"]'),
('b871de10-fca1-4073-93ca-987ea39a90dd','夏日歸自寶林二首  其一','王之道','宋','宋诗','song-poetry','','[]','十里招提路，崎嶇祝聖歸。',48,'全唐诗/poet.song.104000.json','["十里招提路，崎嶇祝聖歸。", "青黄原上麥，紅白草間薇。", "正看雲容合，俄驚雨脚飛。", "餘花被霑濕，芳氣襲人衣。"]'),
('2d4ca218-e152-4119-ae55-37ec64fc91d9','夏日歸自寶林二首  其二','王之道','宋','宋诗','song-poetry','','[]','遠岫升初日，長林靄曙煙。',48,'全唐诗/poet.song.104000.json','["遠岫升初日，長林靄曙煙。", "峰迴遥見塔，溪轉静鳴泉。", "竹籜新披錦，茅花欲擘綿。", "清和多美蔭，歸路得蹁蹮。"]'),
('13a6c8db-b344-4b25-8f6d-679ffc767343','和詹德秀出南汰二首  其一','王之道','宋','宋诗','song-poetry','','[]','曉出東郊路，春霖數尺泥。',48,'全唐诗/poet.song.104000.json','["曉出東郊路，春霖數尺泥。", "湖山供勝賞，花草覔新題。", "坐聽鳴鴻北，歸看落日西。", "乍晴何所喜，芳樹早鶯啼。"]'),
('dcb00cc2-499b-4922-9747-800e09e92210','和詹德秀出南汰二首  其二','王之道','宋','宋诗','song-poetry','','[]','小沼鳴蛙吹，虚堂墮燕泥。',48,'全唐诗/poet.song.104000.json','["小沼鳴蛙吹，虚堂墮燕泥。", "對花容命酒，書事喜分題。", "僧舍喬林北，田家古道西。", "鵓鳩晴喚婦，穀穀傍人啼。"]'),
('9ec23d80-88d8-452c-864a-1f32f12f66ef','題香巖與何希淵陳勉仲聯轡','王之道','宋','宋诗','song-poetry','','[]','市井三墪北，招提百丈東。',48,'全唐诗/poet.song.104000.json','["市井三墪北，招提百丈東。", "晴雲披靉靆，寒日弄曈曨。", "滴瀝林梢雨，凄凉盖影風。", "我慚追驥足，策蹇走巴僮。"]'),
('2fd2c85a-e085-4138-a689-894b8dea1778','東靈鷲','王之道','宋','宋诗','song-poetry','','[]','松盖雨還偃，雲扉風自闗。',48,'全唐诗/poet.song.104000.json','["松盖雨還偃，雲扉風自闗。", "縱横兩溪水，高下萬重山。", "入室三彈指，臨淵一點顔。", "懸知少來往，石笋綠苔斑。"]'),
('4b02d05b-ef4e-4e29-801b-aa675da5b31e','題石磧明因院用李端叔韵','王之道','宋','宋诗','song-poetry','','[]','楚漢干戈地，巋然見此山。',48,'全唐诗/poet.song.104000.json','["楚漢干戈地，巋然見此山。", "艱難思帝業，牢落漫禪關。", "野鳥驚人散，江湖到岸邉。", "明朝又東去，空羡阿師閒。"]'),
('ab2dba67-76b6-4dd9-90bd-f658bdd8cbf4','題法輪寺','王之道','宋','宋诗','song-poetry','','[]','孤塔雲烟外，荒蹊草莽間。',48,'全唐诗/poet.song.104000.json','["孤塔雲烟外，荒蹊草莽間。", "蓼花紅糝碎，楓葉絳綃殷。", "送客三溪遠，逢僧半日閒。", "功名休覽鏡，淪落鬢毛斑。"]'),
('2ae89832-85da-418e-8f1a-6d117bd2ac60','題宣州書堂山寺','王之道','宋','宋诗','song-poetry','','[]','書堂形勝好，山轉與江抛。',48,'全唐诗/poet.song.104000.json','["書堂形勝好，山轉與江抛。", "泉古應黄蘖，亭新換白茅。", "雨餘蒼蘚合，春晚綠陰交。", "欲問香巖旨，風林竹自敲。"]'),
('8cba5126-04a7-48d7-8a49-076633a60abf','秋日遊南汰二首  其一','王之道','宋','宋诗','song-poetry','','[]','小雨霑秋旱，清曦霽曉氛。',48,'全唐诗/poet.song.104000.json','["小雨霑秋旱，清曦霽曉氛。", "山留歸壑水，風送過江雲。", "碧瓦觚稜出，黄茅兔徑分。", "高僧似相喜，茗飲話殷勤。"]'),
('dcb2a373-a97a-4b63-a355-b11b6bc16fe7','秋日遊南汰二首  其二','王之道','宋','宋诗','song-poetry','','[]','松篁團野色，葭薍接江氛。',48,'全唐诗/poet.song.104000.json','["松篁團野色，葭薍接江氛。", "芳菊開新雨，晴天掃片雲。", "村醪過寺共，風袂轉山分。", "邂逅梅夫子，清談得致勤。"]'),
('43e60dec-d885-4c0b-b93f-2e13c5e44131','次因上人韵','王之道','宋','宋诗','song-poetry','','[]','一從潜水别，三見菊花黄。',48,'全唐诗/poet.song.104000.json','["一從潜水别，三見菊花黄。", "舊好論交篤，新詩引興長。", "勞生閒自笑，道術淡相忘。", "蝴蝶秋來懶，時應到睡鄉。"]'),
('b7a4c9d0-fa99-4d02-9550-dfe1607b9504','送浮屠善慧東游','王之道','宋','宋诗','song-poetry','','[]','西去方祈穀，東來適佩萸。',48,'全唐诗/poet.song.104000.json','["西去方祈穀，東來適佩萸。", "凄風梧脱葉，積雨稻生蚨。", "詩骨寒巖木，禪心古廟爐。", "莫將明月句，容易謁姑蘇。"]'),
('9f5f494f-10aa-4307-bd9c-c6ae5e06b578','送浮屠道郭雲游','王之道','宋','宋诗','song-poetry','','[]','何必袁州去，塵塵小釋迦。',48,'全唐诗/poet.song.104000.json','["何必袁州去，塵塵小釋迦。", "一笻非外物，四海即吾家。", "曉色霜還重，秋容菊正華。", "此行良不惡，冬笋已排牙。"]'),
('b920ad9c-f6c9-47f8-abbc-1def63df6674','和鞏興宗題回峰寺贈明山主','王之道','宋','宋诗','song-poetry','','[]','江共煙雲遠，山連藪澤長。',48,'全唐诗/poet.song.104000.json','["江共煙雲遠，山連藪澤長。", "日從三伏烈，風借九秋凉。", "休作桃花觀，聊同柏子香。", "相逢無一事，不必下禪牀。"]'),
('595ea3a3-bfe8-4845-8685-00648b12f2d9','寧公新拜首座因贈','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','著書新奏御，優詔及禪扉。',48,'全唐诗/poet.song.104000.json','["著書新奏御，優詔及禪扉。", "首座名雖貴，家山老未歸。", "磬聲寒繞枕，塔影静侵衣。", "終憶西湖上，秋風白鳥飛。"]'),
('b9f55b28-a685-4227-bb40-b7e3cc3dfb7e','春日遊西塔示本上人','王之道','宋','宋诗','song-poetry','','[]','暇日搜奇勝，羸驂適莽蒼。',48,'全唐诗/poet.song.104000.json','["暇日搜奇勝，羸驂適莽蒼。", "幽花撩醉眼，早麥慰饑腸。", "佛屋幾間在，村墟三里長。", "廉纖晚來雨，未覺客心傷。"]'),
('8c34ab32-c908-4c47-8d5e-7fcee63e3490','春日書懷  其一','王之道','宋','宋诗','song-poetry','','[]','野桃經雨爛争華，似促畦丁種早瓜。',64,'全唐诗/poet.song.104000.json','["野桃經雨爛争華，似促畦丁種早瓜。", "不見少年閒信馬，空憐寒士出無車。", "泥融近水芹抽葉，地暖依墻薺放花。", "偶憶惠連春草句，夜來魂夢到天涯。"]'),
('d8a8e3b4-d3f7-459e-9744-6d6820628582','春日書懷  其二','王之道','宋','宋诗','song-poetry','','[]','高文知已動天庭，昨日春雷下六丁。',64,'全唐诗/poet.song.104000.json','["高文知已動天庭，昨日春雷下六丁。", "濟旱會施惟肖雨，舉賢先應少微星。", "行趨北闕形神健，坐對東風醉夢醒。", "連日暖烟隨處好，吳山應勝越山青。"]'),
('e9ea43d0-2852-44f3-a15e-ac3694d4c949','立春小酌呈諸兄','王之道','宋','宋诗','song-poetry','','[]','共喜春隨曉色來，東郊歡踴賽牛迴。',64,'全唐诗/poet.song.104000.json','["共喜春隨曉色來，東郊歡踴賽牛迴。", "破寒青轉蕪菁葉，抵日紅抽芍藥荄。", "歲換未勞驚我壯，酒封聊復爲君開。", "上林不負遷喬約，百蟄同驚此夜雷。"]'),
('2a9bd930-a27b-4eed-a6d5-74d0a8e5eefe','和伯父仲球立春即事二首  其一','王之道','宋','宋诗','song-poetry','','[]','怪得青腰稍霽威，卻應緹室報飛灰。',64,'全唐诗/poet.song.104000.json','["怪得青腰稍霽威，卻應緹室報飛灰。", "揺風柳带緣冰重，破凍溪流與岸迴。", "群盜傳聞湖外去，愁雲凖擬歲前開。", "玉盤絲菜今蕭索，頼有詩筒日往來。"]'),
('f0f882bf-9844-4755-afb8-9e64d6fcd6cb','和伯父仲球立春即事二首  其二','王之道','宋','宋诗','song-poetry','','[]','對雪酬春付酒杯，兵餘真似復然灰。',64,'全唐诗/poet.song.104000.json','["對雪酬春付酒杯，兵餘真似復然灰。", "路通千里傳書去，人喜三軍破賊迴。", "梅萼封檀香未徹，湖聲撞玉凍初開。", "疏籬敗屋休興歎，幸事群兇不再來。"]'),
('c2635c5c-50d8-4f80-ade7-6c3505a29782','春日有感示魏定父','王之道','宋','宋诗','song-poetry','','[]','聚散時來不自由，相逢相别欲何尤。',64,'全唐诗/poet.song.104000.json','["聚散時來不自由，相逢相别欲何尤。", "韋皋况有三年約，陶穀端非一日謀。", "殘角爲誰驚曉夢，遠山多事惹春愁。", "故園又作驪駒賦，尚幸持觴爲勸留。"]'),
('061c5408-db32-4977-86b8-efb3557b70ff','清明即事','王之道','宋','宋诗','song-poetry','','[]','柳逕桃溪碧草芳，故園遥寄水雲鄉。',64,'全唐诗/poet.song.104000.json','["柳逕桃溪碧草芳，故園遥寄水雲鄉。", "老來轉使宦情薄，春思頗增詩興長。", "教子文書容自勉，逢人尊酒爲誰忙。", "海棠卻似憐衰朽，依倚東風試晚粧。"]'),
('9cab21fd-57b4-4590-9a5e-1c89b3f53ab9','追和東坡送春和陳德夫','王之道','宋','宋诗','song-poetry','','[]','柳外風檣迅莫追，柳間遲日弄晴暉。',64,'全唐诗/poet.song.104000.json','["柳外風檣迅莫追，柳間遲日弄晴暉。", "青春已作堂堂去，烏轡何由緩緩飛。", "入户呢喃輕語燕，隔林咿軋静鳴機。", "誰言四月芳菲盡，萱草葵花覺昨非。"]'),
('20cc1eb7-d8ea-462c-b92a-99f5aa6eb12e','鹿鳴宴','王之道','宋','宋诗','song-poetry','','[]','蒼顔華髪老書生，來赴公堂宴食苹。',64,'全唐诗/poet.song.104000.json','["蒼顔華髪老書生，來赴公堂宴食苹。", "曾預宣和聞喜集，重觀乾道計偕行。", "繡衣勸駕追前哲，熊軾賓賢繼列城。", "久矣邦人虚桂籍，正須公等振英聲。"]'),
('8ff9fd3e-3feb-4f14-bb84-5a2fcbbcb2cc','秋日書懷  其一','王之道','宋','宋诗','song-poetry','','[]','斷虹收盡晚風凉，撲鼻誰家社酒香。',64,'全唐诗/poet.song.104000.json','["斷虹收盡晚風凉，撲鼻誰家社酒香。", "門外山横青玉案，屋頭榴綻紫羅嚢。", "對吟已覺輸新俊，遇酒還能發老狂。", "坐想西園梨棗熟，昔年猶記拉君嘗。"]'),
('ca3cb30a-1847-40f0-a72e-a24357e05a53','秋日書懷  其二','王之道','宋','宋诗','song-poetry','','[]','一别成均十九秋，斷腸千里致書郵。',64,'全唐诗/poet.song.104000.json','["一别成均十九秋，斷腸千里致書郵。", "可憐率土民心固，端爲當年聖澤流。", "此去會看還北狩，夜來先夢到東州。", "尊君正是吾儕事，可但南冠學楚囚。"]'),
('7c06cce8-6292-431a-801e-3702457e5952','秋日書懷  其三','王之道','宋','宋诗','song-poetry','','[]','到齊何日醉青州，久矣平原困督郵。',64,'全唐诗/poet.song.104000.json','["到齊何日醉青州，久矣平原困督郵。", "避地未容行信步，汎江聊得卧安流。", "望窮落鶩千山晚，夢斷驚颷萬壑秋。", "安得尚方三尺劍，掃除驕寇獻俘囚。"]'),
('b8eb58af-90e2-4c8a-a364-654d2c99b283','對雪和馬大卿','王之道','宋','宋诗','song-poetry','','[]','投分江梅亦太清，尋盟風絮卻多情。',64,'全唐诗/poet.song.104000.json','["投分江梅亦太清，尋盟風絮卻多情。", "勢先澤腹歸冰鑑，氣迫毫尖入管城。", "吏部夢踰秦嶺去，將軍來作蔡州行。", "擁爐令我思前躅，策蹇高吟愧孟生。"]'),
('d44a7cb2-c39a-43ac-af63-f7929147150c','對雪和因老韵','王之道','宋','宋诗','song-poetry','','[]','諫陛何人正伏蒲，將壇無事且投壺。',64,'全唐诗/poet.song.104000.json','["諫陛何人正伏蒲，將壇無事且投壺。", "因觀雪曲詞争勝，便覺詩鄰勢不孤。", "警雁王師方入蔡，贈梅邉使欲離吳。", "可憐鼠輩殊輕敵，乃敢堂堂捋虎鬚。"]'),
('ea0fc2ab-c351-463d-a648-e26dc519e970','和張彦智對雪','王之道','宋','宋诗','song-poetry','','[]','雪山何處覓瞿曇，壓盡江南瘴與嵐。',64,'全唐诗/poet.song.104000.json','["雪山何處覓瞿曇，壓盡江南瘴與嵐。", "待伴可堪風作黨，交光應喜月成三。", "濯巾漉酒供杯勺，涉筆聯詩尚笑談。", "柳絮自今輕謝句，使君才氣擅東南。"]'),
('f538667d-12f4-474c-9776-aea965313635','苦寒','王之道','宋','宋诗','song-poetry','','[]','風屑瓊寒透薄帷，擁裘端與火相宜。',64,'全唐诗/poet.song.104000.json','["風屑瓊寒透薄帷，擁裘端與火相宜。", "煖迴熾焰身成直，撥到殘灰手欲龜。", "贈炭尚誰憐正曜，授薪還自愧支離。", "不甘力請從緇侣，苦調寒窗强作詩。"]'),
('5429948a-3fe2-441f-9698-9cbe2d6abcc4','題合肥驛','王之道','宋','宋诗','song-poetry','','[]','重來歲月恍如飛，但怪蕪城壁四圍。',64,'全唐诗/poet.song.104000.json','["重來歲月恍如飛，但怪蕪城壁四圍。", "千里漫推新政善，幾人能遂故園歸。", "雲蒸殘暑催登穀，風作新凉戒授衣。", "小驛滯留朋舊絕，何妨白晝掩朱扉。"]'),
('5af5b56b-8310-4523-b83c-cdbf719fe6e4','題元發弟竹軒','王之道','宋','宋诗','song-poetry','','[]','竹林深處敞軒楹，分我西園一半清。',64,'全唐诗/poet.song.104000.json','["竹林深處敞軒楹，分我西園一半清。", "蒼玉幾番披夏籜，老龍長此戰秋聲。", "寒侵虚幌詩增爽，綠浸疏醽醉不醒。", "應許七賢追盛集，煩君書入鄙夫名。"]'),
('1caafa43-0bc2-47fe-90f5-8e130beb7764','題時軒','王之道','宋','宋诗','song-poetry','','[]','圖書堆裏席凝塵，聊與時軒作主人。',64,'全唐诗/poet.song.104000.json','["圖書堆裏席凝塵，聊與時軒作主人。", "自恐謝安行不免，誰言陶侃困無津。", "東榮曉色高迎日，南圃花光得占春。", "想見戴侯風味勝，輕弹珠玉到江濱。"]'),
('90ff028f-e207-4548-806c-4250af42c1ab','題許公塞驛','王之道','宋','宋诗','song-poetry','','[]','遐想清游意欲飛，巢湖西畔碧山圍。',64,'全唐诗/poet.song.104000.json','["遐想清游意欲飛，巢湖西畔碧山圍。", "高城别後騷人到，小驛春迴燕子歸。", "壁上新詩留醉墨，庭前飛絮點征衣。", "窮愁勿用頻惆悵，來歲而今在北扉。"]'),
('6dcc71d2-0d11-4264-aed5-db87cb91aebd','題無爲秀溪亭','王之道','宋','宋诗','song-poetry','','[]','畫橋雕檻接招提，新有幽人榜秀溪。',64,'全唐诗/poet.song.104000.json','["畫橋雕檻接招提，新有幽人榜秀溪。", "十頃净明天上下，兩奩光映水東西。", "飛樓湧殿參差見，古木修篁咫尺迷。", "此景此時君信否，綠楊陰裏囀黄鸝。"]'),
('b7b9427b-8e45-447c-8737-bc19ec36cbe8','憫旱','王之道','宋','宋诗','song-poetry','','[]','食貧那識小槽紅，回也簞瓢久屢空。',64,'全唐诗/poet.song.104000.json','["食貧那識小槽紅，回也簞瓢久屢空。", "翹候載芟歌濟濟，忍看雲漢嘆爞爞。", "困窮轉覺蓬心隘，憔悴猶憐菜頰豐。", "坐對驕陽思霈澤，日占鳴鸛望穹窿。"]'),
('950d2a9d-74f6-4112-a837-3155852c254e','爲興國周少隠題','王之道','宋','宋诗','song-poetry','','[]','紫翠森攅面面山，箇中佳致爲君還。',64,'全唐诗/poet.song.104000.json','["紫翠森攅面面山，箇中佳致爲君還。", "憑闌人在風塵表，落紙詩成咳唾間。", "良夜幸陪紅袖醉，清時聊伴白鷗閒。", "籠紗歸去高城晚，凝翠堂東月滿灣。"]'),
('141d7b0c-f421-4b5e-b8d3-4461fb8f683b','爲彭積甫題熈春堂','王之道','宋','宋诗','song-poetry','','[]','似聞伐石旋誅茅，已見高堂蔭樂郊。',64,'全唐诗/poet.song.104000.json','["似聞伐石旋誅茅，已見高堂蔭樂郊。", "百里湖山供眼界，滿城桃李動春梢。", "寒梅過盡看成實，乳燕飛來欲定巢。", "何日登臨閒信馬，路邉人復少年嘲。"]'),
('865f68f6-b30e-42a6-88a3-6b3135c622b7','田間夜歸有作示王覺民二首  其一','王之道','宋','宋诗','song-poetry','','[]','風雲蹤跡付扁舟，水竹生涯寄一丘。',64,'全唐诗/poet.song.104000.json','["風雲蹤跡付扁舟，水竹生涯寄一丘。", "世故舉同鷄抱鴨，物情無怪馬生牛。", "百年半向愁中老，萬事常從酒到休。", "莫愛得官輕得句，争如飽食對吟捜。"]'),
('e863ef75-e00e-4e32-be7d-25e0ffffae13','田間夜歸有作示王覺民二首  其二','王之道','宋','宋诗','song-poetry','','[]','江上秋來憶少牢，龜腸尤覺病詩饕。',64,'全唐诗/poet.song.104000.json','["江上秋來憶少牢，龜腸尤覺病詩饕。", "調和索似三分醬，澒洞看如八斗糟。", "水怪重增風勢惡，湘靈難禁雁聲高。", "何當一雨洗煙月，爲放清光歸我曹。"]'),
('13f3e330-e70e-4c28-b050-6f3da6b2395f','寄題峽州楚塞樓','王之道','宋','宋诗','song-poetry','','[]','江向西陵勢漸平，萬山環合翠峥嶸。',64,'全唐诗/poet.song.104000.json','["江向西陵勢漸平，萬山環合翠峥嶸。", "須知楚國嘗爲塞，不爲涪翁浪得名。", "人若此賢真俊傑，樓還舊觀煥神明。", "臨風毎聽灘聲咽，似怨張儀作暮横。"]'),
('71aaed81-6da9-40fa-a4b7-0bb367324149','和陶尉喜雨呈張文伯','王之道','宋','宋诗','song-poetry','','[]','賀客休辭酒盞深，使君心是老農心。',64,'全唐诗/poet.song.104000.json','["賀客休辭酒盞深，使君心是老農心。", "精誠已致當時雨，膏澤將爲異歲霖。", "得水槁苖俱競秀，乘秋高鳥自能吟。", "宣風宜有中和作，戞玉鏘金播八音。"]'),
('956ccdba-4e79-4687-8725-adf77d65aac0','和王冲之喜雨呈張文伯','王之道','宋','宋诗','song-poetry','','[]','指點邦人著眼看，魯侯雩祭正玄端。',64,'全唐诗/poet.song.104000.json','["指點邦人著眼看，魯侯雩祭正玄端。", "望來已見千山雨，此去那憂百穀乾。", "高廪有期從穧斂，奔霆何處起龍蟠。", "新詩得得書靈應，傳與群公好縱觀。"]'),
('08ce95c0-42b2-490d-9c32-8f800682aec4','和應資深九日游康樂園二首  其一','王之道','宋','宋诗','song-poetry','','[]','村落瀟瀟晚吹生，斜陽天際與林平。',64,'全唐诗/poet.song.104000.json','["村落瀟瀟晚吹生，斜陽天際與林平。", "黄花照眼吟肩聳，紅袖扶頭醉帽輕。", "可慣探題仍擊鉢，敢辭償令獨浮觥。", "相逢又復驚相别，樽酒何妨意氣傾。"]'),
('df1136ff-e719-4f0b-a918-ec7d5bbdcdf6','和應資深九日游康樂園二首  其二','王之道','宋','宋诗','song-poetry','','[]','里社安閒得久生，金華端不羡初平。',64,'全唐诗/poet.song.104000.json','["里社安閒得久生，金華端不羡初平。", "山林應有清修重，軒冕還将道義輕。", "詩捷口占那復藁，酒豪盆酌不論觥。", "一斑已幸窺秋句，囷廪他時冀倒傾。"]'),
('eb76f99a-f32e-42b2-b95e-f494509f6b2b','春日郊行和郭希魯二首  其一','王之道','宋','宋诗','song-poetry','','[]','縈風楊柳綠絲長，過雨桑麻沃以光。',64,'全唐诗/poet.song.104000.json','["縈風楊柳綠絲長，過雨桑麻沃以光。", "聯騎不妨多載酒，看花無用更燒香。", "望窮巖電捜詩眼，愁轉車輪感别腸。", "勝集清游定何處，它年曲水記流觴。"]'),
('94cc299f-32c3-48d6-81ba-8e85bb3d36aa','春日郊行和郭希魯二首  其二','王之道','宋','宋诗','song-poetry','','[]','坐對煙江疊嶂圖，何如門外翠屏紆。',64,'全唐诗/poet.song.104000.json','["坐對煙江疊嶂圖，何如門外翠屏紆。", "尋芳敢擅攜笻去，命友應從折簡呼。", "酒裏光陰閒活計，詩餘情思静功夫。", "浪吟痛飲真難遇，休問西山日欲晡。"]'),
('54248b2c-1fd7-4bda-9732-426dc427fed1','和吳子美香林湯韵','王之道','宋','宋诗','song-poetry','','[]','泉沸鷄籠山下林，潯陽曾記尺餘深。',64,'全唐诗/poet.song.104000.json','["泉沸鷄籠山下林，潯陽曾記尺餘深。", "濯鮮瀹卵非予事，清暑攘寒盖我心。", "物態漫勞私曖曖，靈源當信匪今今。", "簿書汨沒塵埃久，附驥何時遂滌襟。"]'),
('74193364-fb37-45a6-9917-7495b6d3ff75','上已日阻雨和王冲之韵','王之道','宋','宋诗','song-poetry','','[]','袚除聊復對江亭，樽酒相從一笑傾。',64,'全唐诗/poet.song.104000.json','["袚除聊復對江亭，樽酒相從一笑傾。", "那得此時仍此樂，况逢難弟與難兄。", "潺潺暮雨簷間溜，滑滑春泥柳外聲。", "好在海棠紅閤淚，向人悽愴益多情。"]'),
('c32d8ad2-94ed-4ade-9fa1-67708b63ac60','和竇又勇秋日見訪阻雨見贈','王之道','宋','宋诗','song-poetry','','[]','風雨蕭蕭暮不休，頓添寒色送窮秋。',64,'全唐诗/poet.song.104000.json','["風雨蕭蕭暮不休，頓添寒色送窮秋。", "已荒深院菊猶在，欲去短亭人强留。", "千里書遲空噪鵲，四鄰砧亂混鳴鳩。", "相逢棊戰宜終日，卧稻從他爛不收。"]'),
('0c728c07-1a1e-42f0-b8b7-ae025154ff10','和石守道喜雨','王之道','宋','宋诗','song-poetry','','[]','坐聽簷雨快高吟，酒到從斟不厭深。',64,'全唐诗/poet.song.104000.json','["坐聽簷雨快高吟，酒到從斟不厭深。", "酣戰遂符占蟻信，鬰興良慰望霓心。", "一時與被堯天澤，四海同蘇傅野霖。", "霑足豈惟秋有歲，麥田猶及趁犁金。"]'),
('0019912c-fd9d-4304-a634-ad1d8fd06d11','伏蒙知縣縣尉二寮友以夏旱得雨賡石徂徠喜雨韵見貺不可虚辱復嗣其韵書謝仍命兒曹同賦','王之道','宋','宋诗','song-poetry','','[]','綠槐陰外聽蟬吟，節過分龍夏已深。',64,'全唐诗/poet.song.104000.json','["綠槐陰外聽蟬吟，節過分龍夏已深。", "千里亢陽憂歲旱，一時甘雨快人心。", "養禾不害連朝曀，沃暑應容數日霖。", "多謝同寮憐老拙，雙南佳句競鏗金。"]'),
('5efbcbae-2b59-43dd-ab03-0a81a2dd19dd','追和東坡張昌言喜雨呈同官','王之道','宋','宋诗','song-poetry','','[]','旱魃正須三尺雨，飛廉旋布四天雲。',64,'全唐诗/poet.song.104000.json','["旱魃正須三尺雨，飛廉旋布四天雲。", "詩成采筆揮瓊玖，酒到酡顔散纈紋。", "蓮沼灔翻宵溜急，槐庭清送午風薫。", "欣欣千里農夫慶，衰病空慚老使君。"]'),
('b2195113-7070-4304-ac88-ea2561f5dd1a','和董令升舍人','王之道','宋','宋诗','song-poetry','','[]','雨餘沙路潤無泥，瀲灔溪流與岸齊。',64,'全唐诗/poet.song.104000.json','["雨餘沙路潤無泥，瀲灔溪流與岸齊。", "苒苒年華催我老，酣酣春意得人迷。", "聯珠便覺新詩富，浮玉還聽雅唱低。", "楊柳緩揺陰正午，誰家籬落一聲鷄。"]'),
('de53b851-916d-4ce9-bc2e-e5b8e7880db9','和董令升舍人夢中得句','王之道','宋','宋诗','song-poetry','','[]','早晚天書下紫泥，如今人物擅三齊。',64,'全唐诗/poet.song.104000.json','["早晚天書下紫泥，如今人物擅三齊。", "才華好自鑾坡進，詩思休從蝶夢迷。", "深院日遲黄鳥囀，長橋風軟綠楊低。", "春容不用相撩撥，老去心情似木鷄。"]'),
('eda721c7-5138-4ab6-9cae-96ea28e06131','和張安國舍人','王之道','宋','宋诗','song-poetry','','[]','判花西掖妙當年，曾見聲華振日邉。',64,'全唐诗/poet.song.104000.json','["判花西掖妙當年，曾見聲華振日邉。", "文翰共推唐李嶠，功名將踵漢韋賢。", "江山到處供詩笥，風月多情付酒船。", "琳館正應聊爾耳，會看鵬擊水三千。"]'),
('d35a8e75-b98b-49ce-bf3d-3c1c12de9dc8','和張文紀詠雪二首  其一','王之道','宋','宋诗','song-poetry','','[]','萬境沉沉夜氣嚴，廣寒初下水晶簾。',64,'全唐诗/poet.song.104000.json','["萬境沉沉夜氣嚴，廣寒初下水晶簾。", "三杯强沃澆腸酒，一捻聊分暖硯鹽。", "已恨梅梢遭挫折，可堪風物爲般添。", "才高柳絮雖難到，此語於今亦惡拈。"]'),
('c174af8e-051f-4733-966d-ff9cb63f618d','和張文紀詠雪二首  其二','王之道','宋','宋诗','song-poetry','','[]','朝來經閣課楞嚴，撩亂飛花競擈簾。',64,'全唐诗/poet.song.104000.json','["朝來經閣課楞嚴，撩亂飛花競擈簾。", "似是青腰誇黑帝，故教姑射混無鹽。", "地爐無奈貂裘薄，斗酒難供座客添。", "詩債惱人眠不得，夜寒殘管亦須拈。"]'),
('8c9be00f-0814-476c-ad24-0b6f3a6c7b63','再和董令升雪二首  其一','王之道','宋','宋诗','song-poetry','','[]','春雪初融作燕泥，梅花零落杏花齊。',64,'全唐诗/poet.song.104000.json','["春雪初融作燕泥，梅花零落杏花齊。", "遥山掃翠雲初斂，芳草鋪青路欲迷。", "别恨毎憂兒輩覺，老懷終爲世情低。", "新詩價重連城壁，敢比靈犀獨駭鷄。"]'),
('c50aad7a-0c1b-44e3-9841-7a7f5f27fb16','再和董令升雪二首  其二','王之道','宋','宋诗','song-poetry','','[]','欲下閒庭不蹋泥，但驚飛絮與堦齊。',64,'全唐诗/poet.song.104000.json','["欲下閒庭不蹋泥，但驚飛絮與堦齊。", "一枝誤失禽棲穏，三窟遥應兔迹迷。", "填塞澗溪還地厚，壅培山阜覺天低。", "寒光照應東窗白，咿喔應先報曉雞。"]'),
('b99fa4b8-7dfe-4a67-9a4b-6b119709e11c','追和東坡嚴車二雪詩  其一','王之道','宋','宋诗','song-poetry','','[]','公詩有意拂廉纖，令似歐陽韵更嚴。',64,'全唐诗/poet.song.104000.json','["公詩有意拂廉纖，令似歐陽韵更嚴。", "犬子亦應慚賦縞，癡兒端合愧誇鹽。", "飛綿勃窣争平塹，凍笋槎牙欲墮簷。", "胡避只今何處是，玉屏森映一峰尖。"]'),
('b1f4001b-3c33-42d5-86e0-11e1596faa8c','追和東坡嚴車二雪詩  其二','王之道','宋','宋诗','song-poetry','','[]','雪滿江城酒不賖，閉門那患出無車。',64,'全唐诗/poet.song.104000.json','["雪滿江城酒不賖，閉門那患出無車。", "未容踏凍尋梅萼，應喜臨風見柳花。", "炭重烏銀争曉市，蔬挑翠羽荷鄰家。", "何人正下紅蓮幙，大嚼蒸羊手更义。"]'),
('1be5e6bf-3c45-41e4-aa6a-52922d30569a','和周少隠實錄院對竹三首  其一','王之道','宋','宋诗','song-poetry','','[]','夫子文章僕命騷，高標寧若歲寒凋。',64,'全唐诗/poet.song.104000.json','["夫子文章僕命騷，高標寧若歲寒凋。", "慣看雄辯朝揮麈，想見清吟夜度韶。", "老去荷君頻折簡，時來容我尚同寮。", "區區長倩何爲者，不樂平原意本朝。"]'),
('4a166674-c04e-422f-850d-43c3d132ca8c','和周少隠實錄院對竹三首  其二','王之道','宋','宋诗','song-poetry','','[]','老來鬚鬢白刁騷，猶喜丹心未遽凋。',64,'全唐诗/poet.song.104000.json','["老來鬚鬢白刁騷，猶喜丹心未遽凋。", "秋賦肯甘同宋玉，晝眠聊復繼邉韶。", "翩翩幽鳥隨風屐，炯炯寒燈伴夜寮。", "多謝故人珠玉寄，水雲堆裏望天朝。"]'),
('aae5ae32-8064-44c9-9e4d-cb82fb17682a','和周少隠實錄院對竹三首  其三','王之道','宋','宋诗','song-poetry','','[]','窗寒疏竹共蕭騷，可笑圓荷着露凋。',64,'全唐诗/poet.song.104000.json','["窗寒疏竹共蕭騷，可笑圓荷着露凋。", "實錄成書輝日月，奉常新樂奏咸韶。", "佳篇千里來青瑣，好夢連宵到綺寮。", "湖海固應聊爾耳，佇看丹詔下公朝。"]'),
('d813706b-f8a6-4d5c-92ca-4d4559213f82','和韵寄董令升舍人','王之道','宋','宋诗','song-poetry','','[]','曾將燕石報瓊華，别後哦詩愧莫涯。',64,'全唐诗/poet.song.104000.json','["曾將燕石報瓊華，别後哦詩愧莫涯。", "空腹但看長柄械，緩行何用短轅車。", "神馳鄧步彌天葑，夢入朋谿夾徑花。", "何日天台尋藥去，女仙迎笑飯胡麻。"]'),
('a6148dac-bf38-443d-b69c-9d3eab520f55','和余元明時元明邀余同李次元夜飲','王之道','宋','宋诗','song-poetry','','[]','坐中强半是同年，頼有斯人席更圓。',64,'全唐诗/poet.song.104000.json','["坐中强半是同年，頼有斯人席更圓。", "跨馬未須貪遠道，舉觴聊復望青天。", "枯荷折葦三墪路，明月清風百丈船。", "俯仰便成陳迹恨，須知此集不論錢。"]'),
('dad37d92-3a7c-450e-b471-3d82adb3a25e','避寇糝潭登李彦修延秀閣','王之道','宋','宋诗','song-poetry','','[]','王師千里下邦畿，三月宜新對敵圍。',64,'全唐诗/poet.song.104000.json','["王師千里下邦畿，三月宜新對敵圍。", "江上扁舟隨處是，煙中華屋轉頭非。", "逢人借問何時定，有客來傳二聖歸。", "已辦笭箵學元結，卜鄰猶冀不相違。"]'),
('e0bb5956-22bc-4ad4-81d4-f537c1d1d015','和因上人午睡韵','王之道','宋','宋诗','song-poetry','','[]','多謝高人問起居，惠然相過共秋蔬。',64,'全唐诗/poet.song.104000.json','["多謝高人問起居，惠然相過共秋蔬。", "栖栖衆且疑夫子，碌碌誰知效阿奴。", "老去睡鄉還積欠，君來詩社責新逋。", "便便一覺南窗午，短簟方牀意不疏。"]'),
('586e0124-dfce-4e29-9a32-226b6cad41fe','歷陽寄定城尉彦逢弟','王之道','宋','宋诗','song-poetry','','[]','故園鵯鵊久催耕，休戀公田秫與秔。',64,'全唐诗/poet.song.104000.json','["故園鵯鵊久催耕，休戀公田秫與秔。", "别恨久隨黄耳去，歸心應望白雲生。", "干戈叢裏三書考，春夏交來幾閉城。", "我亦藍田負丞者，相從何日賦淵明。"]'),
('bd0aef65-73bf-4351-a530-692fc50c4109','和蕭山臨川亭壁間留題韵','王之道','宋','宋诗','song-poetry','','[]','水外峰巒碧四環，雨多門徑蘚苔斑。',64,'全唐诗/poet.song.104000.json','["水外峰巒碧四環，雨多門徑蘚苔斑。", "滯留又及炊新粟，歡喜何當見舊山。", "招隠有詩來霅上，倦游無夢到雲間。", "西興十里秋潮晚，坐數扁舟带月還。"]'),
('4c0fb3f1-bb40-4d96-b90f-ac6a3b0db74b','和彦逢弟春日即事','王之道','宋','宋诗','song-poetry','','[]','楊花如雪菜花黄，路出初郊正日長。',64,'全唐诗/poet.song.104000.json','["楊花如雪菜花黄，路出初郊正日長。", "喜對新詩醒病眼，會逢膏雨沃驕陽。", "過僧竹院茶爭美，酌客山堂酒倍香。", "常恨抗塵仍走俗，不知身在水雲鄉。"]'),
('dd14399e-d24c-40dd-a4ba-6ec4b7da2331','和陳勉仲春日偶成二首  其一','王之道','宋','宋诗','song-poetry','','[]','帷幄何人正坐籌，匈奴輕漢索懷柔。',64,'全唐诗/poet.song.104000.json','["帷幄何人正坐籌，匈奴輕漢索懷柔。", "回鑾未睹迎天駟，勸穡還驚出土牛。", "雨過池塘新漲綠，春歸原野霽煙浮。", "中興自古須群策，更願君王慎厥猷。"]'),
('3a59a78a-dd70-4b45-ba5e-69cd46c9e49d','和陳勉仲春日偶成二首  其二','王之道','宋','宋诗','song-poetry','','[]','江表歸來得自由，舊鄉能復到温柔。',64,'全唐诗/poet.song.104000.json','["江表歸來得自由，舊鄉能復到温柔。", "辭源已見流三峽，筆力當期挽萬牛。", "白日忍從黄霧塞，青天那復黑雲浮。", "掃除驕寇還强漢，會有忠良告遠猷。"]'),
('aefc4ad2-babb-4afb-b7e8-c4af9c78abec','春日偶成','王之道','宋','宋诗','song-poetry','','[]','餘生今赴邇英朝，似說夔龍許續貂。',64,'全唐诗/poet.song.104000.json','["餘生今赴邇英朝，似說夔龍許續貂。", "枯枿遂承新雨露，蒼鷹應識舊雲霄。", "廢興須信闗時命，勞逸誰能問貫條。", "十載山林勞夢寐，五更天仗聽簫韶。"]'),
('6bf36543-cc28-4649-b3fa-a3f5130e5149','春日次韵張叔元','王之道','宋','宋诗','song-poetry','','[]','遲日輕風過雨天，草青南陌欲生烟。',64,'全唐诗/poet.song.104000.json','["遲日輕風過雨天，草青南陌欲生烟。", "江湖節物登王鮪，村落歸心起杜鵑。", "已辦尋芳游野寺，何當修褉泛溪船。", "路逢少婦携籠去，爲說蠶兒向雨眠。"]'),
('25dcaa9e-2260-423a-9fac-b09956d32176','和秦壽之中秋玩月三首  其一','王之道','宋','宋诗','song-poetry','','[]','一樽芳酒起沉烟，絕勝紅裙擁後前。',64,'全唐诗/poet.song.104000.json','["一樽芳酒起沉烟，絕勝紅裙擁後前。", "山色水光相上下，月華秋氣共清圓。", "佳時令我思韓愈，好夢逢君想惠連。", "老大不知追逐樂，卻因妍唱惜流年。"]'),
('5981fbb5-de14-4f84-8149-40001ccf5c4e','和秦壽之中秋玩月三首  其二','王之道','宋','宋诗','song-poetry','','[]','湖光無際接雲烟，舉酒登臨夕照前。',64,'全唐诗/poet.song.104000.json','["湖光無際接雲烟，舉酒登臨夕照前。", "坐送落霞還杳靄，倚看明月上高圎。", "清談浩渺河源注，麗句縱横繡段連。", "歸去鳳池知不日，山城岑寂記今年。"]'),
('c142f2c0-3cb3-459f-88e2-d8c39b8e44cd','和秦壽之中秋玩月三首  其三','王之道','宋','宋诗','song-poetry','','[]','腸斷江城斂暮烟，一聲清笛短亭前。',64,'全唐诗/poet.song.104000.json','["腸斷江城斂暮烟，一聲清笛短亭前。", "揚舲共喜風初轉，戯綵當期月正圓。", "水落雙溪和石出，霜餘疊嶂與雲連。", "令人暗想昭亭路，屈指歸來又四年。"]'),
('45d86a37-ef60-44e6-95f3-98b31ec211a2','和張彦智中秋對月','王之道','宋','宋诗','song-poetry','','[]','萬里青天霽色開，嫦娥駕玉上雲來。',64,'全唐诗/poet.song.104000.json','["萬里青天霽色開，嫦娥駕玉上雲來。", "樓中勝飲八仙聚，物外清談三語該。", "空翠水光争滉漾，漏聲鐘韵共徘徊。", "秋盤應愛金櫻好，紅抺佳人醉裏腮。"]'),
('16eecb48-d76b-4475-8272-cac31f9a0460','和高守無隠官閑即事  其一','王之道','宋','宋诗','song-poetry','','[]','老去空悲樂事稀，百年渾醉幾多巵。',64,'全唐诗/poet.song.104000.json','["老去空悲樂事稀，百年渾醉幾多巵。", "雖貧頼有舊栽竹，縱嬾未容全廢詩。", "碧草望迷烟漠漠，黄梅看熟雨垂垂。", "莫嫌蕪纇晚相凂，欲換邦君白雪詞。"]'),
('124475c9-c675-45e7-a0f1-7ddfd74078eb','和高守無隠官閑即事  其二','王之道','宋','宋诗','song-poetry','','[]','誰憐村落笑歌稀，全把茶甌當酒巵。',64,'全唐诗/poet.song.104000.json','["誰憐村落笑歌稀，全把茶甌當酒巵。", "枯槁又經三月雨，窮愁聊付一篇詩。", "窗間遠岫青千疊，樓外長天碧四垂。", "何日獲陪文字飲，欲翻妍唱入新詞。"]'),
('730d9c2f-e92d-4289-b185-4f07bcd9614c','和胡德輝增明軒','王之道','宋','宋诗','song-poetry','','[]','釣魚聊復效詹何，肯向青山較少多。',64,'全唐诗/poet.song.104000.json','["釣魚聊復效詹何，肯向青山較少多。", "身世自憐巢幕燕，利名誰鑒撲燈蛾。", "風前逸氣舒長笛，酒裏清愁到短歌。", "安得梧桐來鸑鷟，一鳴千古繼卷阿。"]'),
('aa0720c1-b5ff-40cd-ba92-97111651d191','寄奉符大有叔','王之道','宋','宋诗','song-poetry','','[]','血氣侵凌不復豪，往來欹倒似乘濤。',64,'全唐诗/poet.song.104000.json','["血氣侵凌不復豪，往來欹倒似乘濤。", "寧知嬾過嵇中散，亦有詩如謝法曹。", "舊藁只堪供醬瓿，故人相贈有綈袍。", "兗州賓主同風味，惡句煩公更一薅。"]'),
('9d5c1214-4609-43a6-a43c-404bfa498037','和曾式古','王之道','宋','宋诗','song-poetry','','[]','白雲飛處見層巔，回首風檣去若仙。',64,'全唐诗/poet.song.104000.json','["白雲飛處見層巔，回首風檣去若仙。", "舊隠已鋤三徑菊，新吟聊愬一嚢錢。", "春歸沂水還相樂，秋到盱江盛有年。", "更着綵衣歌且舞，高堂侍瀝奉周旋。"]'),
('93923509-220e-4d27-b075-ca138a472a91','和何希淵韵','王之道','宋','宋诗','song-poetry','','[]','敢負交游素所期，自憐衰滯使君疑。',64,'全唐诗/poet.song.104000.json','["敢負交游素所期，自憐衰滯使君疑。", "向来兵火亦何久，此去功名應未遲。", "詩似清風宜我慰，心如白水欲誰欺。", "扁舟儻赴相從約，江北江南笑有辭。"]'),
('9b7b35f0-fa87-470b-9b0a-8c5971ea7a97','和孔純老歸自屬邑三首  其一','王之道','宋','宋诗','song-poetry','','[]','行縣歸来賦陟岡，青梅應快一樽嘗。',64,'全唐诗/poet.song.104000.json','["行縣歸来賦陟岡，青梅應快一樽嘗。", "詩成妙墨揮張聖，酒到高歌發楚狂。", "夾道野花圍步障，兩行官妓簇橋梁。", "嗟予貧悴跧蓬蓽，不及郊迎笑舉觴。"]'),
('6020348d-b846-4f7e-9631-5c2f42fe17e0','和孔純老歸自屬邑三首  其二','王之道','宋','宋诗','song-poetry','','[]','往来陰雨恰彌旬，滑滑那堪鳥語頻。',64,'全唐诗/poet.song.104000.json','["往来陰雨恰彌旬，滑滑那堪鳥語頻。", "行色可無三日霽，旅懷應付萬家春。", "欣聞郊勞開瑶席，想見車旋入錦茵。", "何幸詩筒時寄我，慰懷須信有詩人。"]'),
('786c9d8f-9c64-4e7c-b232-6eaf33b00db9','和孔純老歸自屬邑三首  其三','王之道','宋','宋诗','song-poetry','','[]','詩濤難放筆頭乾，歸及初晴素魄圓。',64,'全唐诗/poet.song.104000.json','["詩濤難放筆頭乾，歸及初晴素魄圓。", "善譽敢論當世比，佳萹應任老夫傳。", "凌雲列岫堆螺髻，出水新荷點翠鈿。", "報政還朝知不晚，追隨能復記當年。"]'),
('e16ec792-2299-4e39-9cc6-aaa1cd2312ab','和梁宏父二首  其一','王之道','宋','宋诗','song-poetry','','[]','時來談笑取侯封，清曠寧容雅志從。',64,'全唐诗/poet.song.104000.json','["時來談笑取侯封，清曠寧容雅志從。", "上聖急賢齊舜禹，群公引類邁夔龍。", "非材似我十圍櫟，有用如君千丈松。", "邂逅相逢辱傾盖，能令瓦釜配黄鐘。"]'),
('4275ebd3-be3a-4536-8f32-f4a6c7445677','和梁宏父二首  其二','王之道','宋','宋诗','song-poetry','','[]','功名須向壯年收，顧我摧頽已白頭。',64,'全唐诗/poet.song.104000.json','["功名須向壯年收，顧我摧頽已白頭。", "節晚獨存松柏勁，歲寒還見雪霜浮。", "老將耄及從人笑，醉欲眠時遣客休。", "眼力尚能觀細字，詩筒經卷且優游。"]'),
('94f03ac8-570e-4b02-9b6f-e4417d02dbbf','走筆和孔純老催詩債次韵','王之道','宋','宋诗','song-poetry','','[]','閉門對客總言詩，淹速由人敢預期。',64,'全唐诗/poet.song.104000.json','["閉門對客總言詩，淹速由人敢預期。", "思若湧泉誇往哲，文如翻水擅當時。", "年成定見爭稱善，月鍊懸知鬬出奇。", "疾似枚皋何足道，漢朝終貴長卿遲。"]'),
('b768d067-fd43-4bf5-9f5b-4988f83489aa','避寇姥山','王之道','宋','宋诗','song-poetry','','[]','山前湖水抱烟村，湖外山光隠若存。',64,'全唐诗/poet.song.104000.json','["山前湖水抱烟村，湖外山光隠若存。", "泛宅浮家聊自託，蔭松藉草欲誰論。", "物情魚沬真堪笑，世事槐安不在言。", "囘首故園煨燼裏，歸歟猶勝傍人門。"]'),
('71f12fdd-5ba8-46c9-9171-32e7a62ea21d','和鄒進士','王之道','宋','宋诗','song-poetry','','[]','望外青山便到家，馮讙何患出無車。',64,'全唐诗/poet.song.104000.json','["望外青山便到家，馮讙何患出無車。", "坐逢石鼎應聯句，箧有龍潭敢鬬茶。", "樽酒幾時同竹葉，功名終日鑒菱花。", "君看一雨蘇群槁，所至人心樂否耶。"]'),
('72a77f61-d08d-4f2b-9699-e4ef7e9c5edd','和丁景仁三叉河留題贈李仲山','王之道','宋','宋诗','song-poetry','','[]','飄零雙鬢已星星，萬里江湖寄此身。',64,'全唐诗/poet.song.104000.json','["飄零雙鬢已星星，萬里江湖寄此身。", "山擁青螺初洗雨，水浮蒼壁似圍春。", "别來興廢同千古，此去榮枯會一新。", "葭薍彌天草如積，寛予猶頼有斯人。"]'),
('64cf5745-6039-4be0-b0a8-f3d248af7b9e','弟子厚自相山徙居湖塘又復一月矣距外除只數日間光景漂流徒成感慨讀新詩興不能已輒和韵','王之道','宋','宋诗','song-poetry','','[]','相逢休訪楚江萍，我老無能一壯丁。',64,'全唐诗/poet.song.104000.json','["相逢休訪楚江萍，我老無能一壯丁。", "卜宅又驚三浹日，御琴空感再周星。", "新愁夘酒心先醉，氣怯春寒夢易醒。", "卻喜故山遥在眼，舉頭時見竹青青。"]'),
('d7497b44-a2be-455a-a577-9d6d60465031','和李難老','王之道','宋','宋诗','song-poetry','','[]','半生場屋弄朱衣，猶喜春來破白歸。',64,'全唐诗/poet.song.104000.json','["半生場屋弄朱衣，猶喜春來破白歸。", "同輩交游惟我拙，一時人物似君稀。", "風神要在山庭峻，辭吐初疑鋸屑飛。", "州縣未應淹驥足，釣名誰羡子陵磯。"]'),
('8ec6f1ee-2b90-4343-a02f-0a4e1fc494de','和張公儀','王之道','宋','宋诗','song-poetry','','[]','醉中行草綰秋蛇，十載風櫺憶舊家。',64,'全唐诗/poet.song.104000.json','["醉中行草綰秋蛇，十載風櫺憶舊家。", "朋舊亂多從鬼錄，詩書閒益富生涯。", "稻塍綠合迷秧馬，沙嘴潮回下釣車。", "歸去西疇新雨足，飯秔應不羡胡麻。"]'),
('f4993ed6-eadc-49e9-9edc-2ede7d0a9740','和趙積中','王之道','宋','宋诗','song-poetry','','[]','入室芝蘭氣不殊，逢君還憶見君初。',64,'全唐诗/poet.song.104000.json','["入室芝蘭氣不殊，逢君還憶見君初。", "梅花正喜春懸鳯，藿葉俄同夏鱠魚。", "下榻舊聞看孺子，負荆誰復謝相如。", "艱難正詘平戎策，及早東游叩帝居。"]'),
('b40b7e6e-4828-44bc-a293-41242dd1dac9','和江和仲','王之道','宋','宋诗','song-poetry','','[]','把讀新詩憶舊家，深村羸犢短轅車。',64,'全唐诗/poet.song.104000.json','["把讀新詩憶舊家，深村羸犢短轅車。", "年豐野老常携酒，客至幽禽自喚茶。", "亂後所存惟五柳，老來無意約山花。", "相逢何必曾相識，乘興時來過此耶。"]'),
('9e3ae2aa-1294-453c-8ef3-3fcf6afd3125','和張元禮','王之道','宋','宋诗','song-poetry','','[]','力學三年看有成，龍蛇蟠蟄冀存身。',64,'全唐诗/poet.song.104000.json','["力學三年看有成，龍蛇蟠蟄冀存身。", "一杯餞别初迎臘，千里歸來欲送春。", "愛日光陰宜共惜，及時德業要争新。", "吾家叢桂風流在，速取高科慰老親。"]'),
('617c9220-f1f3-452b-b9dc-ba43da2c73ed','和閭必志見寄韵','王之道','宋','宋诗','song-poetry','','[]','老矣詩才欠壮觀，羡君閒燕富清歡。',64,'全唐诗/poet.song.104000.json','["老矣詩才欠壮觀，羡君閒燕富清歡。", "染羮早厭誇黿指，食肉應宜謝馬肝。", "送客篇章堪寄遠，論文杯勺自驅寒。", "扁舟近過池頭否，百丈西南水欲乾。"]'),
('d3b97e8d-5b9d-424d-bbca-fa70401f514b','和陳勉仲二首  其一','王之道','宋','宋诗','song-poetry','','[]','人似平原字亦顔，詩成長在笑談間。',64,'全唐诗/poet.song.104000.json','["人似平原字亦顔，詩成長在笑談間。", "試看落筆雲烟疾，難放揺春草木閒。", "美俗未容窺製錦，勸耕聊得伴行山。", "慚將鄭腊酬荆璞，無怪年時債未還。"]'),
('e09ca4cb-1cce-494e-9903-60e24d3a2c32','和陳勉仲二首  其二','王之道','宋','宋诗','song-poetry','','[]','相逢憐我太衰顔，冰雪精神照座間。',64,'全唐诗/poet.song.104000.json','["相逢憐我太衰顔，冰雪精神照座間。", "霽日有情茶乳合，春風無力柳絲閒。", "肯從逋客來三徑，秪恐佳人賦二山。", "舊說毛公今見否，似聞新向玉京還。"]'),
('b3d45cd6-792b-4daf-9baa-734884120613','和魏定父被檄還無爲','王之道','宋','宋诗','song-poetry','','[]','雨脚廉纖日脚微，秋陰猶暗北山陲。',64,'全唐诗/poet.song.104000.json','["雨脚廉纖日脚微，秋陰猶暗北山陲。", "莫言巖壑都無用，須信風雲會有期。", "邂逅醉鄊還自適，周旋詩社好相規。", "黄華又報重陽近，想見遲遲去魯時。"]'),
('99ab67a6-6e49-4ae7-b9f6-e24f3a0cf605','和孔純老按屬邑二首  其一','王之道','宋','宋诗','song-poetry','','[]','高車西去忽踰旬，坐想登臨得句頻。',64,'全唐诗/poet.song.104000.json','["高車西去忽踰旬，坐想登臨得句頻。", "楊柳陰交山徑晚，酴醾香滿驛亭春。", "吟餘掃壁時揮翰，醉裏投牀任吐茵。", "聞說歸來歡喜甚，故人相遇是詩人。"]'),
('fca41a3a-1add-46ca-a296-36d1b5f1e065','和孔純老按屬邑二首  其二','王之道','宋','宋诗','song-poetry','','[]','楊柳依依半掩扉，新晴疏影弄斜睴。',64,'全唐诗/poet.song.104000.json','["楊柳依依半掩扉，新晴疏影弄斜睴。", "好花覔句忍輕負，幽鳥勸沽良重違。", "閒愛青苔緣砌上，静看蝴蝶撲窗飛。", "雨多不覺蕪菁過，又喜盤中筍蕨肥。"]'),
('aff0add2-6505-46b7-bcc5-126a795c7d55','和許端夫兄弟二首時端夫出守當塗  其一','王之道','宋','宋诗','song-poetry','','[]','燈火當年記馬行，一時人物玩垂裳。',64,'全唐诗/poet.song.104000.json','["燈火當年記馬行，一時人物玩垂裳。", "舊游亂後半蕪没，新貴邇來多罪亡。", "我有塤箎相應和，君同蘭玉競芬芳。", "高文已見含元賦，不用研思古戰場。"]'),
('d43c4579-0513-4101-86d7-ba110dceff8f','和許端夫兄弟二首時端夫出守當塗  其二','王之道','宋','宋诗','song-poetry','','[]','相喜何須日寄聲，如君無處不知名。',64,'全唐诗/poet.song.104000.json','["相喜何須日寄聲，如君無處不知名。", "縱觀妙墨雲煙動，想見新詩欬唾成。", "带雪山川增綺麗，向春梅柳自欣榮。", "好將十詠圖歸去，穏步花甎繼李程。"]'),
('e0ecd94c-a25b-4bb2-86c2-1dee1ed1e5f3','和袁望回','王之道','宋','宋诗','song-poetry','','[]','千古風流憶孔明，老龍高卧志存身。',64,'全唐诗/poet.song.104000.json','["千古風流憶孔明，老龍高卧志存身。", "强陪簮紱更三聖，安坐江湖又四春。", "便合癡狂稱達者，誰能窮悴作騷人。", "一杯聊復從公醉，要見予言總是真。"]'),
('5e212459-ce92-4e4c-9a14-6bb50efc4471','過鄧步和張叔元見贈韵','王之道','宋','宋诗','song-poetry','','[]','獨舸東來夏日長，歸裝從此益生光。',64,'全唐诗/poet.song.104000.json','["獨舸東來夏日長，歸裝從此益生光。", "卧雲禾穂珠成實，傾露荷花麝被嚢。", "逸世才猷金騕褭，逼人風味木蘭堂。", "常疑正始遺音絕，把讀新詩遠壇場。"]'),
('e60c28fc-c643-41de-af21-6649abec86e2','夜泊官牌夾口大風追和陳去非歲晚感懷','王之道','宋','宋诗','song-poetry','','[]','咿喔鄰鷄夜向闌，曉風驕挾曉霜寒。',64,'全唐诗/poet.song.104000.json','["咿喔鄰鷄夜向闌，曉風驕挾曉霜寒。", "吹燈强取殘書讀，撥火重尋遠信看。", "綠蟻已應浮臘甕，青絲行復送春盤。", "旅懷欲倩高鴻寄，憑仗新詩付筆端。"]'),
('0243b8f6-6703-47b4-9303-d9cef79f7767','和張序臣合肥驛中詩','王之道','宋','宋诗','song-poetry','','[]','槖皋何處合肥東，知有詩翁杖履中。',64,'全唐诗/poet.song.104000.json','["槖皋何處合肥東，知有詩翁杖履中。", "魯會一時歸寂寞，吳吟千載發清雄。", "湖山照碧朦朧日，鞍馬欺寒料峭風。", "春入花梢人易感，莫教房闥歎飛蓬。"]'),
('0923790e-c5dc-4430-8378-bf1d04626b05','長至和魏公達','王之道','宋','宋诗','song-poetry','','[]','半夜迎長坐候明，眼看初日屋山平。',64,'全唐诗/poet.song.104000.json','["半夜迎長坐候明，眼看初日屋山平。", "詩豪不共年俱長，鬢雪惟應老自生。", "得酒人情何太喜，犯寒春色不多争。", "老農相慶無它語，盡道冬晴好趁耕。"]'),
('d8fa9135-3c7c-4e60-83a2-2257cfdde0e7','和孔純老送司法吳德聲','王之道','宋','宋诗','song-poetry','','[]','舞腰迴雪奏伊凉，餞設鈴齊舉别觴。',64,'全唐诗/poet.song.104000.json','["舞腰迴雪奏伊凉，餞設鈴齊舉别觴。", "如子固宜傾坐客，顧予何計挽征艎。", "交情舊喜推東道，歸夢先應到北堂。", "花柳枝頭春已閙，佇觀超擢寘周行。"]'),
('537601b2-5953-46b2-a574-7dbbef2835e0','和方景南參議見贈','王之道','宋','宋诗','song-poetry','','[]','向來疏率任天真，此去扶持護善鄰。',64,'全唐诗/poet.song.104000.json','["向來疏率任天真，此去扶持護善鄰。", "只恐磨磚難作鏡，已知行水戒推輪。", "簞瓢本是吾家物，軒冕寧容我輩人。", "多謝諸公共推轂，欣欣寒谷暗生春。"]'),
('1768fe30-08b5-4b4b-941a-b1cade083b73','和彦時兄韵','王之道','宋','宋诗','song-poetry','','[]','立馬山前問酒家，山峰森列兩溪斜。',64,'全唐诗/poet.song.104000.json','["立馬山前問酒家，山峰森列兩溪斜。", "扶疏新竹聽流水，天矯古松看霽霞。", "遠目自能供覔句，枯腸終不柰搜茶。", "一杯湯餅東窗晚，危坐清吟對月華。"]'),
('6090a08d-e500-4d8c-8dd9-1de2034a6507','用李夢發韵','王之道','宋','宋诗','song-poetry','','[]','夢迴詩思不勝清，卧聽幽禽兩囀更。',64,'全唐诗/poet.song.104000.json','["夢迴詩思不勝清，卧聽幽禽兩囀更。", "窗角界金分月色，山腰鳴玉潄溪聲。", "欲行且住心還適，久雨新晴眼倍明。", "莫爲浮名廢真賞，較來何重亦何輕。"]'),
('1ca6243c-50ec-43d0-801d-ee473325ff80','梅隠亭','王之道','宋','宋诗','song-poetry','','[]','無慮無營得自如，亂紅狼籍綠陰初。',64,'全唐诗/poet.song.104000.json','["無慮無營得自如，亂紅狼籍綠陰初。", "莫貪視盜誅鋤術，輕換齊民種蒔書。", "風物最憐清且好，賓朋那患數斯疏。", "高談亹亹還終晷，坐覺庭花影上裾。"]'),
('00beff8e-7b41-4518-a5e6-88f123fe8b20','麗澤堂','王之道','宋','宋诗','song-poetry','','[]','焚香讀易欲何求，只恐西鄰未識丘。',64,'全唐诗/poet.song.104000.json','["焚香讀易欲何求，只恐西鄰未識丘。", "千里交遊思命駕，一龕燈火喜逢秋。", "胸中雲夢應無筭，天上風雷得遍搜。", "莫向明時老巖壑，伊周元不羡巢由。"]'),
('becd85a5-c86e-45e8-b632-1bf53686629e','能賦臺','王之道','宋','宋诗','song-poetry','','[]','萬頃玻瓈水浸空，臺前佳色詠難窮。',64,'全唐诗/poet.song.104000.json','["萬頃玻瓈水浸空，臺前佳色詠難窮。", "倚欄人在烟霞外，落筆詩成笑語中。", "屬句畏慚非孟子，供歡端合有車公。", "解將能否分優劣，過眼昭然向與雄。"]'),
('7cbe818e-28a6-42ea-a848-464fa58e0546','代人上段拂參政','王之道','宋','宋诗','song-poetry','','[]','玉牒書成已六年，東游曾記此周旋。',64,'全唐诗/poet.song.104000.json','["玉牒書成已六年，東游曾記此周旋。", "千齡令慶亨嘉會，二府新分造化權。", "咫尺雲天依日月，斯須霖雨浹山川。", "應憐汨沒塵埃者，白髪青衫走道邉。"]'),
('39e4b8fb-3cc7-432d-ac3c-5610594f9c5d','江南道中','王之道','宋','宋诗','song-poetry','','[]','江迴山崦兩三家，招颭東風酒斾斜。',64,'全唐诗/poet.song.104000.json','["江迴山崦兩三家，招颭東風酒斾斜。", "羸馬送曛行自急，峭寒欺客晚還加。", "日邉雁足應傳信，竹外梅梢合放花。", "指點東城歸路窵，一川流水閙棲鴉。"]'),
('492d8a9a-02f8-415b-8dad-ec3f488be72a','隠静道中','王之道','宋','宋诗','song-poetry','','[]','馬頭聊復問諸塗，東指宣城百里餘。',64,'全唐诗/poet.song.104000.json','["馬頭聊復問諸塗，東指宣城百里餘。", "水外山屏供步障，道傍蛙吹接行車。", "青歸柳色浮烟裏，紅入花光過雨初。", "春意似同人意好，此行那患食無魚。"]'),
('d4597c53-69e0-4628-bf52-65ae82b53c89','寄余元明','王之道','宋','宋诗','song-poetry','','[]','對月令人憶子年，别來重見望舒圓。',64,'全唐诗/poet.song.104000.json','["對月令人憶子年，别來重見望舒圓。", "閒中情性南無界，物外光陰小有天。", "連喜得官如得句，慣看乘馬似乘船。", "朝迴共醉知何日，凖擬春衣當酒錢。"]'),
('b9b186e6-40f3-4840-8715-ebce768eab62','寄孫次卿','王之道','宋','宋诗','song-poetry','','[]','歸來啜菽得無愁，但覺官身不自由。',64,'全唐诗/poet.song.104000.json','["歸來啜菽得無愁，但覺官身不自由。", "敢倩雙魚傳尺素，要知一日似三秋。", "射陽别後從新辟，幽谷公餘獲勝游。", "尚憶龍盤分袂處，五更殘月在山頭。"]'),
('4e3db0f1-422f-4727-8903-434316348239','次韵高守無隠苦熱','王之道','宋','宋诗','song-poetry','','[]','鬰蒸還起砲車雲，旱氣方隆雨未能。',64,'全唐诗/poet.song.104000.json','["鬰蒸還起砲車雲，旱氣方隆雨未能。", "應念開幬來白鳥，故成灑酒聚青蠅。", "南皮痛飲君當繼，北牖高眠我獨醒。", "人仰郡侯清可倚，暑中真是一條冰。"]'),
('3ac20acf-6490-46e6-884e-0bab5ddb45a3','用東坡贈晁新城韵呈朱烏江','王之道','宋','宋诗','song-poetry','','[]','偶然來賦瓦梁行，亂後欣聞醉客聲。',64,'全唐诗/poet.song.104000.json','["偶然來賦瓦梁行，亂後欣聞醉客聲。", "村戍火明人指路，江城風静夜鳴鉦。", "對牀聽雨他時念，撥火哦詩此意清。", "聞說魚軒還枳里，先生應合暫歸耕。"]'),
('3b1bda2c-c68c-4a8e-8675-ff37d1a9359c','和連聖舉呈張彦智','王之道','宋','宋诗','song-poetry','','[]','公望巖巖映廣東，曲江重見舊家風。',64,'全唐诗/poet.song.104000.json','["公望巖巖映廣東，曲江重見舊家風。", "威行草木霜争肅，春到湖山雪自融。", "至喜此心魚鳥共，去思前日吏民同。", "從今不復憂兵火，卻敵如公笑語中。"]'),
('ba8aec25-25c3-4dcb-8d56-c57690f40df3','次韵伯遠運幹見寄','王之道','宋','宋诗','song-poetry','','[]','善鄰雖幸借餘光，終愧陳臻問發棠。',64,'全唐诗/poet.song.104000.json','["善鄰雖幸借餘光，終愧陳臻問發棠。", "官柳又驚眉拂翠，宫梅應喜額塗黄。", "江湖得計還相造，道義論交付兩忘。", "多謝乾坤容長物，許乘春意到文昌。"]'),
('742bb1e4-13b1-40f9-85af-0432723dbec9','次彦時兄苦旱韵','王之道','宋','宋诗','song-poetry','','[]','斗粟衡門且自安，老來筋力厭辛酸。',64,'全唐诗/poet.song.104000.json','["斗粟衡門且自安，老來筋力厭辛酸。", "官游動是三年别，邂逅應容一笑歡。", "荷浦珠聯秋露溢，稻田龜坼暑風亁。", "昨朝溪足捎新雨，已覺羸軀怯夜寒。"]'),
('39699ce3-e794-46b1-95a2-856bbf214e56','次韵沈元吉兵火後初食羊','王之道','宋','宋诗','song-poetry','','[]','時難盆甑久無羶，夢寐何郎食萬錢。',64,'全唐诗/poet.song.104000.json','["時難盆甑久無羶，夢寐何郎食萬錢。", "一臠乍驚肥羜美，五紽應喜敝裘全。", "好從牛炙論蓴菜，堪笑河魨詠柳綿。", "弹鋏得魚良不惡，先生何用鄙烹鮮。"]'),
('d246e052-2a99-4e57-93fe-3da90ddcd559','次韵陳勉仲二首  其一','王之道','宋','宋诗','song-poetry','','[]','蜂喜春晴競出籠，雪明籬脚眼看融。',64,'全唐诗/poet.song.104000.json','["蜂喜春晴競出籠，雪明籬脚眼看融。", "柳條借日還金色，梅萼因風動玉容。", "窺牖數聲禽度曲，過庭千字雁書空。", "青氈笑指吾家物，芳草無邉一望中。"]'),
('bcd43167-0009-47b3-b707-e42e2fff1371','次韵陳勉仲二首  其二','王之道','宋','宋诗','song-poetry','','[]','十載窮愁鳥出籠，春來天意似通融。',64,'全唐诗/poet.song.104000.json','["十載窮愁鳥出籠，春來天意似通融。", "得書故舊頗相憫，上疏朝廷應見容。", "開府莫辭金帛盡，犂庭當冀祲氛空。", "廟堂素定平戎策，不待文淵在目中。"]'),
('a66956fb-9ce7-42bc-95d6-cc4099a01009','次韵張進彦見寄二首  其一','王之道','宋','宋诗','song-poetry','','[]','坐想雲烟走筆端，夜哦佳製老忘寒。',64,'全唐诗/poet.song.104000.json','["坐想雲烟走筆端，夜哦佳製老忘寒。", "一時思致追長慶，千載風流識建安。", "接武尚稽班玉筍，昂霄終合待金鑾。", "自憐衰退無新語，捧腹還君醉眼看。"]'),
('9e9515b5-f566-49bc-9d18-3cfe7d736072','次韵張進彦見寄二首  其二','王之道','宋','宋诗','song-poetry','','[]','鼻息齁齁盡日眠，從他兒輩競嘲邉。',64,'全唐诗/poet.song.104000.json','["鼻息齁齁盡日眠，從他兒輩競嘲邉。", "那知問對成中說，自得逍遥喜內篇。", "雪裏書来簷噪鵲，燈前詩就鼎凝煙。", "中郎去後人難繼，漫詫柯亭富笛椽。"]'),
('2bd19ca3-57c9-4ab0-80d7-e0677074160d','次韵同舍李支使夢與二首  其一','王之道','宋','宋诗','song-poetry','','[]','三紀橋門過隙光，醉吟曾共晚風凉。',64,'全唐诗/poet.song.104000.json','["三紀橋門過隙光，醉吟曾共晚風凉。", "舊游何在已蕪没，前好欲言空感傷。", "重對詩嚢開錦繡，要看談麈落冰霜。", "苕溪此去如相憶，雙鯉時應寄一行。"]'),
('26ec648c-833d-48e9-98f6-52eb1c0e6bef','次韵同舍李支使夢與二首  其二','王之道','宋','宋诗','song-poetry','','[]','短短燈檠便且光，看書猶記感秋凉。',64,'全唐诗/poet.song.104000.json','["短短燈檠便且光，看書猶記感秋凉。", "飄零未遂襟期遠，遲暮徒驚歲月傷。", "初喜嫩荷青直盖，不知新竹粉儲霜。", "相從益覺交情篤，時擲隋珠到我行。"]'),
('fcf794b2-7ebd-4c0a-9f1e-895f0d7f516c','次韵周子嘉詠雪','王之道','宋','宋诗','song-poetry','','[]','勢凌風力鬬清嚴，徹骨尤非老病堪。',64,'全唐诗/poet.song.104000.json','["勢凌風力鬬清嚴，徹骨尤非老病堪。", "凍蠡夜回千首北，寒梅朝放一枝南。", "扁舟底事方行役，販履何人正立談。", "江上别來勞夢寐，相寛猶喜見詩三。"]'),
('f8137bde-bd71-4343-841a-17a990cb385b','詠雪','王之道','宋','宋诗','song-poetry','','[]','白榆風起匝天來，透隙穿簾醉眼開。',64,'全唐诗/poet.song.104000.json','["白榆風起匝天來，透隙穿簾醉眼開。", "氈襯庭階茸妥貼，带盤山徑玉縈迴。", "根行萬國將宜麥，香動千林獨放梅。", "閒把銀杯評柳絮，始知謝女亦非才。"]'),
('46a0225c-8918-4220-a8f8-112fcb66abe8','和彦時兄臘雪六首  其一','王之道','宋','宋诗','song-poetry','','[]','不耕何敢嘆無囷，多謝先生早見傾。',64,'全唐诗/poet.song.104000.json','["不耕何敢嘆無囷，多謝先生早見傾。", "望歲比同傷再潦，逢年今共快三霙。", "光凝夜旦千山曉，勢合高卑萬壑平。", "坐想袁安門未掃，洛陽誰復念孤惸。"]'),
('2814499e-1d2d-4291-ab3a-c5892358f3e5','和彦時兄臘雪六首  其二','王之道','宋','宋诗','song-poetry','','[]','一洗乾坤不動塵，瑶臺銀闕鬬清新。',64,'全唐诗/poet.song.104000.json','["一洗乾坤不動塵，瑶臺銀闕鬬清新。", "齊腰欲究安心法，乘興當爲訪戴人。", "曄曄寒江歸釣艇，丁丁虚谷動樵斤。", "二詩遠比幽蘭勝，擊節懸知衆所賓。"]'),
('ef424ccd-e6e2-4067-9c60-bdf405e2bdeb','和彦時兄臘雪六首  其三','王之道','宋','宋诗','song-poetry','','[]','敢以簞瓢傲廪囷，撇醅聊復笑還傾。',64,'全唐诗/poet.song.104000.json','["敢以簞瓢傲廪囷，撇醅聊復笑還傾。", "爲言空腹朝搜句，不覺寒窗夜集霙。", "澤浹寰區成地富，光生蓬蓽見天平。", "預占有歲從今始，廊廟何憂不及惸。"]'),
('6c34de31-623c-456a-a4ea-444ce1e45fe8','和彦時兄臘雪六首  其四','王之道','宋','宋诗','song-poetry','','[]','瑶林交映出風塵，便覺寒門氣象新。',64,'全唐诗/poet.song.104000.json','["瑶林交映出風塵，便覺寒門氣象新。", "莫訝窗前群噪鵲，須憐江上有歸人。", "抛甎已喜來荆璞，斵堊無勞運郢斤。", "坐擁紅金饒大嚼，一時高會幕中賓。"]'),
('357e5592-9806-45c5-9ebc-d681ae57de83','和彦時兄臘雪六首  其五','王之道','宋','宋诗','song-poetry','','[]','厭聞饑雀噪空囷，猶喜茅齋未遽傾。',64,'全唐诗/poet.song.104000.json','["厭聞饑雀噪空囷，猶喜茅齋未遽傾。", "屑玉豈勞青女送，飛花聊混白雲霙。", "預占歲稔矜祥舊，不擇貧家荷施平。", "早晚林梢掛寒日，爲迴和氣慰饑惸。"]'),
('442e3872-0c76-4f5e-b292-ff1f25f43244','和彦時兄臘雪六首  其六','王之道','宋','宋诗','song-poetry','','[]','舉首西風漫障塵，清無纖翳六花新。',64,'全唐诗/poet.song.104000.json','["舉首西風漫障塵，清無纖翳六花新。", "謝庭擬似吟飛絮，洛浦飄颻見麗人。", "漏箭不知樓外曉，觥籌先發坐中春。", "兔園盛集應難繼，空想當時主與賓。"]'),
('3191dcfa-b94b-46a0-b2fd-356c0a953041','次韵孫興宗梅花','王之道','宋','宋诗','song-poetry','','[]','厭浥庭柯雨未乾，乍晴天氣午猶寒。',64,'全唐诗/poet.song.104000.json','["厭浥庭柯雨未乾，乍晴天氣午猶寒。", "傳來多謝新詩寄，接得翻愁病眼看。", "漫想素粧嫌粉涴，須憐青子着枝酸。", "和羮有日君知否，老大心腸只自寛。"]'),
('7bb26fd0-f65b-47b1-a52f-9f6ab35a13aa','次韵董令升梅花','王之道','宋','宋诗','song-poetry','','[]','花前樽酒瀉尖泥，痛飲仍欣客到齊。',64,'全唐诗/poet.song.104000.json','["花前樽酒瀉尖泥，痛飲仍欣客到齊。", "竹外一枝青更好，水邉疏影動還迷。", "醉醒正值微風入，酬唱何妨素魄低。", "聞說歸舟陽羡去，應容酌别爲烹鷄。"]'),
('0bf35c39-0122-479e-8fd0-719aaec863dd','詠梅示魏吉老','王之道','宋','宋诗','song-poetry','','[]','孤芳常恐百花知，桃李紛紛亦强追。',64,'全唐诗/poet.song.104000.json','["孤芳常恐百花知，桃李紛紛亦强追。", "照雪精神應自喜，逼人風味不吾虧。", "幽香隠約留衣袂，疏影玲瓏鑒硯池。", "欲識東君好消息，夜來青鳥宿南枝。"]'),
('e87ae055-ed11-4ba4-a262-b4d2292e6079','次方正叔知縣韵僕今年六十有三竊觀正叔贈陳甥述懷詩有感予心併和二首奉呈  其一','王之道','宋','宋诗','song-poetry','','[]','年踰六十我何堪，心曲因君得縱談。',64,'全唐诗/poet.song.104000.json','["年踰六十我何堪，心曲因君得縱談。", "閲史舊甞疑夏五，參禪今遂薦前三。", "飲闌卻怪清樽惡，饑甚猶憐糲食甘。", "交態物情何足較，邇來爐鼎興方酣。"]'),
('e3246158-311e-4688-9eb3-42361588b505','次方正叔知縣韵僕今年六十有三竊觀正叔贈陳甥述懷詩有感予心併和二首奉呈  其二','王之道','宋','宋诗','song-poetry','','[]','水滿陂塘麥滿村，路逢田父和長言。',64,'全唐诗/poet.song.104000.json','["水滿陂塘麥滿村，路逢田父和長言。", "題詩懶作蠅頭字，貰酒愁看犢鼻褌。", "芳草藉青迷野逕，遠山横翠入柴門。", "道衡骨朽無人繼，卿相誰能預識温。"]'),
('8a6f170d-cb71-48ee-85c3-2f353c3a08d9','和張詠老知縣','王之道','宋','宋诗','song-poetry','','[]','照蔀輝輝碧夜光，貧兒那復苦悲凉。',64,'全唐诗/poet.song.104000.json','["照蔀輝輝碧夜光，貧兒那復苦悲凉。", "得魚始信筌無用，斵堊終期鼻不傷。", "我類槁苖猶欠雨，君同脩竹飽經霜。", "詩成病眼昏加澁，欲寫還憂細作行。"]'),
('b42379a5-9958-4c3f-ae0f-6fcbaa840a93','臘梅和次韓韵  其一','王之道','宋','宋诗','song-poetry','','[]','一枝横亞竹梢黄，宫様新翻半額粧。',64,'全唐诗/poet.song.104000.json','["一枝横亞竹梢黄，宫様新翻半額粧。", "閒淡似宜冬後日，清癯應怯夜來霜。", "生憎丹臉嬌含酒，巧妬冰肌冷透香。", "取蠟爲花緣底事，浪吟空發少年狂。"]'),
('b6190c64-8306-4a70-b530-c0a4fc9d420f','臘梅和次韓韵  其二','王之道','宋','宋诗','song-poetry','','[]','可憐風骨肖梅英，試問東君曷似生。',64,'全唐诗/poet.song.104000.json','["可憐風骨肖梅英，試問東君曷似生。", "正色不從朱粉涴，耐寒猶怪雪霜輕。", "論交薝蔔君爲勝，投社酴醿我更清。", "縱美詎能齊衆口，漫言異日許調羮。"]'),
('51197f40-c5c7-434d-8d1a-24e1b3cee6be','夏月自六安舟行還安豐','王之道','宋','宋诗','song-poetry','','[]','灔灔溪流漲渌波，乍晴天氣自清和。',64,'全唐诗/poet.song.104000.json','["灔灔溪流漲渌波，乍晴天氣自清和。", "露梢抽翠交新竹，風葉飜紅颭嫩荷。", "水外遠山晨霧重，道傍佳樹午陰多。", "頭旋更苦舟揺兀，說與篙師住得麽。"]'),
('fc06d3f0-b49a-4a74-a769-4d67c779ff01','和州得旨移粟宣城舟中和何希淵韵','王之道','宋','宋诗','song-poetry','','[]','轍魚應怪决江流，千里重爲疊嶂游。',64,'全唐诗/poet.song.104000.json','["轍魚應怪决江流，千里重爲疊嶂游。", "頗慣黑甜相對美，可無赤糙爲寛憂。", "干戈在眼心還折，勲業何時鬢早秋。", "已辦賣刀歸買犢，不妨多種白江州。"]'),
('a68cf1db-eb13-4fc1-9833-374a38e82b22','沙窩道中','王之道','宋','宋诗','song-poetry','','[]','疊疊青山處處溪，溪聲淙玉潄玻瓈。',64,'全唐诗/poet.song.104000.json','["疊疊青山處處溪，溪聲淙玉潄玻瓈。", "懸知菊水人難老，可信桃源路易迷。", "山嶺梅花迎客笑，路傍松盖與雲齊。", "寒林昨夜微經雨，新跡分明過虎蹄。"]'),
('969b6fbf-7ced-4a74-bb2f-6ef4895570da','遡流入柵江','王之道','宋','宋诗','song-poetry','','[]','久客心膓怯遡洄，不堪官事緊相催。',64,'全唐诗/poet.song.104000.json','["久客心膓怯遡洄，不堪官事緊相催。", "踏霜人去繵風吼，衝浪舟行岸凍開。", "雪盡野梅紅剪臘，春迴溪水綠生苔。", "窮愁好逐殘年盡，三日元正與泰來。"]'),
('dc08afb8-e33b-409a-953d-78a1d319a929','春殘次韵張叔元','王之道','宋','宋诗','song-poetry','','[]','亂紅狼籍紫苔斑，簾捲東風雨脚殘。',64,'全唐诗/poet.song.104000.json','["亂紅狼籍紫苔斑，簾捲東風雨脚殘。", "蜀酒漸宜消晝永，單衣猶覺怯朝寒。", "玲瓏有客雙揺轡，矍鑠何人一據鞍。", "芍藥酴醿晴更好，勸君休作夢中看。"]'),
('f43632c7-b323-4d38-85e2-b65a33d4808d','次韵徐伯遠木芙蓉','王之道','宋','宋诗','song-poetry','','[]','千林揺落見孤芳，銷得詩人賦拒霜。',64,'全唐诗/poet.song.104000.json','["千林揺落見孤芳，銷得詩人賦拒霜。", "高壓菊花還獨步，静窺池水試新粧。", "自憐衰病追歡懶，忽睹騷吟引興長。", "何必採江重比並，佳名艶色正相當。"]'),
('8c7673bb-da63-4659-bd43-e5cffe44973c','次韵子厚弟小春偶成','王之道','宋','宋诗','song-poetry','','[]','强插梨花做小春，風前詩思有餘清。',64,'全唐诗/poet.song.104000.json','["强插梨花做小春，風前詩思有餘清。", "路逢野老那知姓，耳聽幽禽自喚名。", "歲晚山林松檜色，天寒闗塞鼔鞞聲。", "枕流潄石君無笑，我欲巖居學子荆。"]'),
('af09192d-ba01-4cc1-867e-66754ded20d0','次韵程德遠登清淮樓','王之道','宋','宋诗','song-poetry','','[]','西望中原懶轉頭，十年空見水東流。',64,'全唐诗/poet.song.104000.json','["西望中原懶轉頭，十年空見水東流。", "塗山漫想諸侯會，濠上聊追二子游。", "大劍長刀秋正擾，淡烟疏雨暮還愁。", "誰能不討清河朔，誓楫當期祖豫州。"]'),
('3e829521-9418-4f63-b13f-3a5439b73ad9','秋興八首追和杜老  其一','王之道','宋','宋诗','song-poetry','','[]','湖外干戈半綠林，湖邉葭薍晚森森。',64,'全唐诗/poet.song.104000.json','["湖外干戈半綠林，湖邉葭薍晚森森。", "風霾未放遠山出，嵐氣又連凄日陰。", "世亂且同吟嘯樂，時來終快掃除心。", "天寒况是開爐近，應有佳人賦藁砧。"]'),
('66acd9cf-bf40-4605-a8ff-b80ad5e6cfe3','秋興八首追和杜老  其二','王之道','宋','宋诗','song-poetry','','[]','巉巖石壁半欹斜，茅栗叢中菊漸華。',64,'全唐诗/poet.song.104000.json','["巉巖石壁半欹斜，茅栗叢中菊漸華。", "風裏斷鴻書带草，山頭飛葉漢浮槎。", "柂樓索莫吟秋笛，戍火青熒咽暮笳。", "争似漁翁最蕭散，晚來和月卧蘆花。"]'),
('2d528011-495d-467e-b184-c7535d11e98b','秋興八首追和杜老  其三','王之道','宋','宋诗','song-poetry','','[]','雲影曚曨日洒暉，金湖西畔晚陰微。',64,'全唐诗/poet.song.104000.json','["雲影曚曨日洒暉，金湖西畔晚陰微。", "漁舟繚繞青山去，楓葉追隨白鳥飛。", "摩詰家風非世有，淵明心性與時違。", "近來病瘠連詩痩，翻愛西臺字様肥。"]'),
('a6e8f75b-7401-4d4e-aadd-6c86fce46ac5','秋興八首追和杜老  其四','王之道','宋','宋诗','song-poetry','','[]','轆轤世態一枰棊，銷得秋來宋玉悲。',64,'全唐诗/poet.song.104000.json','["轆轤世態一枰棊，銷得秋來宋玉悲。", "舒嘯可無元亮意，哦詩如見少陵時。", "江湖於我還蕭散，田舍從他笑重遲。", "異域故人今在否，青燈牢落夜相思。"]'),
('bebf4062-80da-4133-881a-ce8cd0d67289','秋興八首追和杜老  其五','王之道','宋','宋诗','song-poetry','','[]','翠壁蒼崖水外山，山頭茅舍兩三間。',64,'全唐诗/poet.song.104000.json','["翠壁蒼崖水外山，山頭茅舍兩三間。", "夜窗明月來臨卷，晝户清風爲啟闗。", "霞綺障秋驚老眼，酒紅潮面發衰顔。", "集英一夢如今覺，猶憶當時曉趁班。"]'),
('7dea9557-1d2a-4f93-8ae1-5e96981e66a0','秋興八首追和杜老  其六','王之道','宋','宋诗','song-poetry','','[]','遠水西來抱鹿頭，山前草木带霜秋。',64,'全唐诗/poet.song.104000.json','["遠水西來抱鹿頭，山前草木带霜秋。", "黄花雅意撩詩興，紅葉端能寄别愁。", "日月奔馳雙轉轂，江湖漂蕩一輕鷗。", "干戈未戢中興沸，蹴被空懷祖豫州。"]'),
('e3e31e65-e867-4e87-a491-2497ae4066a4','秋興八首追和杜老  其七','王之道','宋','宋诗','song-poetry','','[]','勲業休煩付考功，此生終待老山中。',64,'全唐诗/poet.song.104000.json','["勲業休煩付考功，此生終待老山中。", "宦情薄似賢人酒，詩思清於少女風。", "秋雨養肥桑耳白，溪流濯出柳鬚紅。", "不堪世路頻磽确，四十蕭然秃鬢翁。"]'),
('9f50dfbc-cc3d-48c6-a9a0-50ee48e6b064','秋興八首追和杜老  其八','王之道','宋','宋诗','song-poetry','','[]','迢迢山勢去委蛇，林木東頭見荻陂。',64,'全唐诗/poet.song.104000.json','["迢迢山勢去委蛇，林木東頭見荻陂。", "疏竹依巖秋迸筍，病桑經火雨生枝。", "草侵藥種多難辨，土撥松苖欲自移。", "照眼誰家幾枝橘，出籬丹實正離離。"]'),
('3593fa6d-d373-447e-81bc-8d98b82515e4','送許判官志仁','王之道','宋','宋诗','song-poetry','','[]','是行猶及豫章春，聞說逢迎有故人。',64,'全唐诗/poet.song.104000.json','["是行猶及豫章春，聞說逢迎有故人。", "傾盖爲君殊快意，摻袪令我重傷神。", "向陽花木初開葉，得雨蛟龍已轉身。", "江上新晴應更好，綠楊如幄草如茵。"]'),
('606ffa7d-14a6-42a9-b4d5-cdcc4de24c7d','送董令升舍人歸朋溪二首  其一','王之道','宋','宋诗','song-poetry','','[]','西掖歸来鬢未華，著書論字當生涯。',64,'全唐诗/poet.song.104000.json','["西掖歸来鬢未華，著書論字當生涯。", "撐腸何止五千卷，溢箧定踰三十車。", "秋露青黄新種橘，春風紅紫舊栽花。", "東還貪逐朋溪樂，只恐金鑾詔草麻。"]'),
('9787f8c5-f719-4856-a6df-f60081d73ec9','送董令升舍人歸朋溪二首  其二','王之道','宋','宋诗','song-poetry','','[]','仙舟東去訪金華，歌徹驪駒向水涯。',64,'全唐诗/poet.song.104000.json','["仙舟東去訪金華，歌徹驪駒向水涯。", "試問玉堂司鳯詔，何如蓬島駕雲車。", "雨餘翠篠初飜籜，風暖丹葵欲放花。", "天氣清和行色好，江南江北半桑麻。"]'),
('827ca405-89f0-4efe-b758-7a8739131770','送劉元發歸鄱陽次其韵','王之道','宋','宋诗','song-poetry','','[]','杖藜千里訪茅茨，來赴當年一笑期。',64,'全唐诗/poet.song.104000.json','["杖藜千里訪茅茨，來赴當年一笑期。", "白髪我徒悲老大，青山君尚記艱危。", "夜聽高論因忘寐，晝味新詩可療饑。", "冬日迎長殊可愛，何妨去國少遲遲。"]'),
('e619bf2f-4923-43b4-8d15-b5e5a5e2132c','送淮西轉運判官李彦恢還朝','王之道','宋','宋诗','song-poetry','','[]','江頭旗影弄青紅，似說朝天四牡東。',64,'全唐诗/poet.song.104000.json','["江頭旗影弄青紅，似說朝天四牡東。", "抱病不容攀轡勒，送行那復遣兒童。", "田均税斂千年利，福及瘡痍九郡同。", "此去定知還禁近，從來陰德報宜豐。"]'),
('91be916e-a24c-45cc-8e39-5cd1fa97df04','送徐次公罷歷陽任歸三衢','王之道','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','聞說家書賦鶺鴒，歸歟難弟見難兄。',64,'全唐诗/poet.song.104000.json','["聞說家書賦鶺鴒，歸歟難弟見難兄。", "接聯本作二年調，解印俄成千里行。", "故國一犁春雨足，長江三板暮潮平。", "爛柯况是神仙宅，招隠詩成好寄聲。"]'),
('b051a4df-fe54-4e70-9895-c5feae391c68','送徐季公運幹罷任','王之道','宋','宋诗','song-poetry','','[]','羈栖無柰老而窮，又見徐卿馬首東。',64,'全唐诗/poet.song.104000.json','["羈栖無柰老而窮，又見徐卿馬首東。", "快意一時荷葉雨，增明千里稻花風。", "高材合在雲霄上，勝處能忘澗壑中。", "法護相從如問我，爲言蹤跡與君同。"]'),
('13fcda54-29ba-44f9-af90-09757c989504','送端溪尉張達城挈家南歸','王之道','宋','宋诗','song-poetry','','[]','年時蕭寺雪初晴，聞道君來眼倍明。',64,'全唐诗/poet.song.104000.json','["年時蕭寺雪初晴，聞道君來眼倍明。", "送别又看秋欲去，論交還感盖初傾。", "帆張須水秋潮漲，路入鉛山晚翠横。", "快向端溪從吏隠，歸來穏步上蓬瀛。"]'),
('46db10d0-8d18-43ac-ad41-32afc2ff4f37','送江致遠歸建昌','王之道','宋','宋诗','song-poetry','','[]','翩然歸興不吾留，應爲高堂念遠遊。',64,'全唐诗/poet.song.104000.json','["翩然歸興不吾留，應爲高堂念遠遊。", "數日語離良作惡，幾時書到得無愁。", "白沙翠竹千山晚，朱實黄花萬里秋。", "後夜西風茅店月，醉吟應不費冥搜。"]'),
('87e50c1b-72ba-4006-88c1-b7919eae2a06','房陵秋日','王之道','宋','宋诗','song-poetry','','[]','新詩來處自房州，已及瓜時嘆滯留。',64,'全唐诗/poet.song.104000.json','["新詩來處自房州，已及瓜時嘆滯留。", "曾望碧雲頻送目，又驚紅葉再敲秋。", "千山不隔清風遠，兩地應同素月流。", "游刃似君誠利器，只今無復見全牛。"]'),
('04dd3dfe-9a3c-468f-8ba2-c80aa0b1a977','中秋和彦立兄韵悼伯父仲球','王之道','宋','宋诗','song-poetry','','[]','月華秋氣共清圓，千古佳時句一聯。',64,'全唐诗/poet.song.104000.json','["月華秋氣共清圓，千古佳時句一聯。", "節物傷心還惙惙，山光經雨自涓涓。", "潢池兵火今方熾，溝壑饑羸正可憐。", "怊悵去年人已矣，亂離誰復問招延。"]'),
('d3321027-1e64-40ff-9131-ce6094854c8f','邉公式周表卿侍郎同年會','王之道','宋','宋诗','song-poetry','','[]','侍郎修好燕群公，雁塔題名二紀同。',64,'全唐诗/poet.song.104000.json','["侍郎修好燕群公，雁塔題名二紀同。", "談笑静移楊柳日，杯盤清泛芰荷風。", "鵬摶競祝三旌貴，鯨吸相期百榼空。", "此會明年應更好，馬周行亦起新豐。"]'),
('d582186f-dca3-4561-8c5b-11345576132f','蘇臺憫農','王之道','宋','宋诗','song-poetry','','[]','稻田高下欲分畦，積潦瀰茫隔寸堤。',64,'全唐诗/poet.song.104000.json','["稻田高下欲分畦，積潦瀰茫隔寸堤。", "天意未收連夜雨，農功良苦半身泥。", "一丸莫救風濤决，千頃空憐稼穡低。", "朝滿夕除應可信，望晴心緒憶昌黎。"]'),
('5ab29efc-e49a-4f66-bb32-1654258ac1ed','宣城驛中送建康倅趙純中','王之道','宋','宋诗','song-poetry','','[]','芍藥飄零雨洗春，江城柳色静無塵。',64,'全唐诗/poet.song.104000.json','["芍藥飄零雨洗春，江城柳色静無塵。", "扁舟未果尋歸路，小驛那堪送故人。", "萬里雲天心共遠，一龕燈火話相親。", "因風無惜霑餘馥，我亦貧兒望富鄰。"]'),
('c34e22c5-6e3c-4f4c-8ef9-7791d1ffbce3','和文倅侯彦嘉二首  其一','王之道','宋','宋诗','song-poetry','','[]','相逢珠玉走佳章，顧我無能更老蒼。',64,'全唐诗/poet.song.104000.json','["相逢珠玉走佳章，顧我無能更老蒼。", "嘗鼎固應從指染，衝天行喜見雲翔。", "向來别恨江同遠，此去詩情日共長。", "才似二公今二妙，山庭淵角繡肝腸。"]'),
('1e82d644-3d7e-4073-98f4-39acc49e17cb','和文倅侯彦嘉二首  其二','王之道','宋','宋诗','song-poetry','','[]','暉暉晴日樹頭平，望外遥山宿霧輕。',64,'全唐诗/poet.song.104000.json','["暉暉晴日樹頭平，望外遥山宿霧輕。", "積潦夜增南浦漲，微風朝送北窗清。", "滯留羈客牽歸思，陶寫新詩盡物情。", "誰謂春宵常苦短，老來無寐厭長更。"]'),
('2d7b0667-1a11-4658-b8c3-91e4e855ea8e','送無爲守鄭深道移嚴州','王之道','宋','宋诗','song-poetry','','[]','世稱儒雅擅青徐，今見君侯信不虛。',64,'全唐诗/poet.song.104000.json','["世稱儒雅擅青徐，今見君侯信不虛。", "報政未容更繡水，除書先已易桐廬。", "郡鄰帝所旋趨召，地切家山勿戀居。", "千乘來迎催去急，邦人何計挽行車。"]'),
('a4b4d334-0eb7-4ce1-9882-cdfa3786f75a','送錢遜叔出守襲慶賜出身除職','王之道','宋','宋诗','song-poetry','','[]','賜對金鑾下九天，旋聞熊軾爲驅前。',64,'全唐诗/poet.song.104000.json','["賜對金鑾下九天，旋聞熊軾爲驅前。", "人從芸閣初分直，桂折蟾宫乍得仙。", "刺史江山聊復爾，翰林風月自依然。", "下車快草東封疏，今去祥符正百年。"]'),
('93365d69-c144-4c7a-9cd7-01dde2c66ed9','次韵蔣守張進彦','王之道','宋','宋诗','song-poetry','','[]','邂逅傳杯莫放杯，七年重見夢初回。',64,'全唐诗/poet.song.104000.json','["邂逅傳杯莫放杯，七年重見夢初回。", "休嗟歲月堂堂去，且喜旌麾得得來。", "春至會霑新雨露，時清應掃舊氛埃。", "如君才業今張鎬，憐我棲遲轂屢推。"]'),
('b1dcaab9-f358-47da-b8e4-c0876e3da166','送陳南仲守象州','王之道','宋','宋诗','song-poetry','','[]','熊軾朱轓照野眀，知君今赴象山行。',64,'全唐诗/poet.song.104000.json','["熊軾朱轓照野眀，知君今赴象山行。", "榮觀共作歎嗟語，静念獨傷離别情。", "畏景逼人才數日，脩塗計此始三程。", "至時應在中元後，好寄雙魚慰友生。"]'),
('9936e76f-9394-4036-886e-e19761a5eccc','送秦德久守安豐','王之道','宋','宋诗','song-poetry','','[]','歷水分攜十六年，相逢鬚鬢盡蒼然。',64,'全唐诗/poet.song.104000.json','["歷水分攜十六年，相逢鬚鬢盡蒼然。", "喜君宦况新來好，許我交情老更堅。", "小雨送行春溜急，長楊留别午陰圓。", "畫船插幟澄江遠，回首風帆指繡川。"]'),
('2ba7cfb1-fa28-4341-8d0b-7ae119e12604','喜雨','王之道','宋','宋诗','song-poetry','','[]','雷聲翻海電光紅，濯濯薔薇一夜空。',64,'全唐诗/poet.song.104000.json','["雷聲翻海電光紅，濯濯薔薇一夜空。", "雲氣共看淵躍蜧，雨祥曾驗葉生蟲。", "佇期多稼干箱富，先慶來麰百室豐。", "飾喜自慚樽酒薄，只將香火向穹窿。"]'),
('707626f6-b002-4b2b-9e4a-be7d49b99d00','次韵周漕喜雨','王之道','宋','宋诗','song-poetry','','[]','十載棲遲畎畆間，無聊尤苦屢無年。',64,'全唐诗/poet.song.104000.json','["十載棲遲畎畆間，無聊尤苦屢無年。", "可憐一雨今時若，便覺千塍頓鬰然。", "擊壌有期應共慶，效顰非分敢争妍。", "正當簷溜江河决，想見高吟夜不眠。"]'),
('e18bf31c-33a0-49b8-b8d1-efbe35f65e75','酬章序臣二首  其一','王之道','宋','宋诗','song-poetry','','[]','風梢揺落雪飛花，誰傳江梅到我家。',64,'全唐诗/poet.song.104000.json','["風梢揺落雪飛花，誰傳江梅到我家。", "曾把數枝分暗馥，要催群卉助光華。", "高吟兩絕那容繼，勝賞雙清蔑以加。", "春不世情應委曲，十年留滯在天涯。"]'),
('66d645fe-2167-4f14-9df7-b8d98e6b2c0f','酬章序臣二首  其二','王之道','宋','宋诗','song-poetry','','[]','老懶觀梅喜見花，一枝聊復寄君家。',64,'全唐诗/poet.song.104000.json','["老懶觀梅喜見花，一枝聊復寄君家。", "清香撲袂傳春信，疏影揺窗借日華。", "小小池塘從掩映，依依楊柳漫交加。", "和羮風味今猶古，回首青青遂有涯。"]'),
('2b49a5f8-253e-4dfb-adde-e80bb61dc505','酬李才叔見贈','王之道','宋','宋诗','song-poetry','','[]','篙師且緩莫予催，老眼逢君喜暫開。',64,'全唐诗/poet.song.104000.json','["篙師且緩莫予催，老眼逢君喜暫開。", "相與未成招隠什，分携宜盡送行杯。", "誰令急景堂堂去，我爲佳人得得來。", "萬壑千岩終欲遍，歸歟清夢轉幽哉。"]'),
('29f92733-7bcd-4c07-8a55-ce4742fcc09f','酬周少隠贈行之什','王之道','宋','宋诗','song-poetry','','[]','我老無知獨夢魚，清風一枕午鐘餘。',64,'全唐诗/poet.song.104000.json','["我老無知獨夢魚，清風一枕午鐘餘。", "忽驚珠玉情相厚，便覺山林計不疏。", "酒熟會看延客醉，詩成還復遣兒書。", "何人竟得閒中趣，只恐無聊歎索居。"]'),
('6ac25107-4cbb-4a0e-ba21-2aa7be6d1aff','酬張進彦見寄','王之道','宋','宋诗','song-poetry','','[]','皇華應記去年曾，六轡馳驅問固陵。',64,'全唐诗/poet.song.104000.json','["皇華應記去年曾，六轡馳驅問固陵。", "道路向來荒枳棘，隄封從昔錯溝塍。", "烟銷列嶂秋光遠，木落長淮霽色澄。", "自笑壯心窮未已，欲言言大怕人憎。"]'),
('b9a5ec79-6db6-4348-87f1-4b147b5d8bd5','酬吕公季','王之道','宋','宋诗','song-poetry','','[]','相逢賓戯快逢場，何幸輕投得夜光。',64,'全唐诗/poet.song.104000.json','["相逢賓戯快逢場，何幸輕投得夜光。", "半面向懷精舍舊，一行今整漢陽裝。", "如君俊逸猶沉滯，顧我迂疏合退藏。", "别乘未來霜候冷，客燈明滅漏聲長。"]'),
('378550a1-e425-47a9-a947-d7bbcb983088','酬蘄春王宰公眀','王之道','宋','宋诗','song-poetry','','[]','致身華貫屬華年，顧我駑痾久不前。',64,'全唐诗/poet.song.104000.json','["致身華貫屬華年，顧我駑痾久不前。", "醉被長官輕罵鄭，懶從學子競嘲邉。", "功名有日還三傑，詩酒何人繼八仙。", "才業似君真獨步，文章政事盡堪傳。"]'),
('eb4771bc-1f21-4997-8eac-0eb8777fadee','和趙養正春日遊魏園','王之道','宋','宋诗','song-poetry','','[]','藜杖芒鞋信脚行，宿雲披絮雨初晴。',64,'全唐诗/poet.song.104000.json','["藜杖芒鞋信脚行，宿雲披絮雨初晴。", "溪邉草色青氈合，竹外山光翠盖横。", "弱柳弄閒無限思，小桃含笑不勝情。", "清眀此去旬餘日，花底能尋載酒盟。"]'),
('a83f5a07-d64a-4b54-ad92-92be657e062b','和孫延壽喜雨述懷韵','王之道','宋','宋诗','song-poetry','','[]','小雨霏霏夜接朝，乍驚和氣入民謠。',64,'全唐诗/poet.song.104000.json','["小雨霏霏夜接朝，乍驚和氣入民謠。", "官逋庶爲麥秋緩，酒價定隨人意饒。", "欲落棗花蠶斷繭，半黄梅子稻移苖。", "書生不慣征徭苦，牢落僧房不自聊。"]'),
('a24b27f7-96cf-4764-afee-96df44592971','寄别江茂德赴麻城丞二首','王之道','宋','宋诗','song-poetry','','[]','此行何處有淹留，新得中郎萬斛舟。',64,'全唐诗/poet.song.104000.json','["此行何處有淹留，新得中郎萬斛舟。", "會見馬群空冀野，還同鶴駕到揚州。", "鱸魚出網紅翻錦，江水浮山綠潑油。", "回首風檣惜輕别，一聲鴻雁起滄洲。"]'),
('020c81a8-7ab6-4607-9c48-5e8ff141d048','次韵周運判彦約芍藥','王之道','宋','宋诗','song-poetry','','[]','獨殿群芳占晚春，對花猶幸有斯人。',64,'全唐诗/poet.song.104000.json','["獨殿群芳占晚春，對花猶幸有斯人。", "宓妃正自須曹賦，楚女何妨與宋鄰。", "醉著午風濃似酒，粧融朝雨細如塵。", "邉城正藉詩書帥，爼豆於今識祭遵。"]'),
('0acb967e-0eff-45f1-b7a1-e58d21a04829','次韵蔡永叔雙頭芍藥','王之道','宋','宋诗','song-poetry','','[]','反復新詩對月華，視模猶及正而葩。',64,'全唐诗/poet.song.104000.json','["反復新詩對月華，視模猶及正而葩。", "坐馳芍藥心先醉，身老江湖眼欲花。", "夜半已酬連理約，風前還見一枝斜。", "灘頭更下雙鸂鶒，併與妖紅作意誇。"]'),
('447bab7d-2468-4ae2-b3e5-ad0eae4e5044','和方正叔芍藥','王之道','宋','宋诗','song-poetry','','[]','院落青和晝漏長，曲欄高檻倚新粧。',64,'全唐诗/poet.song.104000.json','["院落青和晝漏長，曲欄高檻倚新粧。", "未饒玉蘂來仙女，那羡蓮花似阿郎。", "遣興勉從吾輩在，追歡難入少年場。", "開緘忽得驚人句，滿紙雲烟翰墨香。"]'),
('ec62197f-1b7a-4e71-9b9e-865792606c03','夜聽劉昭遠彈琴','王之道','宋','宋诗','song-poetry','','[]','河陰高轉月光流，露脚斜飛夜氣收。',64,'全唐诗/poet.song.104000.json','["河陰高轉月光流，露脚斜飛夜氣收。", "焦尾冷含三尺水，悲風彈破一庭秋。", "廣陵别後多新操，子敬亡來絕舊遊。", "欲洗世間筝笛耳，爲言干斛不須求。"]'),
('5466cce9-4e4c-41f6-8643-f7089c6decc1','和江和仲司理喜雨','王之道','宋','宋诗','song-poetry','','[]','朝來虹影散青紅，旱氣旋隨夜雨空。',64,'全唐诗/poet.song.104000.json','["朝來虹影散青紅，旱氣旋隨夜雨空。", "頏頡競看飛石燕，蠉蠕應快洗桃蟲。", "舊聞人說天心觧，今見時和歲事豐。", "五穀穣穣無幾日，敢將豚酒謝穹窿。"]'),
('80fa1138-bdc4-4215-ba5c-f1d8137648ae','紫薇花','王之道','宋','宋诗','song-poetry','','[]','過盡紅薇到紫薇，廣庭高檻見芳菲。',64,'全唐诗/poet.song.104000.json','["過盡紅薇到紫薇，廣庭高檻見芳菲。", "繽紛不逐槐花落，拂掠應從燕子飛。", "枝壓畫簷朝露重，影揺苔砌午風微。", "何當草詔絲綸閣，伴我黄昏坐禁闈。"]'),
('d94061f2-5ed5-43c7-b849-f0480035b91e','春雪','王之道','宋','宋诗','song-poetry','','[]','一夜春寒夢寐清，柳梢梅萼頗闗情。',64,'全唐诗/poet.song.104000.json','["一夜春寒夢寐清，柳梢梅萼頗闗情。", "山川千里玉爲路，樓觀半天雲滿城。", "徑醉已從釃酒去，稍晴當辦出郊行。", "東君底事偏芳草，剗盡依然上砌生。"]'),
('501c3103-b0f3-4664-8467-e2665a1816a7','立春日雪和趙端質韵','王之道','宋','宋诗','song-poetry','','[]','春寒有信不踰期，肯爲衰顔獨見欺。',64,'全唐诗/poet.song.104000.json','["春寒有信不踰期，肯爲衰顔獨見欺。", "白雪已輸梅鬬早，綠樽尤與火相宜。", "擷來野蔌和萱草，分得江魚貫柳枝。", "刺史憂民民共樂，賽牛歸去競褰帷。"]'),
('c6e3eee6-c6f2-4f57-94cf-944f766dcb17','次韵何子應大卿喜雪武昌作','王之道','宋','宋诗','song-poetry','','[]','雲氣浮江不見邉，擁爐吟雪思飄然。',64,'全唐诗/poet.song.104000.json','["雲氣浮江不見邉，擁爐吟雪思飄然。", "風將急霰先鳴瓦，水剪寒花忽際天。", "才澁敢陪梁苑客，興來從泛剡溪船。", "將軍乘夜平淮蔡，翻笑元和十二年。"]'),
('d735cc70-833b-49e8-a52a-4b85a7a154f1','哀周然明','王之道','宋','宋诗','song-poetry','','[]','三薦渠能老一儒，班超投筆好從吾。',64,'全唐诗/poet.song.104000.json','["三薦渠能老一儒，班超投筆好從吾。", "功名到手身先死，詩禮傳家道不孤。", "千里新封從馬鬛，百年餘慶萃鵷雛。", "西風哀挽桐川上，儻有青芻致奠無。"]'),
('77bfca32-85a5-4f93-8264-d2973ced6aca','魏道弼父挽詞代曾子修','王之道','宋','宋诗','song-poetry','','[]','德邵年高冠里閭，慶餘猶及魏公舒。',64,'全唐诗/poet.song.104000.json','["德邵年高冠里閭，慶餘猶及魏公舒。", "似聞白鶴歸華表，應有青芻奠故廬。", "帝夢漫驚虞澗築，史占空歎渭濱漁。", "泫然東望無從涕，莫厠邦人會葬車。"]'),
('b353e5f9-dd00-4497-98f6-a1cd7b3072db','次韵元發弟秋日德餘庵書事二首  其一','王之道','宋','宋诗','song-poetry','','[]','飽諳世事轉疏慵，投老猶能向佛宫。',64,'全唐诗/poet.song.104000.json','["飽諳世事轉疏慵，投老猶能向佛宫。", "危坐遂移桑蔭日，清談仍對菊花風。", "凴君爲我追歡伯，自此游山作醉翁。", "聞說秋來足佳句，暮歸應念錦囊空。"]'),
('7a6a8e19-6575-443d-9a88-8606bc4b7c71','次韵元發弟秋日德餘庵書事二首  其二','王之道','宋','宋诗','song-poetry','','[]','十載江湖歎斷蓬，夢魂時到帝王宫。',64,'全唐诗/poet.song.104000.json','["十載江湖歎斷蓬，夢魂時到帝王宫。", "珠簾高捲蝦鬚日，寶扇斜開雉尾宫。", "勿誚趙堯刀筆吏，須憐竇鞏囁嚅翁。", "兒童來告黄花熟，可喜樽中酒不空。"]'),
('b3872ea2-b1b4-4702-a4ee-8beff22985c6','和戴禹功水雲館留題','王之道','宋','宋诗','song-poetry','','[]','兵火間闗我爾同，相逢聊喜話怱怱。',64,'全唐诗/poet.song.104000.json','["兵火間闗我爾同，相逢聊喜話怱怱。", "山長不礙飛雲去，江漲應從遠水通。", "白鷺晚潮初浸脚，雨花遺址正横空。", "臨風遐想成惆悵，千古興亡一局終。"]'),
('dc2067ef-1d44-4e1c-bf83-55832137f2e6','和秦壽之題天祚宫','王之道','宋','宋诗','song-poetry','','[]','洞天無際復無旁，喬木梢雲十萬章。',64,'全唐诗/poet.song.104000.json','["洞天無際復無旁，喬木梢雲十萬章。", "身外軒裳誰繫綰，壺中日月自舒長。", "平生塵垢煩三沐，投老功名笑五漿。", "白鹿青牛今在否，一聲秋磬上寥陽。"]'),
('995c4174-1340-48bc-b961-a75e046bec62','題浮光丘家山寺','王之道','宋','宋诗','song-poetry','','[]','古寺鐘鳴漏向殘，馬嘶人起束征鞍。',64,'全唐诗/poet.song.104000.json','["古寺鐘鳴漏向殘，馬嘶人起束征鞍。", "曈曨半弄陰晴日，栗烈初迎小大寒。", "溪水斷流寒凍合，野田飛燒曉霜乾。", "嗟予老踏浮光路，陟岵懷親眼欲酸。"]'),
('133ef69a-bef3-4fc4-b4d5-dfc72a7a5b81','次韵秦壽之題四祖','王之道','宋','宋诗','song-poetry','','[]','古木參天翠作堆，雲中石棧爲誰開。',64,'全唐诗/poet.song.104000.json','["古木參天翠作堆，雲中石棧爲誰開。", "樓臺正倚雙峰起，香火曾瞻四祖來。", "霜重静聞秋子落，風高愁聽曉猿哀。", "當年松上花何似，五葉依然映紫苔。"]'),
('628a2757-f5e6-4e10-bedd-f1ea36999acb','次韵秦壽之題五祖','王之道','宋','宋诗','song-poetry','','[]','栽花傳法總吾身，生滅無煩取次論。',64,'全唐诗/poet.song.104000.json','["栽花傳法總吾身，生滅無煩取次論。", "一夢儻從今日覺，群峰應許此山尊。", "塔中相好如來具，手裏衣盂達磨存。", "若遇小兒宜借問，性華何處更尋根。"]'),
('d662ba38-3724-4af3-ac95-ce3705432c6c','題四祖山瀑泉亭','王之道','宋','宋诗','song-poetry','','[]','雲影曈曨雨弄晴，山頭小立聽溪聲。',64,'全唐诗/poet.song.104000.json','["雲影曈曨雨弄晴，山頭小立聽溪聲。", "不驚赤日雷霆吼，但怪青天雪雹鳴。", "氣逼衣裳秋暑薄，光揺林藪午風輕。", "法身清浄元無垢，何用臨流更濯纓。"]'),
('55f77d1b-57d9-41b7-9cfd-44e118a6e6b5','贈五祖山浄老','王之道','宋','宋诗','song-poetry','','[]','欲知祖意路堂堂，滿目湖山自放光。',64,'全唐诗/poet.song.104000.json','["欲知祖意路堂堂，滿目湖山自放光。", "林湧亂雲迎馬足，峰迴荒磴上羊腸。", "心花肯逐春同老，法雨何妨歲用康。", "試向樵夫問端的，白蓮生處是吾鄉。"]'),
('6bb0c90e-ddb8-4d0b-99f6-db610dc80cd1','贈古若之上人','王之道','宋','宋诗','song-poetry','','[]','灔潭澄碧見師心，我欲窮源何處尋。',64,'全唐诗/poet.song.104000.json','["灔潭澄碧見師心，我欲窮源何處尋。", "萬壑松風酬夜諷，一犁花雨發春吟。", "不妨契闊三年别，卻得留連數日陰。", "竹外小桃開也未，靈雲應已久披襟。"]'),
('504b6b82-a63a-49c6-a0ac-062a690c2232','送浮屠曇遠歸無爲持鉢','王之道','宋','宋诗','song-poetry','','[]','一笻春色滿郊畿，弹指淮南迅若飛。',64,'全唐诗/poet.song.104000.json','["一笻春色滿郊畿，弹指淮南迅若飛。", "丈室正須香積供，孤雲聊作故山歸。", "長安城裏風烟好，錦繡溪頭筍蕨肥。", "我有上林桃李約，未容隨子赴親闈。"]'),
('8687f01e-8e53-4ccc-8e9f-fe118156726c','宿吉祥寺贈應上人','王之道','宋','宋诗','song-poetry','','[]','窗前脩竹翠摩雲，清閟題軒念昔人。',64,'全唐诗/poet.song.104000.json','["窗前脩竹翠摩雲，清閟題軒念昔人。", "三紀重來驚隔世，一言相契定前因。", "携尊得得紛親友，抉藕纍纍萃里民。", "祖意如來煩指似，迷舟何幸濟通津。"]'),
('e4f5304a-8c0b-4b6a-b8b1-60fd5d9ae76f','雨中宿竹林寺謝尉仁父見訪','王之道','宋','宋诗','song-poetry','','[]','幽人好客不嫌紆，带水拖泥辱顧予。',64,'全唐诗/poet.song.104000.json','["幽人好客不嫌紆，带水拖泥辱顧予。", "僧舍頓驚樽有酒，旅庖那患食無魚。", "敢辭數里來相遇，要使它時付特書。", "新竹茂林中掃逕，一甌春雪少躊躇。"]'),
('fbf70a5e-e552-4936-aded-aa87744a96c1','示隠静恭老','王之道','宋','宋诗','song-poetry','','[]','游山何敢避泥塗，恰值催花夜雨餘。',64,'全唐诗/poet.song.104000.json','["游山何敢避泥塗，恰值催花夜雨餘。", "杯渡已知無用楫，馬行今信不更車。", "數聲幽鳥過庭際，一派飛泉赴壑初。", "正欲尋師問心法，卻驚行色逼鐘魚。"]'),
('627ca0b9-24d0-4bef-8b05-3e3a8248da5b','送懿上人持鉢潜川','王之道','宋','宋诗','song-poetry','','[]','坐覺青山忽上心，着鞭來欲故人尋。',64,'全唐诗/poet.song.104000.json','["坐覺青山忽上心，着鞭來欲故人尋。", "萬松未放孤雲過，一飯共聽幽鳥鳴。", "莫厭崎嶇窮野徑，須憐料峭結春陰。", "潜川耆舊如相問，千里長同月一襟。"]'),
('3de0e57e-8e3d-4484-a7e8-fffbd1c90a40','横枝山北别懿上人','王之道','宋','宋诗','song-poetry','','[]','青山終是慰人心，到處相逢不用尋。',64,'全唐诗/poet.song.104000.json','["青山終是慰人心，到處相逢不用尋。", "顧我未能忘楚些，因君聊復效吳吟。", "遥林入眼增雙碧，羸馬奔家競寸陰。", "何事横枝送南北，他年同此記分襟。"]'),
('8b64129f-2751-462d-a200-a83608e62ec4','因上人訪予相山夜聞二子誦書有詩次韵','王之道','宋','宋诗','song-poetry','','[]','杖錫東來意亦勤，寒巖枯木自相親。',64,'全唐诗/poet.song.104000.json','["杖錫東來意亦勤，寒巖枯木自相親。", "方驚妙論雨侵坐，忽喜新詩光照人。", "物外交遊清似水，夢中憂患碎如塵。", "兒童正欲承礱錯，應覺臨文便有神。"]'),
('a17a67e9-3af9-4bb8-86da-ad01b4427640','還通上人卷','王之道','宋','宋诗','song-poetry','','[]','格清詞苦與誰論，携繞錢塘給事墳。',64,'全唐诗/poet.song.104000.json','["格清詞苦與誰論，携繞錢塘給事墳。", "所得豈容人繼和，朗吟應被鶴聽聞。", "月輪冷照千巖雪，霞片輕裝萬疊雲。", "投向吾廬卜知己，擬將詩草爲師焚。"]'),
('59e09340-b2d5-463c-82f7-e8232cc4b6ea','次韵和朗公見贈','王之道','宋','宋诗','song-poetry','','[]','朗公垂老尚吟詩，曾泛三湘看九嶷。',64,'全唐诗/poet.song.104000.json','["朗公垂老尚吟詩，曾泛三湘看九嶷。", "欲問勞生心擾擾，强酬佳句思遲遲。", "紅塵策馬殊無味，碧杖移僧自合宜。", "共待中條山有雪，寺樓吟望更同誰。"]'),
('510312de-5b71-4c0d-ab67-03d416a1d897','贈省欽','王之道','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','舊隠何年别翠微，瀑泉聲外鏁禪扉。',64,'全唐诗/poet.song.104000.json','["舊隠何年别翠微，瀑泉聲外鏁禪扉。", "御前曾寫八分字，天上特宣三事衣。", "燈照夜庵霜後冷，鼎烹秋菌雨中肥。", "終歸五老峰邉去，杯渡長江一錫飛。"]'),
('d7f6b108-8882-434f-86cb-b3fa5bf33c91','和因上人三首  其一','王之道','宋','宋诗','song-poetry','','[]','一抨蘭若復誰家，坐見羲和下日車。',64,'全唐诗/poet.song.104000.json','["一抨蘭若復誰家，坐見羲和下日車。", "燥吻未濡蓮社酒，枯腸空攪玉川茶。", "揺風綠竹初飜籜，過雨紅葵甚放花。", "得句至今頻示我，安能鬰鬰久兹耶。"]'),
('3251c2cf-0d63-4e1a-85e9-06ad4fded854','和因上人三首  其二','王之道','宋','宋诗','song-poetry','','[]','歸騎何時遂到家，蒼頭獵獵走風車。',64,'全唐诗/poet.song.104000.json','["歸騎何時遂到家，蒼頭獵獵走風車。", "醜妻終勝長爲客，薄酒能無更飲茶。", "夢斷北窗凉似水，望中南畆雨飛花。", "采蓮遊女應相識，早晚扁舟訪若耶。"]'),
('7a7a5d7c-3037-4563-bcb4-c7f5cc9de2b1','和因上人三首  其三','王之道','宋','宋诗','song-poetry','','[]','白雲飛處是吾家，石眼泠泠水一車。',64,'全唐诗/poet.song.104000.json','["白雲飛處是吾家，石眼泠泠水一車。", "醉日到來應種竹，梅時過盡好藏茶。", "遥憐壺棗初成實，似說占禾半吐花。", "已得伽陀微妙句，歸歟香火諷囉耶。"]'),
('fa047b10-618e-4d71-830a-7a27fb3413fa','贈朗上人','王之道','宋','宋诗','song-poetry','','[]','净剃霜髭展舊真，自疑容貌是前身。',64,'全唐诗/poet.song.104000.json','["净剃霜髭展舊真，自疑容貌是前身。", "僧中獨守三千戒，詩裏閒銷七十春。", "僻寺蘚深人到少，故山雲好夢歸頻。", "禪齋近日誰還往，祇有西垣放逐臣。"]'),
('f2fb6fcd-05c3-4a8c-95a7-e423778064c6','贈贊寧大師','王之道','宋','宋诗','song-poetry','','[]','詔修僧史浙江濱，萬卷書中老一身。',64,'全唐诗/poet.song.104000.json','["詔修僧史浙江濱，萬卷書中老一身。", "赴闕尚留支遁馬，援毫應待仲尼麟。", "溟濛雪影松窗曉，狼籍苔花竹院春。", "還許幽齋暫相訪，卻慙陶令滿衣塵。"]'),
('9221f276-e48c-4c2d-bb49-d7214d7031f9','朗上人見訪復謁不遇留刺而還有詩見謝依韵和答','王之道','宋','宋诗','song-poetry','','[]','湯休訪我我重尋，獨叩松闗絕好音。',64,'全唐诗/poet.song.104000.json','["湯休訪我我重尋，獨叩松闗絕好音。", "滿袖塵埃回俗步，一鑪香火隔禪林。", "偶留刺字情非淺，忽枉詩章思更深。", "猶喜謫官無吏役，往來從此伴閒吟。"]'),
('66ef0662-d9a3-4418-ac96-eeeceb476bbe','贈遇公上人','王之道','宋','宋诗','song-poetry','','[]','卧雲衣服半斕斑，吳越烟蘿舊往還。',64,'全唐诗/poet.song.104000.json','["卧雲衣服半斕斑，吳越烟蘿舊往還。", "幾度看濤羅刹石，經年尋藥武夷山。", "剃髭刃澁秋窗冷，補衲燈微夜榻閒。", "應笑勞生苦多事，槐花時節入秦闗。"]'),
('a8a9360f-6adb-47d0-ab82-31d94d9ad412','寄贊寧上人','王之道','宋','宋诗','song-poetry','','[]','支公兼有董狐才，史傳修成乙夜開。',64,'全唐诗/poet.song.104000.json','["支公兼有董狐才，史傳修成乙夜開。", "天子遠酬丹詔去，高僧不出白雲來。", "眉毫久别應垂雪，心印休傳本似灰。", "若念重瞳欲相見，未妨西上一浮杯。"]'),
('ca638dfa-02aa-46fa-998a-8fd452a01281','和天寧因上人次韵','王之道','宋','宋诗','song-poetry','','[]','日月漂流一鳥過，别來心迹病維摩。',64,'全唐诗/poet.song.104000.json','["日月漂流一鳥過，别來心迹病維摩。", "是非孰辨聊分謗，誕信相譏要止訛。", "揺落獨憐松不改，澄清嘗見海無波。", "句中有眼勞開警，更問諸人會得麽。"]'),
('c576f27a-3f1b-40a2-ab41-2a9ca98708c7','和褒山因老二首  其一','王之道','宋','宋诗','song-poetry','','[]','湖上逢師又到家，别來詩句好相誇。',64,'全唐诗/poet.song.104000.json','["湖上逢師又到家，别來詩句好相誇。", "休嗟晚菊今迷草，且喜寒梅欲放花。", "丈室香温巖寶坐，將壇風軟擁高牙。", "相思對雪酬珠玉，不覺茅簷送月華。"]'),
('30d055e3-4aad-47cb-86dc-065f8caa8e59','和褒山因老二首  其二','王之道','宋','宋诗','song-poetry','','[]','島可文章似出家，不將言語落浮誇。',64,'全唐诗/poet.song.104000.json','["島可文章似出家，不將言語落浮誇。", "雪中令我思風絮，天上因君合雨花。", "一炷飛烟雲天矯，數行佳樹玉槎牙。", "山高殊覺青霄近，捫虱南窗向日華。"]'),
('34136ef1-895b-4c2b-9890-e50644f978e0','次韵因上人謝徐守遺顧渚茶','王之道','宋','宋诗','song-poetry','','[]','相從聊罷致書郵，情寄詩筒早晚休。',64,'全唐诗/poet.song.104000.json','["相從聊罷致書郵，情寄詩筒早晚休。", "顧我未忘童子好，評君還向古人求。", "緗奩啟處雲英馥，石鼎煎來雪浪浮。", "多謝徐卿分顧渚，報之瓊玖兩相收。"]'),
('10f8df97-5226-452b-9c42-882d1b3062c5','送趙端質歸朝','王之道','宋','宋诗','song-poetry','','[]','聖治中興日，宗藩第一流。',144,'全唐诗/poet.song.104000.json','["聖治中興日，宗藩第一流。", "九重資共理，三載頼分憂。", "昨日交符虎，當時競带牛。", "咄嗟成藥石，談笑獲鋤耰。", "善政稱無擾，罷民遂有瘳。", "教風興子弟，膏澤被田疇。", "士論高强漢，王功繼屏周。", "外臺書課最，禁從表才猷。", "往矣登青瑣，宜哉建碧油。", "瘡痍爭借寇，憔悴獨依劉。", "我願攀鱗進，人思卧轍留。", "是行端可喜，名姓在金甌。"]'),
('cf0d0a06-1dc3-415d-9719-4028738430fe','過富池題澄江閣二首  其一','王之道','宋','宋诗','song-poetry','','[]','晚日千峰色，秋風萬里情。',72,'全唐诗/poet.song.104000.json','["晚日千峰色，秋風萬里情。", "望雲雙目眩，渇雨寸心傾。", "有客詩方就，何人笛正横。", "渚烟縈别浦，江月動前楹。", "草木腥猶在，生靈痛未平。", "傷哉一杯酒，北向酹邉城。"]'),
('4ee0b0d9-854d-4518-bd3e-8b24cfbd008a','過富池題澄江閣二首  其二','王之道','宋','宋诗','song-poetry','','[]','江山南北限，風月古今情。',72,'全唐诗/poet.song.104000.json','["江山南北限，風月古今情。", "舉酒杯還覆，逢人盖暫傾。", "目窮飛鳥落，心逐斷雲横。", "小市支殘屋，嚴祠列畫楹。", "晚烟漁艇遠，夏潦荻洲平。", "試問濡須路，歸歟過幾城。"]'),
('d4a307b8-4ae7-4c4c-8391-e8cbb10c9cf0','次韵劉春卿書懷','王之道','宋','宋诗','song-poetry','','[]','老去宜安分，年來强競辰。',288,'全唐诗/poet.song.104000.json','["老去宜安分，年來强競辰。", "功名雖自許，心腹欲誰陳。", "頼有金谿彦，相從錦水濵。", "詞華三鳯蔚，詩律八音純。", "風月論交舊，雲山發興新。", "鄙懷煩澡雪，高義歎傾囷。", "李嶠真才子，唐邕實異人。", "感時悲鶴戰，憂國賦車轔。", "寤寐思摧敵，行藏冀澤民。", "廉高辭鄭粟，狂笑取韓銀。", "松柏迷荆棘，琳琅雜珷珉。", "北游觀赤幘，西走避黄巾。", "端木謀存魯，長沙論過秦。", "江湖雙醉眼，天地一閒身。", "遵海嗟黄屋，垂衣想紫宸。", "擒王須李靖，抗賊付張巡。", "尚緩三城役，方馳六轡詢。", "兩河蜂伴蟻，多壘介和鱗。", "烽火青淮隔，樓船古汴堙。", "離宫埋茂草，禁籞掩荒榛。", "典冊尊諸夏，戎羌守四鄰。", "如何來醜類，容易破重闉。", "大厦煙焚突，長堤蟻潰漘。", "複垣閶闔夜，層觀景龍春。"]'),
('01033c53-210a-4d27-bc5c-47ae920d01bb','追和韓退之雪韵','王之道','宋','宋诗','song-poetry','','[]','一時符衆望，七尺騐童謠。',120,'全唐诗/poet.song.104000.json','["一時符衆望，七尺騐童謠。", "人喜豐穰兆，吾知瘴癘銷。", "戲看還撲面，閒試欲齊腰。", "堕絮紛辭萼，飛花半惹條。", "松篁低到地，溪澗合平橋。", "月牖潜争入，風簾静自揺。", "紅金延坐夜，綠蟻送行朝。", "暗上歌茵隰，輕随舞袖飄。", "千林翻魯縞，萬里藉鮫綃。", "燈市堪行樂，何妨酒價饒。"]'),
('aca1b3d6-7c4d-4c27-bedf-37a87f07a55a','菊有黄花爲彦逢弟壽','王之道','宋','宋诗','song-poetry','','[]','正色憎桃李，凌霜見嫩黄。',72,'全唐诗/poet.song.104000.json','["正色憎桃李，凌霜見嫩黄。", "有同高士操，常占晚秋芳。", "裊裊金風軟，漙漙玉露光。", "君恩隆一束，時令應重陽。", "幸遇桑蓬慶，欣逢麴米香。", "敢因難老祝，採掇奉瑶觴。"]'),
('cbeca073-de85-4abb-9735-a688160db68d','春雪和袁望囘三首  其一','王之道','宋','宋诗','song-poetry','','[]','殘歲連人日，同雲暗海涯。',120,'全唐诗/poet.song.104000.json','["殘歲連人日，同雲暗海涯。", "晨開才曭晃，暮集復交加。", "野色鋪霜縞，秋光散玉葩。", "老夫僵不掃，稚子走争拿。", "皎潔欺梅萼，嚴凝禁草芽。", "餓彪迷舊穴，驚雁失圓沙。", "有客方誇酒，何人欲鬬茶。", "南山歌禹甸，西國想毗耶。", "弄日烏薪熟，圍風翠幙遮。", "豈知春霽好，萬物動芳華。"]'),
('76b14bad-1137-4bfa-a3f9-5dfe5c036ded','春雪和袁望囘三首  其二','王之道','宋','宋诗','song-poetry','','[]','誰謂過殘臘，餘寒遂有涯。',120,'全唐诗/poet.song.104000.json','["誰謂過殘臘，餘寒遂有涯。", "雪來風益横，冰着雨還加。", "萬里隋堤絮，千山庾嶺葩。", "袁門晨尚閉，剡艇夜應拿。", "百蟄猶含土，群芳敢放芽。", "嬌紅還玉茗，新綠借金沙。", "力勝榴花酒，功高雀舌茶。", "人心愁甚矣，天意欲何耶。", "好放朝陽出，休從宿霧遮。", "青腰誠念我，明日變霜華。"]'),
('91b21d81-67c0-4a9b-84e0-a2cfcee76857','春雪和袁望囘三首  其三','王之道','宋','宋诗','song-poetry','','[]','稜稜威正肅，浩浩意無涯。',120,'全唐诗/poet.song.104000.json','["稜稜威正肅，浩浩意無涯。", "雨息風還怒，霜餘雪更加。", "氍毺還席地，薝蔔競分葩。", "虎餓豺狼摶，烏窮鳥雀拿。", "木冰鳴玉佩，簷溜軋蘆芽。", "鶴集疑驚露，羊群憶卧沙。", "晚餐甘當肉，夘酒薄勝茶。", "盈尺其多矣，踰旬果是耶。", "日車行自駕，雲障欲何遮。", "坐想傳柑飲，千官從翠華。"]'),
('221ce8d7-65e1-48f4-99a4-8f3dad782afb','和袁望回春雪','王之道','宋','宋诗','song-poetry','','[]','白雪嫌春晚，縱横布玉霙。',120,'全唐诗/poet.song.104000.json','["白雪嫌春晚，縱横布玉霙。", "柳花隨處發，瑶砌逐門成。", "旌别寒松茂，摧殘凍芋萌。", "飄颻無限思，料峭有餘清。", "舞袂朝猶濕，吟窗夜自明。", "色疑侵兩鬢，光欲眩雙睛。", "曭晃干林曉，潺湲萬壑晴。", "江梅含故態，山鳥弄新聲。", "雅與詩情惬，應憐病骨輕。", "澆腸一杯酒，風力鬬峥嶸。"]'),
('8780b123-fe5d-43ce-93f5-22b42a795655','對雪和子𨗨用歐陽子韵','王之道','宋','宋诗','song-poetry','','[]','散漫來天際，高吟正倚門。',120,'全唐诗/poet.song.104000.json','["散漫來天際，高吟正倚門。", "遠山雲母合，芳樹柳花繁。", "匝地銀無價，冰湖鑑有痕。", "何人穿敝履，有客擁高軒。", "訪戴從東棹，游梁快北轅。", "鼎寒香屢撥，杯冷酒重温。", "風力千林吼，雲容萬騎屯。", "食餘鹽虎卧，坐久炭猊蹲。", "觀舞更三疊，論文罄一樽。", "清芬難揜覆，端的屬梅園。"]'),
('97e5ad4a-8c91-43a8-9699-f33253029d38','送楊德潤赴禮部試','王之道','宋','宋诗','song-poetry','','[]','雨意止還作，天容寒未舒。',72,'全唐诗/poet.song.104000.json','["雨意止還作，天容寒未舒。", "無聊懷劇論，何幸過窮居。", "舉白夜釃酒，剪黄朝薦蔬。", "新詩閒鼔吹，舊隠亂丘墟。", "軒冕時何晚，山林計亦疏。", "中興屈群策，入告莫躊躇。"]'),
('a3dfe3f1-85af-4245-9743-f4aa6b203e6f','追和東坡立春韵寄彦逢弟','王之道','宋','宋诗','song-poetry','','[]','荏苒歲云暮，艱難予豈堪。',72,'全唐诗/poet.song.104000.json','["荏苒歲云暮，艱難予豈堪。", "闗山懷遠别，弓矢廢清談。", "風色霽還暖，梅梢春已酣。", "信音驚遠雁，心緒亂游蠺。", "投筆班超近，擒戎李靖慙。", "行吟望西北，赴難有虞潭。"]'),
('13fd2fc0-bfd8-44ea-b597-6b8be1eb985c','和徐季功墨梅  其一','王之道','宋','宋诗','song-poetry','','[]','閒想窺池倒影，戲成落筆斜枝。',28,'全唐诗/poet.song.104000.json','["閒想窺池倒影，戲成落筆斜枝。", "縱涅難淄玉質，細看何似當時。"]'),
('60c6efe7-fc26-4f03-9320-210f8bf4f87d','和徐季功墨梅  其二','王之道','宋','宋诗','song-poetry','','[]','便是朱唇素面，那知綠葉青枝。',28,'全唐诗/poet.song.104000.json','["便是朱唇素面，那知綠葉青枝。", "浄几明窗展處，微風淡月醒時。"]'),
('7e06b841-667b-4008-a9f3-873afa636f49','題成國仲畫扇','王之道','宋','宋诗','song-poetry','','[]','奮髯欲何爲，戢翼應有待。',24,'全唐诗/poet.song.104000.json','["奮髯欲何爲，戢翼應有待。", "畫工妙丹青，物狀從變態。"]'),
('8d779215-c514-4237-8ad7-1fabfcaba07c','題馬以道畫扇','王之道','宋','宋诗','song-poetry','','[]','寒蘆卧疏黄，遠水分淡碧。',24,'全唐诗/poet.song.104000.json','["寒蘆卧疏黄，遠水分淡碧。", "秋荷如有情，相映兩鸂鶒。"]'),
('18f45619-d28a-4ee3-9491-9e8bbee6eee4','追和魯直蠟梅二首  其一','王之道','宋','宋诗','song-poetry','','[]','一種幽素姿，凌寒爲誰展。',24,'全唐诗/poet.song.104000.json','["一種幽素姿，凌寒爲誰展。", "似嫌冰雪清，故作黄金淺。"]'),
('7a252fcf-0b43-4f25-a686-2b8c7de54d3e','追和魯直蠟梅二首  其二','王之道','宋','宋诗','song-poetry','','[]','歲窮壓霜雪，春至喜風露。',24,'全唐诗/poet.song.104000.json','["歲窮壓霜雪，春至喜風露。", "一枝蠟花梅，清香美無度。"]'),
('a7f83c75-015b-4dbe-84d5-be891fe6f183','送道者史寶通作丐','王之道','宋','宋诗','song-poetry','','[]','昔日山前寺，兵餘掃地空。',24,'全唐诗/poet.song.104000.json','["昔日山前寺，兵餘掃地空。", "汝今能協力，真是寶林通。"]'),
('36bb5bb3-a90b-4281-bf72-a2463d13fddf','又送道者王法圓作丐','王之道','宋','宋诗','song-poetry','','[]','誓將三寸舌，求結萬人緣。',24,'全唐诗/poet.song.104000.json','["誓將三寸舌，求結萬人緣。", "寶刹成功日，當期道法圓。"]'),
('6675d6a6-96d1-44cb-b586-bda1605b75b0','送浮屠道廓','王之道','宋','宋诗','song-poetry','','[]','一宿已先覺，四明那更遊。',24,'全唐诗/poet.song.104000.json','["一宿已先覺，四明那更遊。", "去來無所着，風日海山秋。"]'),
('99828df4-dab2-4098-89b5-e404d053d1b4','送賈教授偉滿罷東歸','王之道','宋','宋诗','song-poetry','','[]','妙年才氣擅超群，試吏來司泮水芹。',32,'全唐诗/poet.song.104000.json','["妙年才氣擅超群，試吏來司泮水芹。", "行矣玉堂應召直，忍將風袂與君分。"]'),
('282ed3e9-be89-47e7-8fc0-269baf97952c','重陽示二三友','王之道','宋','宋诗','song-poetry','','[]','龍山何處暮雲黄，坐想前賢落帽狂。',32,'全唐诗/poet.song.104000.json','["龍山何處暮雲黄，坐想前賢落帽狂。", "茰實菊花良不惡，爲君沽酒作重陽。"]'),
('e8122876-f5df-4b69-8a17-3c5f53f738cb','秋日憫旱題香山莊舍','王之道','宋','宋诗','song-poetry','','[]','千里驕陽稼穡枯，人心窮極但天呼。',32,'全唐诗/poet.song.104000.json','["千里驕陽稼穡枯，人心窮極但天呼。", "須煩巖壑爲霖手，下澤蒼生慰海隅。"]'),
('97eaa3c2-8c3c-4a48-bd43-0fc0a150f583','寄梅花與曾子修','王之道','宋','宋诗','song-poetry','','[]','待船聊復駐征驂，手撚梅花望翠嵐。',32,'全唐诗/poet.song.104000.json','["待船聊復駐征驂，手撚梅花望翠嵐。", "花似若人清絕俗，故從江北寄江南。"]'),
('79e46586-e678-4426-be6b-05a83ba09c57','送曾式古歸建昌','王之道','宋','宋诗','song-poetry','','[]','兩年說歸明日歸，江頭草軟花芬菲。',32,'全唐诗/poet.song.104000.json','["兩年說歸明日歸，江頭草軟花芬菲。", "風調江浄船行駛，好看芳草懷春暉。"]'),
('e7d7bb23-3e10-4086-aec4-3c196c3b47f5','酬孔純老送海錯三首  其一','王之道','宋','宋诗','song-poetry','','[]','海錯東來自四明，感君憐我故分珍。',32,'全唐诗/poet.song.104000.json','["海錯東來自四明，感君憐我故分珍。", "拜嘉何必須豪飲，大嚼姑從得句新。"]'),
('1bf506ba-57fb-49be-8e7f-75f73b71af55','酬孔純老送海錯三首  其二','王之道','宋','宋诗','song-poetry','','[]','螺頭已荷兼三和，鳯髓何須貴八珍。',32,'全唐诗/poet.song.104000.json','["螺頭已荷兼三和，鳯髓何須貴八珍。", "多謝邦君憐不飲，只將詩句巧争新。"]'),
('bed309fc-f6a7-4ea6-8d09-636ffc383057','酬孔純老送海錯三首  其三','王之道','宋','宋诗','song-poetry','','[]','惡語豈堪酬妙句，麤餐曾不饜常珍。',32,'全唐诗/poet.song.104000.json','["惡語豈堪酬妙句，麤餐曾不饜常珍。", "得君海錯俱奇絕，從此鄞江發興新。"]'),
('dba12d74-30e8-4f88-b343-4d7a4c00e515','和子厚弟春日見寄三首  其一','王之道','宋','宋诗','song-poetry','','[]','睡起晴窗正憶渠，老兵聲喏到前除。',32,'全唐诗/poet.song.104000.json','["睡起晴窗正憶渠，老兵聲喏到前除。", "新詩價重連城璧，便覺貧家富不虛。"]'),
('1545c424-134a-4886-8243-6498e6fa589f','和子厚弟春日見寄三首  其二','王之道','宋','宋诗','song-poetry','','[]','一鞭春色去迢迢，溪上紅粧笑語嬌。',32,'全唐诗/poet.song.104000.json','["一鞭春色去迢迢，溪上紅粧笑語嬌。", "酒醉不知行客避，競眠芳草鬬裙腰。"]'),
('f0cac098-d490-476e-ae6d-9a39455d2eec','和子厚弟春日見寄三首  其三','王之道','宋','宋诗','song-poetry','','[]','十里西疇馬送曛，晚風依約度溪雲。',32,'全唐诗/poet.song.104000.json','["十里西疇馬送曛，晚風依約度溪雲。", "懸知今夜桃花雨，一洗焦枯慰使君。"]'),
('8909c420-7b9f-4e86-ac7b-b124962c77f7','謝潘壽卿惠牋并詩','王之道','宋','宋诗','song-poetry','','[]','餉厚東陽一萬畨，從今難放筆頭閒。',32,'全唐诗/poet.song.104000.json','["餉厚東陽一萬畨，從今難放筆頭閒。", "新詩正與花牋似，文彩縱横咳唾間。"]'),
('31b61b5a-c461-453c-ae0f-34c081bf6311','道上雜花盛開','王之道','宋','宋诗','song-poetry','','[]','涓涓流水雨晴初，夾道山花簇綵輿。',32,'全唐诗/poet.song.104000.json','["涓涓流水雨晴初，夾道山花簇綵輿。", "千騎不辭迎候遠，物情春意竟何如。"]'),
('86bdfbbf-5671-4301-b339-6c3614fa44fb','風雨損花','王之道','宋','宋诗','song-poetry','','[]','雨多南國惜春歸，多謝詩人賦采菲。',32,'全唐诗/poet.song.104000.json','["雨多南國惜春歸，多謝詩人賦采菲。", "堕白殘紅無處着，漫隨風絮作團飛。"]'),
('db9483e6-d426-444a-874a-f9cba7353a0c','落梅入硯池','王之道','宋','宋诗','song-poetry','','[]','玉佩翻然下帝傍，墨池照影妬新粧。',32,'全唐诗/poet.song.104000.json','["玉佩翻然下帝傍，墨池照影妬新粧。", "時人莫作飄零看，收拾毫端無盡香。"]'),
('5d5db80f-4fa5-482b-bdaf-2f9c10416455','玉樹花','王之道','宋','宋诗','song-poetry','','[]','幾年埋沒亂荆榛，軒檻移來特地新。',32,'全唐诗/poet.song.104000.json','["幾年埋沒亂荆榛，軒檻移來特地新。", "何事臨風忍相對，傷心一曲舊亡陳。"]'),
('8e692a68-a55f-4007-aa22-938c1eacbd67','芭蕉','王之道','宋','宋诗','song-poetry','','[]','秋風鳴玉雨疏疏，嫩綠臨窗半卷舒。',32,'全唐诗/poet.song.104000.json','["秋風鳴玉雨疏疏，嫩綠臨窗半卷舒。", "似是相知慰牢落，朝來肯寄一緘書。"]'),
