('87eb410e-ce1d-4261-acef-167a4b1de5cb','靜庵山居','李侗','宋','宋诗','song-poetry','','[]','勝如城外宅，花木擁簷前。',48,'全唐诗/poet.song.104000.json','["勝如城外宅，花木擁簷前。", "一雨晚時過，群峰翠色鮮。", "採荆烹白石，接竹引清泉。", "車馬長無到，逍遙樂葛天。"]'),
('7ed2167c-08ea-4eae-97bb-23fbcbab6e52','藏春峽','李侗','宋','宋诗','song-poetry','','[]','咏歸堂裏靜怡神，更步芳亭識趣新。',64,'全唐诗/poet.song.104000.json','["咏歸堂裏靜怡神，更步芳亭識趣新。", "愛竹心虛初長筍，觀梅香散漸含仁。", "雲將膏雨過桐嶺，水泛桃花出劍津。", "生意峽中藏得否，自家收拾滿腔春。"]'),
('b6ab8f65-00ba-4720-9a33-df1fad6f3fe5','碭山懷古','陳剛','宋','宋诗','song-poetry','','[]','山名芒碭勢穹崇，漢祖嚴祠翠靄中。',64,'全唐诗/poet.song.104000.json','["山名芒碭勢穹崇，漢祖嚴祠翠靄中。", "紫氣應時騰碧落，素靈何處泣秋風。", "狐鳴陳涉孤墳壞，金盡梁王石室空。", "畢竟乾坤歸有道，漫誇扛鼎力英雄。"]'),
('298419bd-1d0f-450b-8799-1180a8a1392c','題枯髏圖','馮楫','宋','宋诗','song-poetry','','[]','形骸在此，其人何在。',20,'全唐诗/poet.song.104000.json','["形骸在此，其人何在。", "乃知一靈，不屬皮袋。"]'),
('413e3f5c-bff8-48b2-9e5e-b48442827b03','自詠','馮楫','宋','宋诗','song-poetry','','[]','公事之餘喜坐禪，少曾將脇到床眠。',32,'全唐诗/poet.song.104000.json','["公事之餘喜坐禪，少曾將脇到床眠。", "雖然現出宰官相，長老之名四海傳。"]'),
('ac8c5353-3ee8-4c64-b83b-df691451e219','施經偈','馮楫','宋','宋诗','song-poetry','','[]','我賦躭痂癖，有財貯空虛。',168,'全唐诗/poet.song.104000.json','["我賦躭痂癖，有財貯空虛。", "不作子孫計，不爲車馬速。", "不充玩好用，不買聲色娛。", "置錐無南畝，片瓦無屋廬。", "所得月俸給，唯將贖梵書。", "萬里遣迎介，崎嶇涉長途。", "奉安大剎中，開示諸迷徒。", "庶幾披閱者，咸得入無餘。", "古佛爲半偈，尚乃捨生軀。", "我今以財施，痛楚不侵膚。", "以我較古佛，苦樂萬倍殊。", "所以不惜財，非是稟性愚。", "借問借財人，終日較錙銖。", "無常忽地到，寧免生死無。"]'),
('19bdd55f-48c6-436d-9062-3be63588619f','臨終頌','馮楫','宋','宋诗','song-poetry','','[]','初三十一，中九下七。',20,'全唐诗/poet.song.104000.json','["初三十一，中九下七。", "老人言盡，龜哥眼赤。"]'),
('283c02bd-ef36-49b2-a545-baa238f16d0d','勸諭賑濟詩','馮楫','宋','宋诗','song-poetry','','[]','我朝未第日，鄉間逢歲饑。',252,'全唐诗/poet.song.104000.json','["我朝未第日，鄉間逢歲饑。", "兩率閭里人，相共行賑濟。", "饑民僅得食，免困餓而斃。", "及我登第後，被罪歸田里。", "尋復拜召命，迤邐治行計。", "忽見道途間，小兒有遺棄。", "復自勸鄉邦，割己用施惠。", "日飯八千人，八旬乃休止。", "于時已麥熟，糧食相接濟。", "我始趨行朝，蒙恩長宗寺。", "初本不望報，人以爲能事。", "利司具切奏，還官不容避。", "今年又少歉，我適帥瀘水。", "無戶備飯食，所濟俱用米。", "聊舍三百斛，十中活一二。", "又以一千石，減價平行市。", "每石減十錢，庶幾無湧貴。", "更有不熟處，資簡潼川類。", "計用減價糶，所祈均獲濟。", "我非財有餘，但愍民不易。", "一時所施行，樂爲之識記。"]'),
('9828ae0a-aede-4208-90cd-4441b419487f','迎暉閣','舒清國','宋','宋诗','song-poetry','','[]','藹藹復依依，朝暉以夕暉。',48,'全唐诗/poet.song.104000.json','["藹藹復依依，朝暉以夕暉。", "巖花寒不落，簷鳥靜忘飛。", "僧自眠黄葉，人多夢翠微。", "雲邊時見鹿，飲水近禪扉。"]'),
('1cda122d-5745-4290-9968-57adfc904cf4','頌','釋嗣宗','宋','宋诗','song-poetry','','[]','澗底泥牛金貼面，山頭石女著真紅。',32,'全唐诗/poet.song.104000.json','["澗底泥牛金貼面，山頭石女著真紅。", "繫驢橛上生芝草，不是雲靄香爐峰。"]'),
('61bcac65-3957-467e-b5f7-6c8a4c06a915','偈二首  其一','釋嗣宗','宋','宋诗','song-poetry','','[]','翠巖不是不說，只爲無個季節。',56,'全唐诗/poet.song.104000.json','["翠巖不是不說，只爲無個季節。", "今朝快便難逢，一句爲君剖決。", "露柱本是木頭，秤鎚只是生鐵。", "諸人若到諸方，莫道山僧饒舌。"]'),
('3535be59-e102-4d31-a00a-125e5335f873','偈二首  其二','釋嗣宗','宋','宋诗','song-poetry','','[]','少林坐，庾嶺行，書偈傳衣成戰爭。',64,'全唐诗/poet.song.104000.json','["少林坐，庾嶺行，書偈傳衣成戰爭。", "庾嶺行，少林坐，得髓安心成話墮。", "兩家公案未曾圓，後代兒孫作殃禍。", "這殃禍，可煞大，天下衲僧透不過。"]'),
('f7f72848-ce59-4382-a4b2-fd569a0f089e','頌古三首 虔侍者','釋嗣宗','宋','宋诗','song-poetry','','[]','石人不怕師子吼，須彌頂上翻筋斗。',32,'全唐诗/poet.song.104000.json','["石人不怕師子吼，須彌頂上翻筋斗。", "滄溟竭盡正三更，生鐵崑崙雲外走。"]'),
('12d8913c-1df1-4b06-924e-741f8880a58a','頌古三首 香嚴擊竹','釋嗣宗','宋','宋诗','song-poetry','','[]','粥飯隨時養病軀，本無迷悟可關渠。',32,'全唐诗/poet.song.104000.json','["粥飯隨時養病軀，本無迷悟可關渠。", "無端擊著庵前竹，直至如今在半途。"]'),
('59bd3cd9-1f05-434a-b257-e3632868a30f','頌古三首 二祖得髓','釋嗣宗','宋','宋诗','song-poetry','','[]','弟昆各自逞功能，獨有家兄徹骨貧。',32,'全唐诗/poet.song.104000.json','["弟昆各自逞功能，獨有家兄徹骨貧。", "三拜起來無一語，鼻孔纍垂蓋上脣。"]'),
('dfab28c4-a0dd-473c-bd89-c88f68507ba0','頌古二十六首  其一','釋嗣宗','宋','宋诗','song-poetry','','[]','千年石虎產麒麟，一角通身五彩明。',32,'全唐诗/poet.song.104000.json','["千年石虎產麒麟，一角通身五彩明。", "金鎖玉關渾掣斷，毗盧界內鼓煙塵。"]'),
('087fa10b-6203-4ecf-8a78-5de63a688f42','頌古二十六首  其二','釋嗣宗','宋','宋诗','song-poetry','','[]','一見明星夢便回，千年桃核長青梅。',32,'全唐诗/poet.song.104000.json','["一見明星夢便回，千年桃核長青梅。", "雖然不是調羹味，曾與將軍止渴來。"]'),
('c11ab01c-8637-498b-9b3b-ef57558c1b0d','頌古二十六首  其三','釋嗣宗','宋','宋诗','song-poetry','','[]','過去心不可得，收綸罷釣秋江碧。',109,'全唐诗/poet.song.104000.json','["過去心不可得，收綸罷釣秋江碧。", "扁舟古岸恣閑眠，明月蘆華深穩密。", "現在心不可得，法王家法存今昔。", "謀臣猛將定封疆，說甚隋珠幷趙璧。", "未來心不可得，不可得中只麽得。", "石含玉兮地擎山，惟證乃知難可測。", "千古流芳誰共知，清風帀地有何極。"]'),
('9354ebab-7ded-454a-aee5-00681ba09865','頌古二十六首  其四','釋嗣宗','宋','宋诗','song-poetry','','[]','不是風旛不是心，祖師正眼只如今。',32,'全唐诗/poet.song.104000.json','["不是風旛不是心，祖師正眼只如今。", "如今不識山河礙，識得如今海嶽沉。"]'),
('cb06e126-5b1c-4080-ba56-38d02ebe31ae','頌古二十六首  其五','釋嗣宗','宋','宋诗','song-poetry','','[]','鐵牛耕破洞中天，桃花片片出深源。',32,'全唐诗/poet.song.104000.json','["鐵牛耕破洞中天，桃花片片出深源。", "秦人一去無消息，千古峰巒色轉鮮。"]'),
('affaf1ca-c556-4212-8a4a-4568f6437b07','頌古二十六首  其六','釋嗣宗','宋','宋诗','song-poetry','','[]','鬼子掛起那吒面，赤腳跨定須彌盧。',32,'全唐诗/poet.song.104000.json','["鬼子掛起那吒面，赤腳跨定須彌盧。", "鐵牛鞭起黄河岸，大洋海底食珊瑚。"]'),
('d1224c7f-18d0-457c-9974-fa8ef9a2bf96','頌古二十六首  其七','釋嗣宗','宋','宋诗','song-poetry','','[]','不是心兮不是物，那吒夜入蒼龍窟。',32,'全唐诗/poet.song.104000.json','["不是心兮不是物，那吒夜入蒼龍窟。", "鐵鞭擊碎明月珠，從教大地如翻墨。"]'),
('a5f59661-f8cd-42d0-b4e0-09d9f4a8a91a','頌古二十六首  其八','釋嗣宗','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','石裏藏金誰辨別，遊人但見蘚痕斑。',32,'全唐诗/poet.song.104000.json','["石裏藏金誰辨別，遊人但見蘚痕斑。", "卻被石人窺得破，鐵船載入洞庭山。"]'),
('f0d2be98-b89f-4770-b6d9-94c0566a1256','頌古二十六首  其九','釋嗣宗','宋','宋诗','song-poetry','','[]','妙凈明心，一句全真。',42,'全唐诗/poet.song.104000.json','["妙凈明心，一句全真。", "山河大地，日月星辰。", "舒肝瀝膽，照徹古今。", "個中如不昧，徧界是黄金。"]'),
('9aaf8c1f-76b2-4e00-9f3f-13764e84007a','頌古二十六首  其一○','釋嗣宗','宋','宋诗','song-poetry','','[]','象外橫該宇宙身，聖凡極盡不容塵。',32,'全唐诗/poet.song.104000.json','["象外橫該宇宙身，聖凡極盡不容塵。", "衲僧意氣合如此，當場誰是奪標人。"]'),
('d0aa3e46-7ea6-4c9b-bf95-60a658b482f8','頌古二十六首  其一一','釋嗣宗','宋','宋诗','song-poetry','','[]','婆婆不在五臺山，平地行人作易難。',32,'全唐诗/poet.song.104000.json','["婆婆不在五臺山，平地行人作易難。", "驀直坦然今古路，區區卻過趙州關。"]'),
('0d7efa24-3fb1-4704-87b8-967a5adb1c52','頌古二十六首  其一二','釋嗣宗','宋','宋诗','song-poetry','','[]','一路雄兵犯界河，煙塵塞路絕人過。',32,'全唐诗/poet.song.104000.json','["一路雄兵犯界河，煙塵塞路絕人過。", "安邦賴有張良在，畫角城頭唱楚歌。"]'),
('60bd959b-c797-4b1e-80dd-95822eef15a1','頌古二十六首  其一三','釋嗣宗','宋','宋诗','song-poetry','','[]','萬仞峰前握手時，清歌一曲少人知。',32,'全唐诗/poet.song.104000.json','["萬仞峰前握手時，清歌一曲少人知。", "但見瞎驢驚宇宙，不知法眼付傳誰。"]'),
('d83a3b75-ad8f-4115-8385-09fe054a851e','頌古二十六首  其一四','釋嗣宗','宋','宋诗','song-poetry','','[]','午夜霜凝星斗寒，長空雲盡山月落。',64,'全唐诗/poet.song.104000.json','["午夜霜凝星斗寒，長空雲盡山月落。", "青天喫棒人盡知，蒼龍退骨誰能覺。", "金鳳衝開玉鎖關，麒麟掣斷黄金索。", "迢迢劫外孰能拘，南北東西迥超卓。"]'),
('a812c3cf-d99f-40f9-b1a6-c02e89303f24','頌古二十六首  其一五','釋嗣宗','宋','宋诗','song-poetry','','[]','明頭落節，暗裏喫交，毒手當渠癢處搔。',34,'全唐诗/poet.song.104000.json','["明頭落節，暗裏喫交，毒手當渠癢處搔。", "雪裏鷺鷥飛不見，一隻銀瓶掛樹梢。"]'),
('43f3b884-d25d-4cfb-83f6-04c572c9f4a6','頌古二十六首  其一六','釋嗣宗','宋','宋诗','song-poetry','','[]','笊籬木杓，錢貫桶索，說妙談玄俱是錯。',78,'全唐诗/poet.song.104000.json','["笊籬木杓，錢貫桶索，說妙談玄俱是錯。", "清平鼻孔塞乾坤，天下衲僧無處摸。", "明來握土成金，悟去百草皆藥。", "拗折俱胝指頭，踏斷趙州略彴。", "平常一句用無窮，限量知見徒斟酌。"]'),
('14f9fca8-4072-44e0-83d3-06c977e212aa','頌古二十六首  其一七','釋嗣宗','宋','宋诗','song-poetry','','[]','後園驢喫草，可憐無限虛生老。',30,'全唐诗/poet.song.104000.json','["後園驢喫草，可憐無限虛生老。", "半夜盲人問故鄉，不知身在長安道。"]'),
('d67b6ec3-4549-4874-8e25-4c617ddf7e66','頌古二十六首  其一八','釋嗣宗','宋','宋诗','song-poetry','','[]','生死既不可求，根塵萬病俱休。',28,'全唐诗/poet.song.104000.json','["生死既不可求，根塵萬病俱休。", "從此俱空獨露，蟾輪一片清秋。"]'),
('7c99d3ea-ed18-4c1f-9387-2ab3f8243da3','頌古二十六首  其一九','釋嗣宗','宋','宋诗','song-poetry','','[]','烏龜三眼紅如火，一角麒麟快似錐。',32,'全唐诗/poet.song.104000.json','["烏龜三眼紅如火，一角麒麟快似錐。", "土宿夜遊南贍部，泥牛腳下火星飛。"]'),
('0f37af8b-0240-48ec-aa30-78f48b1cb1e7','頌古二十六首  其二○','釋嗣宗','宋','宋诗','song-poetry','','[]','舒無蹤，卷無跡，日午晴空轟霹靂。',32,'全唐诗/poet.song.104000.json','["舒無蹤，卷無跡，日午晴空轟霹靂。", "衲子驚迷失路頭，神號鬼哭知何極。"]'),
('adff0fc8-01c4-489f-a77f-b1069e26b942','頌古二十六首  其二一','釋嗣宗','宋','宋诗','song-poetry','','["\u8861\u5c71"]','新羅渤海，南嶽天台。',46,'全唐诗/poet.song.104000.json','["新羅渤海，南嶽天台。", "纖塵不礙，豈涉去來。", "回頭斂念，解脫門開。", "反憶善財尋勝友，百城游徧不知回。"]'),
('de105ec1-642c-48ea-9e2e-75363b94ac96','頌古二十六首  其二二','釋嗣宗','宋','宋诗','song-poetry','','[]','貝葉收不盡，一句無私萬法印。',30,'全唐诗/poet.song.104000.json','["貝葉收不盡，一句無私萬法印。", "千聖滿口不能宣，嶺梅漏泄春光信。"]'),
('5071c1e0-8ca1-4c9a-a142-d23430b90442','頌古二十六首  其二三','釋嗣宗','宋','宋诗','song-poetry','','[]','古塚不爲家，漁翁舉棹出蘆花。',30,'全唐诗/poet.song.104000.json','["古塚不爲家，漁翁舉棹出蘆花。", "湛水無風江月迥，長空撒盡暮天霞。"]'),
('50e3b1f4-a5f8-4fce-8f3b-29d5371232cc','頌古二十六首  其二四','釋嗣宗','宋','宋诗','song-poetry','','[]','不勞車馬迹，文王去後無消息。',30,'全唐诗/poet.song.104000.json','["不勞車馬迹，文王去後無消息。", "月華影裏釣魚磯，萬古清風長歷歷。"]'),
('0dacd4f0-25ca-4b41-b4dd-b90005fe7f0d','頌古二十六首  其二五','釋嗣宗','宋','宋诗','song-poetry','','[]','一鏃三關俱透脫，從前汗馬休拈掇。',32,'全唐诗/poet.song.104000.json','["一鏃三關俱透脫，從前汗馬休拈掇。", "須知舊閣快龍舟，當年曾把錦標奪。"]'),
('ef2435fc-3f0e-4902-9678-c2c1e978a4f5','頌古二十六首  其二六','釋嗣宗','宋','宋诗','song-poetry','','[]','妙圓金地絕纖塵，到者當觀無相真。',32,'全唐诗/poet.song.104000.json','["妙圓金地絕纖塵，到者當觀無相真。", "莫道玄門難近向，舉頭便是塔中人。"]'),
('a08594e8-4c81-46f3-9bbb-ce839c660248','贈劉羲仲','吳炯','宋','宋诗','song-poetry','','[]','束带真成屈壯圖，寧思飽死歎侏儒。',64,'全唐诗/poet.song.104000.json','["束带真成屈壯圖，寧思飽死歎侏儒。", "便拈手版還丞相，卻覓芒鞋踏故廬。", "少日縈心但黄嬭，暮年使鬼勾青奴。", "他時有客來載酒，解道欲眠卿去無。"]'),
('e6fa4beb-483a-4f4e-80c2-03de9b1673c6','顔孝子烏墓','吳炯','宋','宋诗','song-poetry','','[]','人倫風化自孝始，我懷義烏顔氏子。',192,'全唐诗/poet.song.104000.json','["人倫風化自孝始，我懷義烏顔氏子。", "昔從書傳聞其名，今來浙東入其里。", "未入里先見路碑，高塚巍然雲樹裏。", "猶有群烏繞墓飛，或者神烏長不死。", "啣土傷吻土亦亦，烏血凝成墓山紫。", "今古人人皆有親，負土葬者豈獨此。", "如何感召到山禽，須就人心推物理。", "生前服勞情自苦，亡後附身哀靡已。", "天地憫憐鬼神泣，無知羽族有所使。", "父子塋域永相依，白雲深處精靈起。", "風吹草卉即萊衣，溪浮蘋藻爲甘旨。", "千秋萬古此經過，誰人眼不淚如水。"]'),
('a728396f-9bfc-4e97-961b-3496ed9ae701','句','吳炯','宋','宋诗','song-poetry','','[]','誰知吾子漢稜粥，壓倒東坡玉糝羹。',16,'全唐诗/poet.song.104000.json','["誰知吾子漢稜粥，壓倒東坡玉糝羹。"]'),
('1f346821-dad0-43aa-9b16-a8c5351d4f3d','題稙庵','陳掞','宋','宋诗','song-poetry','','[]','季鷹雅志本江湖，胡爲入洛誠計疏。',128,'全唐诗/poet.song.104000.json','["季鷹雅志本江湖，胡爲入洛誠計疏。", "一盃蓴羹入歸夢，歲晚僅飽松江鱸。", "何如王郎十畝宅，一生江頭枕江碧。", "西風落日弄煙波，卻笑陶朱計然策。", "我來訪君春已深，江花江柳翻綠陰。", "相攜三徑拾瑤草，爲問客來何苦心。", "固知此事君計得，我被微官苦相逼。", "勸君謹勿語彈冠，便恐紛紛北山檄。"]'),
('4990131b-cbdd-4358-b2bc-05e0bcef29a3','光淥亭杏花','陳掞','宋','宋诗','song-poetry','','[]','西郊見說春事濃，杏花香發眠東風。',64,'全唐诗/poet.song.104000.json','["西郊見說春事濃，杏花香發眠東風。", "主人未解此花意，小槽溜溜盃猶空。", "勸君瀲灧蒲萄綠，好看枝頭紅映肉。", "莫令風雨遣花飛，徒唱人間斷腸曲。"]'),
('e0492077-932c-4930-ba55-0834711faca6','破山寺雙頭白蓮','陳掞','宋','宋诗','song-poetry','','[]','湘南夜水風露清，月明耿耿波益平。',128,'全唐诗/poet.song.104000.json','["湘南夜水風露清，月明耿耿波益平。", "嬋娟有人步羅襪，瓊璫玉佩雙娉婷。", "可憐玉骨埋藏久，腸斷人間無復有。", "豈知化作蘭若蓮，宿契未忘猶並首。", "想應快意洗塵緣，不向謝池爭取妍。", "玻璃盤中凈土頰，一心稽首西方仙。", "請君以圖獻天子，當與嘉禾並周史。", "毋令寂寞墮空山，泣月悲雲清夜殘。"]'),
('a33ecccb-b6fe-428b-9278-3f064de80b62','竹溪爲旌城汪伯溱賦','程介','宋','宋诗','song-poetry','','[]','先生溪上種修竹，呼吸溪光餐竹綠。',96,'全唐诗/poet.song.104000.json','["先生溪上種修竹，呼吸溪光餐竹綠。", "自應不同此君醫，冰雪之胸元不俗。", "我欲相從竹溪中，已辦青蓑黄篾篷。", "臥聽肅肅搖清風，一洗滿懷塵土空。", "祇愁一夕風雷起，變化飛龍葛陂水。", "凌雲去去固無心，莫忘溪頭舞煙雨。"]'),
('3fb2d071-b1bc-494b-a987-6330fb9b011b','題晝寢宮人圖應制','黄泳','宋','宋诗','song-poetry','','[]','御手指嬋娟，春風晝日眠。',48,'全唐诗/poet.song.104000.json','["御手指嬋娟，春風晝日眠。", "粉勻香汗濕，髻壓鬢雲偏。", "柳妬眉間綠，桃驚臉上鮮。", "夢魂何處是，應繞帝王邊。"]'),
('3397a013-c1bc-4214-b952-608a5caa138e','爲師憲兄悼侍兒倩倩  其一','黄泳','宋','宋诗','song-poetry','','[]','蘭質蕙心何所在，風魂雲魄去難招。',32,'全唐诗/poet.song.104000.json','["蘭質蕙心何所在，風魂雲魄去難招。", "子規叫斷黄昏月，疑是佳人恨未消。"]'),
('debb5206-5fe6-4e19-bee8-d2ef3df6e311','爲師憲兄悼侍兒倩倩  其二','黄泳','宋','宋诗','song-poetry','','[]','含怨銜辛情脈脈，家人強遣試春衫。',32,'全唐诗/poet.song.104000.json','["含怨銜辛情脈脈，家人強遣試春衫。", "也知不作堅牢玉，祇向人間三十三。"]'),
('028a5697-87f3-4c75-b676-cc85ac26de44','以二貓送張子賢  其一','李璜','宋','宋诗','song-poetry','','[]','家家入雪白於霜，更有欹鞍似鬧裝。',32,'全唐诗/poet.song.104000.json','["家家入雪白於霜，更有欹鞍似鬧裝。", "便請爐邊叉手坐，從他鼠子自跳梁。"]'),
('dc49c15a-f483-48a3-8fc2-5cdd50773edd','以二貓送張子賢  其二','李璜','宋','宋诗','song-poetry','','[]','銜蟬毛色白勝酥，搦絮推綿亦不如。',32,'全唐诗/poet.song.104000.json','["銜蟬毛色白勝酥，搦絮推綿亦不如。", "老病毗耶須減口，從今休歎食無魚。"]'),
('d6d70f2e-9fe7-4754-9d76-8e02ad8827f2','句','李璜','宋','宋诗','song-poetry','','[]','分明便是龐居士，欲恨無人賣罩籬。',16,'全唐诗/poet.song.104000.json','["分明便是龐居士，欲恨無人賣罩籬。"]'),
('c824dda8-98ad-4930-a91f-50dce7ac6049','潺潺閣','婁乾曜','宋','宋诗','song-poetry','','[]','一派泠泠遶檻清，塵襟洗滌自涼生。',31,'全唐诗/poet.song.104000.json','["一派泠泠遶檻清，塵襟洗滌自涼生。", "夜深好夢驚破，疑是半天風雨聲。"]'),
('b98035ec-cb3b-4e4c-a7f5-e0f2c199ae48','自題肖像','釋景元','宋','宋诗','song-poetry','','[]','生平只說聱頭禪，撞著聱頭如鐵壁。',64,'全唐诗/poet.song.104000.json','["生平只說聱頭禪，撞著聱頭如鐵壁。", "脫卻羅籠截腳跟，大地撮來墨漆黑。", "晚年轉復沒刀刀，奮金剛杵碎窠窟。", "他時要識圓悟面，一爲渠儂併拈出。"]'),
('d714a656-56ee-4c0f-8655-c02d028c0be1','偈','釋景元','宋','宋诗','song-poetry','','[]','野干鳴，師子吼。',36,'全唐诗/poet.song.104000.json','["野干鳴，師子吼。", "張得眼，開得口。", "動南星，嗟北斗。", "金剛階下蹲，神龜火裏走。"]'),
('93dcfdd2-09d6-47ac-929f-7ac5ef3b38e8','偈','釋景元','宋','宋诗','song-poetry','','[]','有時瞋，有時喜，有時觀音面，有時夜叉觜。',56,'全唐诗/poet.song.104000.json','["有時瞋，有時喜，有時觀音面，有時夜叉觜。", "或現鼠尾龍頭，或現鼠頭龍尾。", "偏要檢非，不要檢是。", "是金不博金，是水不博水。"]'),
('b6dd987d-6b2a-48c8-951b-6e0c24125bd2','度南明和尚意擬頌','釋景元','宋','宋诗','song-poetry','','[]','我有明珠一顆，切忌當頭錯過。',28,'全唐诗/poet.song.104000.json','["我有明珠一顆，切忌當頭錯過。", "雖然覿面相呈，也須一槌打破。"]');
